INSERT INTO `quest_text` VALUES ('1','en','Mountain Herb Picking','Deliver 5 Mountain Herbs','Loving Sibling','I want to pick some of this village''s famous Mountain Herbs for my brother in town, but there are too many monsters! Could you please go out for me and bring back 5 Mountain Herbs?');
INSERT INTO `quest_text` VALUES ('1','es','Recogida de hierbas','Entrega 5 hierbas de montaña','Hermano cariñoso','Quiero recoger algunas de las famosas hierbas de las montañas de esta aldea para mi hermano, pero hay muchos monstruos. ¿Podrías recoger para mí 5 hierbas de la montaña?');
INSERT INTO `quest_text` VALUES ('2','en','An Anteka in the Snow','Deliver 3 Anteka Antlers','The Aged Apothecary','In the Eastern lands, it is said that an Anteka''s antlers are good for one''s health. I would like to test this proverb. Please acquire 3 of these antlers for this purpose.');
INSERT INTO `quest_text` VALUES ('2','es','Un Anteka en la nieve','Entrega 3 astas de Anteka','El boticario anciano','En el Este, se dice que las astas de Anteka son buenas para la salud. Me gustaría probarlas para ver si es cierto. Consigue 3 de esas astas para que pueda comprobarlo.');
INSERT INTO `quest_text` VALUES ('3','en','Hunt the Carnivore!','Slay 5 Giaprey','Pokke Village Guard','HELP! The children are being attacked by small, white monsters called Giaprey! 5 of the beasts are outside! Do something! Please! Think of the children!');
INSERT INTO `quest_text` VALUES ('3','es','¡Caza al carnívoro!','Mata a 5 Giaprey','Guardia aldea Pokke','¡SOCORRO! ¡Unos monstruos pequeños y blancos llamados Giaprey están atacando a los niños! ¡Hay 5 fuera! ¡Haz algo! ¡Por favor! ¡Piensa en los niños!');
INSERT INTO `quest_text` VALUES ('4','en','Sinking Feeling','Deliver 3 Popo Tongues','Frightened Youth','As usual, I went into the mountains on my hunt for Popos; however, today they were frightened and fled to the summit. Something must be up there... Please get the Popo Tongues for me!');
INSERT INTO `quest_text` VALUES ('4','es','Sensación de ansiedad','Entrega 3 lenguas de Popo','Joven asustado','Como siempre, fui a las montañas a cazar Popo, pero hoy estaban asustados y huyeron a la cima. Allí debe de haber algo... ¡Por favor, consígueme lenguas de Popo!');
INSERT INTO `quest_text` VALUES ('5','en','Slay the Blangos!','Slay 3 Blangos','Wild Grass Gatherer','Whew! That was incredibly scary! On my walk up the mountain road, some Blangos began to chase me! I think they are still up there, so please slay them quickly!');
INSERT INTO `quest_text` VALUES ('5','es','¡Mata a los Blango!','Mata a 3 Blango','Rec. hierba salvaje','¡Buf! ¡Qué miedo que he pasado! ¡Cuando iba por la carretera de la montaña, unos Blango me han seguido! Me parece que aún siguen allí. ¡Mátalos, por favor!');
INSERT INTO `quest_text` VALUES ('6','en','Gathering - Snowy Mountains','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A gathering quest in the snowy mountains. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('6','es','Recogida – Montañas nevadas','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida en las montañas nevadas. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('7','en','Gathering - Jungle Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A gathering quest in the jungle. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('7','es','Recogida – Zona de jungla','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida en la jungla. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('8','en','Gathering - Desert Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A gathering quest in the desert. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('8','es','Recogida – Zona desierto','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida en el desierto. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('9','en','The Carnivorous Leader','Hunt the Giadrome','Pokke Village Chief','It seems that I can trust you with a difficult job like this. I''d like you to hunt down the leader of a Giaprey pack, the Giadrome. I wish you a beautiful victory in our defense!');
INSERT INTO `quest_text` VALUES ('9','es','El líder carnívoro','Caza al Giadrome','Jefe de aldea Pokke','Parece que puedo confiarte una misión tan difícil como ésta. Quiero que caces al líder de una manada de Giaprey, el Giadrome. ¡Te deseo una bella victoria en nuestra defensa!');
INSERT INTO `quest_text` VALUES ('10','en','Reckless Bulldrome Hunter','Hunt the Bulldrome','Troubled Father','My son decided to become a hunter and ran off after a Bulldrome on his own! Of course, now the tables have turned and I''m worried! Hunt down the Bulldrome on the snowy mountains!');
INSERT INTO `quest_text` VALUES ('10','es','Cazador de Bulldrome','Caza al Bulldrome','Padre preocupado','¡Mi hijo decidió ser cazador y se fue él solo tras un Bulldrome! Ya ha pasado un tiempo y estoy bastante preocupado. ¡Caza al Bulldrome en las montañas nevadas!');
INSERT INTO `quest_text` VALUES ('11','en','Slay the Giaprey!','Slay 20 Giaprey','Proud Farmer','I chased off a Giaprey that was feeding on my Popos, but now it''s back with 19 of its buddies! I can''t take on the whole lot of them! Hunters, this is your chance! Please get rid of them for me!');
INSERT INTO `quest_text` VALUES ('11','es','¡Mata a los Giaprey!','Mata a 20 Giaprey','Granjero orgulloso','¡Ahuyenté al Giaprey que se comía a mis Popo! ¡Pero regresó con 19 amigos suyos y son demasiados para mí! ¡Por favor, deshazte de ellos por mí! ¡Cazadores, ésta es vuestra oportunidad!');
INSERT INTO `quest_text` VALUES ('12','en','The Pack of Blangos','Slay 5 Blangos','Calm Villager','I request that you slay the Blangos rampaging through the mountains... A Bulldrome was also spotted in the area. Successfully avoid the Bulldrome and go about your mission.');
INSERT INTO `quest_text` VALUES ('12','es','La manada de Blango','Mata a 5 Blango','Aldeano calmado','Te pido que mates a los Blango que están arrasando las montañas... También se ha visto a un Bulldrome en la zona. Evita al Bulldrome y cumple tu misión.');
INSERT INTO `quest_text` VALUES ('13','en','The Taboo of Negligence!','Deliver 15 Mountain Herbs','Optimistic Lady','The Mountain Herb, one of the seven sacred mountain flowers, truly captures the spirit of the mountains. There shouldn''t be any wyverns in this weather, so you may gather with ease.');
INSERT INTO `quest_text` VALUES ('13','es','¡El tabú de la negligencia!','Entrega 15 Hierbas de montaña','Señora optimista','Esta Hierba de montaña es una de las 7 flores sagradas de la montaña que refleja fielmente el espíritu de las montañas. Con este tiempo, los Wyverns no salen, así que recógelas tranquilo.');
INSERT INTO `quest_text` VALUES ('14','en','Hunt Down the Velocidrome!','Hunt the Velocidrome','Newly Wedded Husband','It seems that whenever my wife goes to pick mushrooms in the Jungle, a large carnivore appears! There''s no way I can let her go pick mushrooms now... Please! Make the Jungle safe again!');
INSERT INTO `quest_text` VALUES ('14','es','¡Caza al Velocidrome!','Caza al Velocidrome','Hombre recién casado','¡Cuando mi mujer está recogiendo setas, aparece un carnívoro enorme! No va a volver a salir a recoger setas en su vida... ¡Ayúdanos a proteger a los aldeanos!');
INSERT INTO `quest_text` VALUES ('15','en','Jungle Menace','Hunt the Yian Kut-Ku','Jungle Envoy','I want you to hunt and kill the giant bird-like monster that has appeared in our jungle. It''s wreaking havoc on our environment and must be stopped!');
INSERT INTO `quest_text` VALUES ('15','es','Amenaza en la jungla','Caza al Yian Kut-Ku','Enviado de la jungla','Quiero que caces y mates al monstruo gigante con forma de pájaro que apareció en la jungla. ¡Está causando estragos en la zona! ¡Hay que detenerlo!');
INSERT INTO `quest_text` VALUES ('16','en','Rarest of the Rare Beasts','Hunt the Congalala','Village Grocer','Do you know of a pink, fanged beast that roams the jungle? That beast has dirtied my shop beyond hope! It''s impossible to clean up! Get rid of it before I''m soiled again!');
INSERT INTO `quest_text` VALUES ('16','es','La más rara de las bestias','Caza al Congalala','Tendero de la aldea','¿Conoces a una bestia rosa con colmillos que vive en la jungla? ¡Me ha dejado la tienda hecha una porquería! ¡No hay quien la limpie! ¡Deshazte de ella antes de que lo vuelva a hacer!');
INSERT INTO `quest_text` VALUES ('17','en','Hunt the Rare Forest Congas!','Slay 10 Congas','Oblivious Daughter','I took a trip to the jungle and saw some beautiful pink animals with fangs. But when I tried to pet them from my carriage, the beasts made a stink on me! I can''t get it off! Punish those meanies!');
INSERT INTO `quest_text` VALUES ('17','es','¡Caza al Conga del bosque!','Mata a 10 Conga','Hija ingenua','Cuando fui a la jungla, vi unos bonitos animales rosas con colmillos. Esas cosas me lanzaron una peste que no me puedo quitar de encima. ¡Castígalos!');
INSERT INTO `quest_text` VALUES ('18','en','Attack of the Giant Bugs!','Slay 20 Vespoids','Jungle Envoy','My village is under attack by a swarm of bug monsters! It seems there are about 20 of them. One on one they are not a threat, but as a group they are deadly. So be careful.');
INSERT INTO `quest_text` VALUES ('18','es','¡Atacan los bichos gigantes!','Mata a 20 Vespoid','Enviado de la jungla','¡Una manada de monstruos bicho está atacando mi aldea! Parece que hay unos 20. Individualmente no son una amenaza, pero como grupo son mortales. Ten cuidado.');
INSERT INTO `quest_text` VALUES ('19','en','Collect to Combine','Deliver 10 Special Mushrooms','Combining Madam','An affinity towards combining is important, but so are fresh raw materials! Special Mushrooms from the jungle are sure to improve your hunting life and wallet! Gather 10 of them!');
INSERT INTO `quest_text` VALUES ('19','es','Recoge para combinar','Entrega 10 Setas especiales','Madam Combi','¡La combinación tiene que gustarte, pero también es importante usar materiales frescos! ¡Las setas especiales de la jungla mejorarán tu vida y tu cartera! ¡Recoge 10!');
INSERT INTO `quest_text` VALUES ('20','en','Hunt the Gendrome!','Hunt the Gendrome','Ambitious Noble','My caravans are being hit by packs of Genprey. It appears there is an extraordinarily powerful boss among them! Hunt down the monster and make the roads safe again for all!');
INSERT INTO `quest_text` VALUES ('20','es','¡Caza al Gendrome!','Caza al Gendrome','Noble ambicioso','Las manadas de Genprey están atacando mis caravanas. ¡Al parecer, tienen un jefe extraordinariamente fuerte! ¡Caza a ese monstruo y haz que las carreteras vuelvan a ser seguras para todos!');
INSERT INTO `quest_text` VALUES ('21','en','The Land Shark','Hunt the Cephadrome','Oasis Village Chief','Our pack-animals were eaten by something in the desert. But nobody actually saw the monster attack! Track down this vile beast and take it out!');
INSERT INTO `quest_text` VALUES ('21','es','El tiburón terrestre','Caza al Cephadrome','Jefe de aldea Oasis','Algo se ha comido a nuestras bestias de carga en el desierto. Pero nadie vio el ataque. ¡Localiza a esa malvada bestia y acaba con ella!');
INSERT INTO `quest_text` VALUES ('22','en','Liver of Legend!','Deliver 3 Piscine Livers','Foreign Peddler','Hello sirs and madams! I deal in rare items that I find in the desert. Recently I''ve got a buyer for Piscine Wyvern and Sand Wyvern livers. Deliver 3 of them to me!');
INSERT INTO `quest_text` VALUES ('22','es','¡Hígado de leyenda!','Entrega 3 Hígados de Piscine','Vend amb extranjero','¡Hola, damas y caballeros! Vendo objetos raros del desierto. Acabo de encontrar un comprador de Hígados de Piscine Wyvern y Wyvern de arena. ¡Tráiganme 3 de esos Hígados!');
INSERT INTO `quest_text` VALUES ('23','en','Gone Fishin''','Deliver 2 Goldenfish','Twilight Fisherman','Fishing. It carries on in the hearts of children and remains a simple pleasure for adults. Hearken back to a simpler time and bring me back 2 of the desert''s most precious gift... Goldenfish!');
INSERT INTO `quest_text` VALUES ('23','es','De pesca','Entrega 2 Peces dorados','Pescador del ocaso','La pesca. Está en el corazón de los niños y es un placer sencillo para los adultos. Rememora aquellos tiempos y tráeme 2 de los regalos más preciados del desierto... ¡Peces dorados!');
INSERT INTO `quest_text` VALUES ('24','en','Gathering - Swamp Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A gathering quest in the swamp. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('24','es','Recogida – Zona pantanosa','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida en el pantano. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('25','en','Gathering - Forest and Hills','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A gathering quest in the forest and hills. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('25','es','Recogida – Bosque y colinas','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida en el bosque y las colinas. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('26','en','Shadow in the Snow','Hunt the Khezu','Pokke Village Chief','If it''s not one thing, it''s another, right? Near the village, a strange flying wyvern called a Khezu has been spotted. It is strong, but I believe you can handle it. Do your very best!');
INSERT INTO `quest_text` VALUES ('26','es','Sombra en la nieve','Caza al Khezu','Jefe de aldea Pokke','Si no es una cosa, es otra. Han visto un extraño Wyvern volador llamado Khezu cerca de la aldea Es muy fuerte, pero creo que puedes acabar con él. ¡Haz lo que puedas!');
INSERT INTO `quest_text` VALUES ('27','en','The Subterranean Glutton','Deliver 3 Khezu Whelps','Delicacy Collector','I''m after the rare larvae of the Khezu. They should be on the summit, so search there. These whelps aren''t to be taken lightly. If you run out of Pickaxes, combine a bone with a rock!');
INSERT INTO `quest_text` VALUES ('27','es','El glotón subterráneo','Entrega 3 crías de Khezu','Coleccionista obj.','Estoy buscando larvas del Khezu. Deberían de estar en la cima, así que busca allí. No hay que subestimar a esas crías. ¡Si te quedas sin picos, combina un hueso con una roca!');
INSERT INTO `quest_text` VALUES ('28','en','Blango Slaying Tactics','Slay 10 Blangos','Armory Owner','The pelt of a Blango can be made into various pieces of armor that are useful in everyday life. Slay 10 of the beasts and bring me their pelts. Beware of the Giadrome.');
INSERT INTO `quest_text` VALUES ('28','es','Tácticas mortales del Blango','Mata a 10 Blango','Propietario armería','El pelo de Blango sirve para fabricar varios tipos de armaduras muy útiles para la vida cotidiana. Mata a 10 y tráemelos, pero cuidado con el Giadrome.');
INSERT INTO `quest_text` VALUES ('29','en','Aim for the Jungle Crab','Hunt the Daimyo Hermitaur','Uncomfortable Butler','I''ve always longed to go hunting in the jungle! However, if a huge monster appeared, I''d be finished! Maybe you could take out the Daimyo Hermitaur for me?');
INSERT INTO `quest_text` VALUES ('29','es','El cangrejo de la jungla','Caza al Daimyo Hermitaur','Mayord. indispuesto','¡Siempre deseé ir de caza a la jungla! ¡Pero si aparece un monstruo enorme, estoy acabado! Quizá tú podrías acabar con ese Hermitaur por mí...');
INSERT INTO `quest_text` VALUES ('30','en','Master of the Giant Lake','Hunt the Green Plesioth','Master Shipwright','Hunt down the water wyvern that keeps harassing my shipyard! Your target is a monster covered in green scales that is more powerful than its cousin! Heh heh!');
INSERT INTO `quest_text` VALUES ('30','es','Maestro del lago gigante','Caza al Plesioth verde','Maestro astillero','¡Caza al Wyvern de agua que está atacando mi astillero! Tu objetivo es un monstruo de escamas verdes que es más fuerte que su primo. ¡Je je!');
INSERT INTO `quest_text` VALUES ('31','en','A Swarm of Hermitaurs','Slay 10 Hermitaurs','Jungle Fisherman','Fishing is no easy endeavor, but lately things have gotten out of hand! While unloading my ship, a swarm of Hermitaurs appeared. Slay 10 of them and let me get on with my work!');
INSERT INTO `quest_text` VALUES ('31','es','Un enjambre de Hermitaur','Mata a 10 Hermitaur','Pescadores de jungla','¡Pescar no es una tarea fácil, pero últimamente las cosas se han complicado! Al descargar el barco, apareció un enjambre de Hermitaur. ¡Mata a 10 para que pueda seguir haciendo mi trabajo!');
INSERT INTO `quest_text` VALUES ('32','en','The Purple Poison Menace','Hunt the Purple Gypceros','Guarded Merchant','I saw a gigantic bird-like monster deep in the jungle! It scared everyone so bad that I can''t do business with a thing like that out there! Please hunt it down so I can work in peace!');
INSERT INTO `quest_text` VALUES ('32','es','La amenaza del veneno morado','Caza al Gypceros morado','Mercader protegido','¡He visto un monstruo con forma de pájaro en la jungla! Ha asustado tanto a la gente que no puedo comerciar con esa cosa por ahí suelta. ¡Cázalo para que pueda trabajar en paz!');
INSERT INTO `quest_text` VALUES ('33','en','The Lurking Desert Giant','Hunt the Daimyo Hermitaur','Lynian Clan Leader','When some of my clan went gathering in the desert, they were attacked by an enormous crab, nya! As long as he''s around, we can''t do business. Help us, nya!');
INSERT INTO `quest_text` VALUES ('33','es','El gigante del desierto','Caza al Daimyo Hermitaur','Líder clan Lynian','¡Algunos de mi clan fueron atacados por un enorme cangrejo cuando estaban de recogida! Si sigue por aquí, no podemos trabajar. ¡Ayúdanos, miau!');
INSERT INTO `quest_text` VALUES ('34','en','Water Wyvern in the Desert','Hunt the Plesioth','Proud Hunter','I found a giant water wyvern in a cave in the desert! I can''t defeat it because it stays underwater. Slay it for me and the glory is all yours!');
INSERT INTO `quest_text` VALUES ('34','es','Wyvern de agua en desierto','Caza al Plesioth','Cazador orgulloso','¡Encontré un Wyvern de agua gigante en una cueva del desierto! No puedo matarlo porque está bajo el agua. ¡Cázalo por mí y la gloria será toda tuya!');
INSERT INTO `quest_text` VALUES ('35','en','Slay the Genprey!','Slay 20 Genprey','Injured Soldier','I''m too injured to go on... The Genprey living in the desert have the power to paralyze their foes. I''d like you to find the pack that did this to me and kill 20 of the fiends!');
INSERT INTO `quest_text` VALUES ('35','es','¡Mata a los Genprey!','Mata a 20 Genpreys','Soldado herido','Estoy muy malherido para continuar... Los Genprey que viven en el desierto pueden paralizar a su enemigo. ¡Me gustaría que encontraras a la manada que me hizo esto y que mates a 20 de ellos!');
INSERT INTO `quest_text` VALUES ('36','en','Gypceros: Venomous Terror','Hunt the Gypceros','Swamp Farmer','The fields all around the town are getting torn to shreds by a gigantic poisonous bird-like monster. Exterminate it for us! Its poison can melt crops, so be careful it doesn''t melt you!');
INSERT INTO `quest_text` VALUES ('36','es','Gypceros: terror venenoso','Caza al Gypceros','Granjero del pantano','Los campos que rodean la ciudad están siendo arrasados por un monstruo similar a un pájaro. ¡Mátalo por nosotros! Su veneno funde las cosechas. ¡Que no te funda a ti!');
INSERT INTO `quest_text` VALUES ('37','en','Attack of the Blue Kut-Ku','Hunt the Blue Yian Kut-Ku','Novice Hunter','That big eared Yian Kut-Ku really made mincemeat out of me! It''s out of my league, so I want you to hunt it down for me! He''s all yours!');
INSERT INTO `quest_text` VALUES ('37','es','Ataque del Kut-Ku azul','Caza al Yian Kut-Ku azul','Cazador novato','¡Ese Yian Kut-Ku de las orejas grandes me ha hecho puré! No estoy a su nivel. ¡Quiero que lo caces por mí! ¡Es todo tuyo!');
INSERT INTO `quest_text` VALUES ('38','en','The Mischief-maker','Hunt the Congalala','Oblivious Daughter','I took a trip to the swamp and saw a pretty pink animal with fangs. But when I tried to call it to the carriage, it threw something dirty at me and now I can''t get the smell off! Punish it!');
INSERT INTO `quest_text` VALUES ('38','es','El travieso','Caza al Congalala','Hija ingenua','En el pantano, vi un animal rosa de colmillos preciosos. Pero cuando lo llamé desde el carro, me lanzó algo asqueroso. ¡Ahora no me puedo quitar ese olor de encima! ¡Castígalo!');
INSERT INTO `quest_text` VALUES ('39','en','Fang of the Iodrome!','Hunt the Iodrome','Swamp Village Envoy','My village is under attack by a pack of Ioprey. Inside their pack, they are led by an incredibly large boss with poison filled fangs. Slay this creature for us!');
INSERT INTO `quest_text` VALUES ('39','es','¡Colmillo del Iodrome!','Caza al Iodrome','Enviado del pantano','Una manada de Ioprey está atacando a mi aldea. La dirige un líder gigantesco con unos colmillos llenos de veneno. ¡Mata a esa criatura por nosotros!');
INSERT INTO `quest_text` VALUES ('40','en','Slay the Great Kut-Ku!','Hunt the Yian Kut-Ku','Foothills Guardsman','A bird-like Yian Kut-Ku is attacking people the world over! It has even shown up in these very hills! If it isn''t eliminated soon, we''re finished! Show me what you''re made of!');
INSERT INTO `quest_text` VALUES ('40','es','¡Cazar al gran Kut-Ku!','Caza al Yian Kut-Ku','Guarda forestal','¡Ese Kut-Ku con forma de pájaro está atacando el mundo entero! ¡Incluso ha pasado por estas colinas! Si no lo eliminamos pronto, estamos acabados. ¡Vamos a ver lo que vales!');
INSERT INTO `quest_text` VALUES ('41','en','A Killing from Mushrooms','Deliver 10 Special Mushrooms','Impatient Trader','Prices on mushrooms from the forest and hills have skyrocketed. Please gather 10 of them for me and I''ll cut you in on the profits! But beware of the Kut-Ku rumored to roam the area.');
INSERT INTO `quest_text` VALUES ('41','es','Setas por las nubes','Entrega 10 Setas especiales','Comerc. impaciente','El precio de las setas del bosque y las colinas está por las nubes. ¡Recoge 10 y repartiré los beneficios contigo! Pero cuidado con el Kut-Ku que se dice que vive por la zona.');
INSERT INTO `quest_text` VALUES ('42','en','Gathering - Volcanic Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A gathering quest in the Volcanic Belt. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('42','es','Recogida – Zona volcánica','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida en la región volcánica. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('43','en','The Ruler of the Snow','Hunt the Blangonga','Pokke Village Chief','My next request requires a true master... Care to test yourself? I''d like you to hunt down the chief of the snowy mountains. Remember, on this quest negligence is unforgivable.');
INSERT INTO `quest_text` VALUES ('43','es','El regente de la nieve','Caza al Blangonga','Jefe de aldea Pokke','Para mi siguiente petición, hay que ser un maestro... ¿Te apetece intentarlo? Hay que cazar al jefe de las montañas nevadas. En esta misión, no se perdonan las negligencias.');
INSERT INTO `quest_text` VALUES ('44','en','Red Shadow in the Swampland','Hunt the Red Khezu','Uncomfortable Butler','I''ve always longed to venture into the swamp! I think I could hunt down a Kelbi, but I could never fight a wyvern. Maybe you''d take care of this special monster for me...');
INSERT INTO `quest_text` VALUES ('44','es','Sombra roja en el pantano','Caza al Khezu rojo','Mayord. indispuesto','¡Siempre deseé aventurarme en el pantano! Creo que puedo cazar un Kelbi, pero jamás podría enfrentarme a un Wyvern. Quizá puedas ocuparte de este monstruo especial por mí...');
INSERT INTO `quest_text` VALUES ('45','en','The Lone Black Garuga','Hunt the Yian Garuga','Barmaid','A Yian Garuga has been spotted in the jungle and there is now a vigorous search on for this atrocious beast. It has downed many a hunter, so take care as you hunt it!');
INSERT INTO `quest_text` VALUES ('45','es','El solitario Garuga negro','Caza al Yian Garuga','Camarera','Han visto un Yian Garuga en la jungla y ahora todo el mundo está buscando a esa bestia tan atroz. ¡Ha acabado con muchos cazadores, así que ten cuidado al cazarlo!');
INSERT INTO `quest_text` VALUES ('46','en','Twin Velocidrome','Hunt 2 Velocidrome','Jungle Lord','2 Velocidrome and their brood have long been menacing this area. Please destroy the two Velocidrome to disperse the pack and return peace and quiet to the jungle!');
INSERT INTO `quest_text` VALUES ('46','es','Velocidrome gemelos','Caza 2 Velocidrome','Señor de la jungla','Esta zona lleva tiempo bajo la amenaza de 2 Velocidrome y su camada. ¡Por favor, destruye a los 2 Velocidrome y dispersa a la manada para recuperar la paz y la tranquilidad de la jungla!');
INSERT INTO `quest_text` VALUES ('47','en','Attack of the Giant Bugs!','Slay 20 Hornetaurs','Landowner','My plantation''s under attack by giant bugs! They nest in the jungle, in a swarm of about 20. Take care of them for me!');
INSERT INTO `quest_text` VALUES ('47','es','Ataque de bichos gigantes','Mata a 20 Hornetaurs','Terrateniente','¡Unos bichos gigantes están atacando mi plantación! Anidan en la jungla, en enjambres de unos 20. ¡Ocúpate de ellos por mí!');
INSERT INTO `quest_text` VALUES ('48','en','Battle of the Blos','Hunt the Monoblos','Kokoto Village Chief','This is a request to the virtuous hunters of Pokke. A Monoblos is tearing through the desert near my village of Kokoto. Please hunt it down for us!');
INSERT INTO `quest_text` VALUES ('48','es','Batalla de Blos','Caza al Monoblos','Jefe aldea Kokoto','Tenemos una petición para los virtuosos cazadores de Pokke. Un Monoblos está causando estragos en el desierto próximo a mi aldea, Kokoto. ¡Por favor, cazadlo por nosotros!');
INSERT INTO `quest_text` VALUES ('49','en','The Silver Horn','Hunt the White Monoblos','Former Kokoto Hunter','I beseech you for help! An old enemy has cut our hunters down to the last man... I fled to tell you that the silver horned White Monoblos terrorizes us once again! Rid us of it!');
INSERT INTO `quest_text` VALUES ('49','es','El cuerno plateado','Caza al Monoblos blanco','Excazador Kokoto','¡Te ruego que nos ayudes! Un antiguo enemigo ha acabado con todos nuestros cazadores... ¡El Monoblos blanco de cuernos plateados ha vuelto para aterrorizarnos! ¡Ayúdanos!');
INSERT INTO `quest_text` VALUES ('50','en','Supreme Ruler of the Swamp','Hunt the Shogun Ceanataur','Scheming Strategist','Hunters! It is time to hunt down the Shogun Ceanataur. Let us rid the swamp zone of this menace and expand our strategic possibilities. This is a highly classified hunt. So don''t tell a soul!');
INSERT INTO `quest_text` VALUES ('50','es','El gran rey del pantano','Caza al Shogun Ceanataur','Estratega maquinador','¡Cazadores! Es hora de cazar al Shogun Ceanataur. Vamos a librar al pantano de esa amenaza y mejorar nuestra gran estrategia. Se trata de una caza de alto secreto. ¡Chitón!');
INSERT INTO `quest_text` VALUES ('51','en','Trapped by Yian Kut-Ku','Hunt the Yian Kut-Ku and Blue Yian Kut-Ku','Beautiful Lady','The Yian Kut-Ku are circling, screaming in their shrill voices. Everyone is trapped inside the town! Please do something!');
INSERT INTO `quest_text` VALUES ('51','es','Asediados por Yian Kut-Ku','Caza al Yian Kut-Ku y al Yian Kut-Ku azul','Mujer hermosa','Los Yian Kut-Ku nos rodean y gritan con sus agudas voces. ¡Todo el mundo está atrapado en la ciudad! ¡Por favor, haz algo!');
INSERT INTO `quest_text` VALUES ('52','en','The Ioprey Leader','Hunt the Iodrome','Hardened Mercenary','We were just in a fight with a pack of Ioprey, but were routed and had to retreat before we could defeat their leader. Hunt it down for us, but beware of its poison attacks.');
INSERT INTO `quest_text` VALUES ('52','es','El líder de los Ioprey','Caza al Iodrome','Mercenario curtido','Estábamos luchando contra una manada de Ioprey, pero cambiaron de dirección y tuvimos que retirarnos antes de derrotar a su líder. ¡Cázalo, pero ten cuidado con sus ataques venenosos!');
INSERT INTO `quest_text` VALUES ('53','en','Basarios: Unseen Peril','Hunt the Basarios','Survivor','A wyvern attacked my team from out of the blue while we were on an expedition to the Volcanic Belt. Where did it come from? Please slay it!');
INSERT INTO `quest_text` VALUES ('53','es','Basarios: peligro oculto','Caza al Basarios','Superviviente','Un Wyvern ha atacado a mi equipo de repente mientras estábamos en una expedición en la región volcánica. ¿De dónde salió? ¡Por favor, mátalo!');
INSERT INTO `quest_text` VALUES ('54','en','Commander in the Flames','Hunt the Shogun Ceanataur','Chief Weapon smith','Upon our trip into the cave at the volcano, an enormous Shogun Ceanataur dropped down from the ceiling right on top of us! Its ambush caused massive damage! Rid the world of that scourge!');
INSERT INTO `quest_text` VALUES ('54','es','Comandante en llamas','Caza al Shogun Ceanataur','Jefe herrero armas','Cuando estábamos en la cueva del volcán, un Shogun Ceanataur inmenso se lanzó directamente encima de nosotros. ¡Hemos sufrido muchos daños! ¡Libra al mundo de ese azote!');
INSERT INTO `quest_text` VALUES ('55','en','Ioprey Hunting','Slay 20 Ioprey','Mine Owner','While mining for ore, we encountered a huge Ioprey nest deep inside our tunnel! We can''t continue working unless you kill 20 of them for us!');
INSERT INTO `quest_text` VALUES ('55','es','Caza de Ioprey','Mata a 20 Ioprey','Propietario de mina','Mientras extraíamos mineral, encontramos un gran nido de Ioprey al fondo de nuestro túnel. ¡No podemos seguir trabajando hasta que mates a 20 por nosotros!');
INSERT INTO `quest_text` VALUES ('56','en','A Band of Ceanataurs','Slay 10 Ceanataurs','Digging Fanatic','I wanted to keep digging in search of the ultimate treasure trove... But some Ceanataurs smashed my Pickaxe! If you don''t get rid of them, there will be no digging for me! Help me!');
INSERT INTO `quest_text` VALUES ('56','es','Una banda de ermitaños','Mata a 10 Ceanataur','Fanático excavación','Estaba cavando en busca de un gran tesoro, cuando unos Ceanataur se cargaron mi Pico. ¡Si no te deshaces de ellos, no podré volver a picar en mi vida! ¡Ayúdame!');
INSERT INTO `quest_text` VALUES ('57','en','More Coal Please','Deliver 15 pcs of Coal','Fort Guard','We need Coal to power our ambush spear cannon. Go to the Volcanic Belt and mine the reserves there! If you''re worried about Pickaxes, combine a long cylindrical bone and a rock.');
INSERT INTO `quest_text` VALUES ('57','es','Más carbón, por favor','Entrega 15 trozos de carbón','Guardia del fuerte','Necesitamos carbón para nuestro cañón de lanzas. ¡Búscalo en las reservas de la región volcánica! Si te preocupan los Picos, combina un hueso largo y cilíndrico con una roca.');
INSERT INTO `quest_text` VALUES ('58','en','The Frozen Dictator','Slay the Kushala Daora','Fleeing Villager','I saw it! I saw it! In the middle of a blinding snow storm, there it was; dark black wings were dancing in the sky... No mere human could stand up to it! Don''t even think of hunting it!');
INSERT INTO `quest_text` VALUES ('58','es','El dictador congelado','Mata al Kushala Daora','Aldeano huidizo','¡Lo vi! ¡Lo vi! En medio de una tormenta de nieve, allí estaba; sus oscuras alas bailaban en el cielo... ¡Ningún humano podría compararse con él! ¡Y mucho menos liquidarlo!');
INSERT INTO `quest_text` VALUES ('59','en','The Elder Dragon of Wind','Slay the Kushala Daora','Jungle Psychic','There was surely a vortex inside of that downpour. The wind wrapped around and revealed Kushala Daora! I don''t foresee anyone defeating it. Weaken it and then drive it away!');
INSERT INTO `quest_text` VALUES ('59','es','Anciano dragón del viento','Mata al Kushala Daora','Vidente de jungla','Seguro que había un vórtice dentro de ese chubasco. ¡El viento que le envolvía dejaba entrever a Kushala Daora. No creo que nadie pueda derrotarlo. Debilítalo hasta que se vaya.');
INSERT INTO `quest_text` VALUES ('60','en','Hermitaur Buffet','Slay 20 Hermitaurs','DesertedArenaManager','I went to open up the little arena that hasn''t been used in a while one morning, and I find that a band of Hermitaurs have turned it into their home! Now I need your help to turn them out!');
INSERT INTO `quest_text` VALUES ('60','es','Buffet Hermitaur','Mata a 20 Hermitaur','Jefe arena desierta','Fui a abrir la arena pequeña, que nadie ha usado en mucho tiempo ¡y descubrí que una banda de Hermitaur la ha convertido en su hogar! ¡Ahora necesito que me ayudes a echarlos!');
INSERT INTO `quest_text` VALUES ('61','en','Absolute Power','Hunt the Tigrex','Pokke Village Chief','The Tigrex, said to be an ancestor of today''s wyverns, has finally made an appearance. With such a powerful beast on the loose, the village is not safe. Hunt it down at once!');
INSERT INTO `quest_text` VALUES ('61','es','Poder absoluto','Caza al Tigrex','Jefe de aldea Pokke','Ha aparecido un Tigrex, que se dice que es el antepasado de los Wyverns modernos. Con esa bestia por ahí suelta, la aldea no está segura. ¡Cázalo de una vez por todas!');
INSERT INTO `quest_text` VALUES ('62','en','The Legendary Kirin','Slay the Kirin','Mountain Explorer','That must have been the phantom beast... The faint glow, and how it seemed to glide over land... There''s no doubt that amazing riches await its slayer!');
INSERT INTO `quest_text` VALUES ('62','es','El legendario Kirin','Mata al Kirin','Montañero','Ha debido de ser la bestia fantasma... Ese brillo y el modo en que parecía deslizarse... ¡Sin duda habrá una gran recompensa para quien la mate!');
INSERT INTO `quest_text` VALUES ('63','en','Two Roars in the Snow','Hunt 2 Blangongas','Alpine Survivor','It happened in an instant... Two Blangongas destroyed all the trees around my house. Now all I want to do is hunt them down so I can get my revenge. Please help me!');
INSERT INTO `quest_text` VALUES ('63','es','Dos rugidos en la nieve','Caza 2 Blangonga','Superviviente alpino','Sucedió en un instante... Dos Blangonga destruyeron todos los árboles alrededor de mi casa. Quiero cazarlos para poder vengarme de ellos. ¡Por favor, ayúdame!');
INSERT INTO `quest_text` VALUES ('64','en','The Poison Siege','Hunt the Gypceros and Purple Gypceros','Selfish Princess','Two poisonous fowl have appeared in the jungle. With them there, the jungle flowers will surely wilt and die! Go kill them... Now!');
INSERT INTO `quest_text` VALUES ('64','es','El asedio venenoso','Caza al Gypceros y al Gypceros morado','Princesa egoísta','Han aparecido dos aves venenosas en la jungla. Por su culpa, las flores de la jungla se van a marchitar. Ve a cazarlas... ¡Rápido!');
INSERT INTO `quest_text` VALUES ('65','en','The Tigrex''s Roar','Hunt the Tigrex','Guild Messenger','I have an urgent request from a hunter on an expedition in the desert! It seems he has encountered the mighty Tigrex! Go to his aid and crush this beast at once!');
INSERT INTO `quest_text` VALUES ('65','es','El rugido del Tigrex','Caza al Tigrex','Mensajero del Gremio','He recibido una petición urgente de un cazador que está de expedición en el desierto. ¡Ha encontrado al poderoso Tigrex! ¡Ve en su ayuda y caza a esa bestia de una vez por todas!');
INSERT INTO `quest_text` VALUES ('66','en','The Runaway Diablos','Hunt the Diablos','Border Captain','A giant wyvern smashed the border-wall and ran into this area. We need to find and kill it before it causes any more trouble!');
INSERT INTO `quest_text` VALUES ('66','es','El Diablos huido','Caza al Diablos','Capitán de frontera','Un Wyvern gigante rompió el muro fronterizo y se coló en esta zona. ¡Hay que buscarlo y cazarlo antes de que cause más problemas!');
INSERT INTO `quest_text` VALUES ('67','en','The Fierce Black Horn','Hunt the Black Diablos','Failed Millionaire','I had hired the most skilled hunters imaginable, and went on a safari for the famed Diablos... But what we found was no mere Diablos! We must slay that black horned wyvern! No matter what!');
INSERT INTO `quest_text` VALUES ('67','es','El fiero cuerno negro','Caza al Diablos negro','Millonario fracasado','Había contratado a los mejores cazadores, quienes partieron en busca del famoso Diablos. ¡Pero eso no era un simple Diablos! Hay que cazar a ese Wyvern negro con cuernos. ¡Como sea!');
INSERT INTO `quest_text` VALUES ('68','en','Ultimate Crab Dinner','Hunt 2 Daimyo Hermitaurs','The Lady Gourmet','I am a true connoisseur of crab cuisine, and as such a connoisseur, I suspect the Daimyo Hermitaurs found in the desert are incredibly tasty! One is never enough, so hunt down two!');
INSERT INTO `quest_text` VALUES ('68','es','Última cena con cangrejo','Caza 2 Daimyo Hermitaur','La Señora Gourmet','Soy todo un experto en platos de cangrejo y, como tal, sospecho que el Daimyo Hermitaur del desierto es enormemente sabroso. ¡Con uno no basta, así que caza dos!');
INSERT INTO `quest_text` VALUES ('69','en','Black Rock in the Swamp','Hunt the Black Gravios','Swamp Townsman','Even in the relative calm of the swamp zone, something has stirred up the monsters. In particular, heavily armored wyverns have been attacking us. Can you help us out?');
INSERT INTO `quest_text` VALUES ('69','es','Roca negra en el pantano','Caza al Gravios negro','Ciudadano pantano','En la relativa calma de la zona pantanosa, algo ha despertado a los monstruos. En concreto, nos han atacado Wyverns con fuertes conchas. ¿Podrías ayudarnos?');
INSERT INTO `quest_text` VALUES ('70','en','Seeking the Strange Mask','Slay 5 Shakalakas','Princess''s Attendant','This is awful! The princess saw some strange masked monsters that made her run for the hills! We''re sending troops on a hunt for the fiends, so track down the masked marauders!');
INSERT INTO `quest_text` VALUES ('70','es','En busca de la máscara','Mata a 5 Shakalaka','Ayuda de cámara','¡Es espantoso! ¡La princesa vio unos extraños monstruos enmascarados que huyeron a las colinas! Hemos enviado tropas para cazarlos, ¡así que encuentra a esos intrusos enmascarados!');
INSERT INTO `quest_text` VALUES ('71','en','Terror of the Gravios','Hunt the Gravios','Troubled Noble','A fearsome Gravios has appeared amidst the magma and desolation of the Volcanic Belt. Hunt down the fire breather for us!');
INSERT INTO `quest_text` VALUES ('71','es','Terror del Gravios','Caza al Gravios','Noble preocupado','Ha aparecido un Gravios terrible en medio del magma y la desolación de la región volcánica. ¡Caza a ese escupefuegos por nosotros!');
INSERT INTO `quest_text` VALUES ('72','en','Check the Ancient Tower','Slay 10 Remobras','Wyverian Maiden','A relic of olden days, the ancient tower is now off-limits. Those examining it should beware the danger posed by the Remobras. They must be defeated before entering the tower!');
INSERT INTO `quest_text` VALUES ('72','es','Explora la Torre antigua','Mata a 10 Remobra','Doncella Wyverian','La Torre antigua, una reliquia de otros tiempos, está en una zona prohibida. Quienes vayan, deben tener cuidado con los Remobra. ¡Hay que matarlos antes de entrar en la torre!');
INSERT INTO `quest_text` VALUES ('73','en','The Empress''s Blazing Throne','Slay the Lunastra','Elder Dragon Scholar','We''ve received a communique from headquarters. An elder dragon has appeared in the Volcanic Belt. Fight the dragon and collect data on its behavior!');
INSERT INTO `quest_text` VALUES ('73','es','El trono de la emperatriz','Mata al Lunastra','Viejo erudito drag.','Hemos recibido un comunicado del cuartel general. Ha aparecido un viejo dragón en la región volcánica. ¡Lucha con el dragón y obtén datos sobre su comportamiento!');
INSERT INTO `quest_text` VALUES ('74','en','Overseer of the Ancients','Slay the Lunastra','Scarlet Mystery Man','Near the forbidden ancient tower, the Lunastra, empress of the elder dragons, is building a nest. Hunters! Who among you can defeat this ancient beast!? Exhibit your true skills!');
INSERT INTO `quest_text` VALUES ('74','es','Guardián de los ancianos','Mata al Lunastra','Hombre mister. esc.','Lunastra, la emperatriz de los viejos dragones, está construyendo un nido cerca de la torre. ¡Cazadores! ¿¡Quién de vosotros puede derrotar a esa bestia!? ¡A ver si sois valientes!');
INSERT INTO `quest_text` VALUES ('75','en','The Elder Dragon of Mist','Slay the Chameleos','Injured Hero','Our intuition told us to turn around, but we thought no one was there... Yet even though no one should''ve been there, we were attacked from behind! Beware! It was an enemy never before seen!');
INSERT INTO `quest_text` VALUES ('75','es','Anciano dragón de la niebla','Mata al Chameleos','Héroe herido','Nuestra intuición nos decía que regresáramos, pero pensábamos que allí no había nadie. Y aunque debería haber sido cierto, nos atacaron. ¡Cuidado! ¡Jamás se ha visto enemigo igual!');
INSERT INTO `quest_text` VALUES ('76','en','Towards the Silence','Slay the Chameleos','Grim Aristocrat','It seems an unknown elder dragon has appeared in the swamp zone. However, no one truly got a clear look at it. What could the beast have been? Slay it, but proceed with caution!');
INSERT INTO `quest_text` VALUES ('76','es','Hacia el silencio','Mata al Chameleos','Aristócrata serio','Parece que en la zona del pantano ha aparecido un viejo dragón. Sin embargo, nadie lo ha visto bien del todo. ¿Qué será esa bestia? ¡Mátala, pero ve con cuidado!');
INSERT INTO `quest_text` VALUES ('77','en','Small Shadow over the Swamp','Hunt the Khezu','Novice Hunter','I was gathering mushrooms in the Swamp when a Khezu appeared, but it was no ordinary Khezu. What was so different about it? You''ll know as soon as you see it!');
INSERT INTO `quest_text` VALUES ('77','es','Pequeña sombra en el pantano','Caza al Khezu','Cazador novato','Estaba recogiendo setas en el Pantano cuando apareció un Khezu, pero no era un Khezu cualquiera. ¿Qué tenía de diferente? ¡Lo sabrás en cuanto lo veas!');
INSERT INTO `quest_text` VALUES ('78','en','Congalala Territorial Fight','Hunt 2 Congalalas','Swamp Envoy','Two Congalalas have started a territorial fight over the Swamp. If they''re not stopped soon, it''ll ruin commerce in the area! Please hurry and put an end to their dispute!');
INSERT INTO `quest_text` VALUES ('78','es','Lucha territorial Congalala','Caza 2 Congalala','Enviado pantano','Dos Congalala han iniciado una lucha territorial por el Pantano. Si no los detenemos pronto, ¡arruinarán el comercio en la zona! ¡Date prisa y acaba con su disputa!');
INSERT INTO `quest_text` VALUES ('79','en','A Troublesome Pair','Hunt the Rathalos and Rathian','Pokke Village Chief','A pair of fire wyverns have taken up residence in the hillside. If you are able to hunt them by yourself, you are truly a top class hunter. Care to try your luck?');
INSERT INTO `quest_text` VALUES ('79','es','Una pareja problemática','Da caza al Rathalos y la Rathian','Jefe de aldea Pokke','Un par de Wyverns de fuego se han instalado en la ladera de la colina. Si puedes cazarlos tú solo, es que eres un cazador de primera línea. ¿Quieres probar suerte?');
INSERT INTO `quest_text` VALUES ('80','en','Dual Plesioth','Hunt the Plesioth and Green Plesioth','Lovely Princess','The water wyvern known as Plesioth is raging in the jungle. And not just one of them! Head off immediately to slay them!');
INSERT INTO `quest_text` VALUES ('80','es','Plesioth doble','Caza al Plesioth y al Plesioth verde','Princesa encantadora','Hay varios Wyverns de agua llamados Plesioth enfurecidos en la jungla ¡Ve allí inmediatamente para matarlos!');
INSERT INTO `quest_text` VALUES ('81','en','Pink Dance in the Jungle','Hunt the Pink Rathian','Uncomfortable Butler','I''ve always longed to be a hunter, but a meeting with a Rathian ended that! Now that I know what it takes, I''ll start over, but you have the spirit to hunt down that Rathian!');
INSERT INTO `quest_text` VALUES ('81','es','Danza rosa en la jungla','Caza la Rathian rosa','Mayord. indispuesto','¡Siempre deseé ser cazador, pero tras un encuentro con una Rathian, eso se acabó! ¡Ahora que sé lo que es, volveré a empezar, pero hay que tener valor para cazar a esa Rathian!');
INSERT INTO `quest_text` VALUES ('82','en','Four Horns','Hunt the Diablos and Black Diablos','Lovely Princess','I simply can''t bear to think about the terror and pain those Diablos are causing my people. I can''t sleep at night with that worry! Hunt down those 2 Diablos for me!');
INSERT INTO `quest_text` VALUES ('82','es','Cuatro cuernos','Caza al Diablos y al Diablos negro','Princesa encantadora','No puedo soportar pensar en el terror y el dolor que esos Diablos están causando a mi gente. ¡No duermo por la noche! ¡Caza a 2 de esos Diablos por mí!');
INSERT INTO `quest_text` VALUES ('83','en','A Sun with Fangs','Slay the Teostra','Wyverian Pioneer','While in the secluded desert village, I spotted an elder dragon with red scales! While I do know some hunters, it would be wrong to make this request of them... So it''s up to you!');
INSERT INTO `quest_text` VALUES ('83','es','Un sol con colmillos','Mata al Teostra','Pionero Wyverian','Cuando estuve en la aldea del desierto, vi a un viejo dragón de escamas rojas. Aunque conozco a algunos cazadores, no estaría bien pedírselo a ellos... ¡Así que es cosa tuya!');
INSERT INTO `quest_text` VALUES ('84','en','Emperor of Flame','Slay the Teostra','Heroic General','I have an earnest request of you... I want you to fight the elder fire dragon we cornered in the Volcanic Belt! Weaken it with your repeated counterattacks and then finally slay the beast!');
INSERT INTO `quest_text` VALUES ('84','es','Emperador de las llamas','Mata al Teostra','General heroico','Tengo una importante tarea para ti... Quiero que luches con el viejo dragón de fuego que acorralamos en la región volcánica. ¡Debilítalo con continuos contraataques y al final acaba con él!');
INSERT INTO `quest_text` VALUES ('85','en','The Shogun''s Encampment','Hunt 2 Shogun Ceanataurs','Hunter In Training','Hey! Hey! Have you heard the news!? There''s a rumor that two enormous monsters with thick shells have appeared in the Volcanic Belt! There must be a hunter somewhere who can face them!');
INSERT INTO `quest_text` VALUES ('85','es','El campamento de Shogun','Caza 2 Shogun Ceanataur','Cazador en prácticas','¡Eh! ¡Eh! ¿¡Has oído las noticias!? ¡Se dice que en la región volcánica han aparecido 2 enormes monstruos con conchas! ¡Debe de haber algún cazador que pueda enfrentarse a ellos!');
INSERT INTO `quest_text` VALUES ('86','en','Attack of the Rathalos','Hunt the Azure Rathalos','Proud Soldier','It cannot be... We tried so hard to kill it... But... My entire war band was wiped out by a wyvern. Now it all rests upon your shoulders, monster hunter! Slay it!');
INSERT INTO `quest_text` VALUES ('86','es','Ataque del Rathalos','Caza al Rathalos celeste','Soldado orgulloso','No puede ser... Intentamos matarlo... Pero... Ese Wyvern acabó con todo mi batallón. ¡Ahora todo depende de ti, cazador de monstruos! ¡Cázalo!');
INSERT INTO `quest_text` VALUES ('87','en','A State of Crisis!','Defend the Town from Shen Gaoren','Red-Faced Commander','Gather, bold hunters! You are the lynchpin of our national defense! A menace creeps towards this town. You must repel this monster and defend the fort.');
INSERT INTO `quest_text` VALUES ('87','es','¡Estado crítico!','Defiende la ciudad de Shen Gaoren','Comandante colorado','¡Valientes cazadores! ¡Sois el eje de nuestra defensa nacional! Una amenaza se cierne sobre esta ciudad. Debéis rechazar al monstruo y defender el fuerte.');
INSERT INTO `quest_text` VALUES ('88','en','The Final Invitation','Hunt 2 Rajang','Scarlet Mystery Man','There are two Rajang, each with golden fur. Hunters, I have prepared a special stage for your grandest performance. Demonstrate your true power... He he he...');
INSERT INTO `quest_text` VALUES ('88','es','La invitación final','Caza 2 Rajang','Hombre mister. esc.','Hay dos Rajang de piel dorada. Cazadores, lo he preparado todo para vuestra más grande actuación. Demostrad vuestra fuerza... Je je je...');
INSERT INTO `quest_text` VALUES ('89','en','A Giant Dragon Invades!','Defend the Fortress from Lao-Shan Lung','Loyal Minister','A giant dragon has attacked our fort! If the fort falls, so too do our lands! Use its installed weaponry to make this beast pay for its indiscretions!');
INSERT INTO `quest_text` VALUES ('89','es','¡Invasión de dragón gigante!','Defiende la fortaleza del Lao-Shang Lung','Ministro leal','¡Un dragón gigante ha atacado nuestro fuerte! ¡Si el fuerte cae también lo harán nuestras tierras! ¡Usa el armamento instalado para hacer pagar a la bestia por sus fechorías!');
INSERT INTO `quest_text` VALUES ('90','en','Bullfangos in the Night','Slay 20 Bullfangos','Very Suspect Peddler','A Bulldrome and its pack are going hog-wild around a mining point for Ore. I don''t want others to find that secret location, so please hunt them in secret for me.');
INSERT INTO `quest_text` VALUES ('90','es','Bullfango en la noche','Mata a 20 Bullfango','Vendedor sospechoso','Un Bulldrome y su equipo están descontrolándose alrededor de un Punto de minería de Mineral. No quiero que nadie más conozca ese lugar secreto así que, por favor, cázalos en secreto.');
INSERT INTO `quest_text` VALUES ('91','en','Whack a Shakalaka','Slay 15 Shakalakas','DesertedArenaManager','I went to open up the little arena that hasn''t been used in a while one morning, and I find that it''s been taken over by a group of strange, little... things! Now I need your help to take them out!');
INSERT INTO `quest_text` VALUES ('91','es','Aporrea un Shakalaka','Mata a 15 Shakalaka','Jefe arena desierta','Fui una mañana a abrir la arena pequeña, que nadie ha usado en mucho tiempo ¡y descubrí que ha sido tomada por un grupo de extrañas... cositas! ¡Ahora necesito que me ayudes a echarlas!');
INSERT INTO `quest_text` VALUES ('92','en','Carnivore Carnival','Slay 20 Velociprey','DesertedArenaManager','I went to open up the little arena that hasn''t been used in a while one morning, and I find that it''s been turned into a meat-lover''s paradise! Please bring an end to their partying!');
INSERT INTO `quest_text` VALUES ('92','es','Carnaval carnívoro','Mata 20 Velocipreys','Jefe arena desierta','Fui una mañana a abrir la arena pequeña, que nadie ha usado en mucho tiempo ¡y descubrí que se ha convertido en un paraíso del carnívoro! ¡Por favor, acaba con la fiesta!');
INSERT INTO `quest_text` VALUES ('93','en','The Beating of Royal Wings','Slay the Vespoid Queen','Jungle Researcher','It''s no use. No matter where I look, I can''t seem to find the Vespoid Queen! Perhaps if you slayed a large number of Vespoids to make her feel that her swarm was in grave danger, she might appear...');
INSERT INTO `quest_text` VALUES ('93','es','El batir de alas reales','Mata al Vespoid reina','Investigador jungla','No hay nada que hacer. ¡Da igual donde mire, no encuentro al Vespoid reina! Quizá aparezca si matas muchos Vespoid para que piense que su prole está en grave peligro...');
INSERT INTO `quest_text` VALUES ('94','en','Secret Request: Hypnocatrice','Hunt the Hypnocatrice','Selfish Mantled Girl','I told my mother that I wanted a hat adorned with a Hypnocatrice''s tail feather, but she got mad and said I was being selfish. Therefore this is a secret request. You must tell no one, OK!?');
INSERT INTO `quest_text` VALUES ('94','es','Solic. secreta: Hypnocatrice','Caza al Hypnocatrice','Chica enm. egoísta','Dije a mi madre que quería un sombrero adornado con una pluma de cola de Hypnocatrice, pero se puso furiosa y me llamó egoísta. Por lo tanto, ésta es una solicitud secreta.');
INSERT INTO `quest_text` VALUES ('95','en','The Burning Dunes','Hunt the Cephadrome','OldDesertTownMayor','There is a gigantic Cephadrome here in the Old Desert. There are numerous casualties and a state of emergency has been declared. We''re calling on all hunters everywhere to please help!');
INSERT INTO `quest_text` VALUES ('95','es','Las dunas ardientes','Caza al Cephadrome','Alcalde vie.alde.des','Hay un Cephadrome gigante aquí en el Viejo desierto. Las bajas son numerosas y se ha declarado el estado de emergencia. ¡Pedimos a todos los cazadores, estén donde estén, que nos ayuden!');
INSERT INTO `quest_text` VALUES ('96','en','Stealing in the Old Swamp!','Hunt the Gypceros','Compassionate Hunter','That Gypceros stole my very important Book of Combos, and then, right after that, a band of Melynx stole my BBQ Spit! At this rate, I''m going to be forced into early retirement! Heeeeelp!');
INSERT INTO `quest_text` VALUES ('96','es','¡Robo en el Viejo pantano!','Caza al Gypceros','Cazador compasivo','¡Ese Gypceros robó mi importantísimo Libro de combos y luego, justo después, una banda de Melynx robó mi Asador de barbacoa! A este paso voy a tener que retirarme antes de tiempo. ¡Ayuuda!');
INSERT INTO `quest_text` VALUES ('97','en','The Purple Poison Menace','Hunt the Purple Gypceros','Guarded Merchant','I saw a gigantic Gypceros lurking deep in the swamp! It scared everyone so bad that I can''t do business with a thing like that out there! Please hunt it down so I can work in peace!');
INSERT INTO `quest_text` VALUES ('97','es','La amenaza del veneno morado','Caza al Gypceros morado','Mercader protegido','¡He visto un enorme Gypceros acechando en lo profundo del pantano! Ha asustado tanto a la gente que no puedo comerciar con esa cosa por ahí. ¡Cázalo para que pueda trabajar en paz!');
INSERT INTO `quest_text` VALUES ('98','en','Target: Basarios','Hunt the Basarios','Illegal Middleman','Off the record, I want you to hunt the Basarios down. You can tell the Guild that you failed and then sell the materials you get wholesale. Hmm? Oh no, this is a real request from the Guild...');
INSERT INTO `quest_text` VALUES ('98','es','Objetivo: Basarios','Caza al Basarios','Hombre ilegal','Entre nosotros, quiero que caces al Basarios. Puedes decirle al Gremio que fallaste y luego vender los materiales que obtengas. ¿Eh? Es una solicitud real del Gremio, de veras...');
INSERT INTO `quest_text` VALUES ('99','en','Old Jungle Lightning','Hunt the Khezu','Madam Merchant','Just when I thought that maybe this time the peace would last, this happens! As long as that Khezu just sits there, we can''t get out of the Old Jungle. Please, come to our rescue, hunter!');
INSERT INTO `quest_text` VALUES ('99','es','Relámpago de la Vieja jungla','Caza al Khezu','Dama mercader','¡Justo cuando pensaba que quizá esta vez la paz fuera duradera, ocurre esto! Mientras el Khezu esté ahí no podemos salir de la Vieja jungla. ¡Por favor, ven a rescatarnos, cazador!');
INSERT INTO `quest_text` VALUES ('100','en','Red Shadow in the Snow','Hunt the Red Khezu','Uncomfortable Butler','I''ve always longed to venture into the Snowy Mountains! I think I could hunt down an Anteka, but I could never fight a wyvern. Maybe you could take care of a special monster for me...');
INSERT INTO `quest_text` VALUES ('100','es','Sombra roja en la nieve','Caza al Khezu rojo','Mayor. indispuesto','¡Siempre deseé aventurarme en las Montañas Nevadas! Creo que podría cazar un Anteka, pero nunca podría enfrentarme a un Wyvern. Quizá puedas encargarte de un monstruo especial por mí.');
INSERT INTO `quest_text` VALUES ('101','en','Congalalas'' Assault','Survive until Time Over or Deliver the Paw Pass Ticket','Selfish Landowner','A large number of Congalalas are congregating in the Swamp and I want you to hunt them down. You must get rid of at least 2 of those horrid things for me. I won''t accept any less!');
INSERT INTO `quest_text` VALUES ('101','es','Asalto de Congalalas','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Terrat. egoísta','Un gran número de Congalalas se están congregando en el Pantano y quiero que los caces. Debes librarte de al menos de dos de esas cosas horribles por mí. ¡No aceptaré menos!');
INSERT INTO `quest_text` VALUES ('102','en','The Meeting of Daimyo','Survive until Time Over or Deliver the Paw Pass Ticket','Tanned Fisherman','Help! There has been an explosion of so many Daimyo Hermitaurs near our fishing grounds that we can''t handle things by ourselves! Get rid of as many as you can so we can get back to fishing!');
INSERT INTO `quest_text` VALUES ('102','es','La reunión de Daimyo','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Pescador moreno','¡Ayuda! Han aparecido tantos Daimyo Hermitaur cerca de nuestra zona de pesca que no podemos acabar con ellos nosotros solos. ¡Deshazte de todos los que puedas para que podamos volver a pescar!');
INSERT INTO `quest_text` VALUES ('103','en','Epic Hunt in the Jungle!','Hunt all of the Large Monsters','Gutsy Youth','So I hear a Yian Kut-Ku and a Daimyo Hermitaur are in the Jungle. Sounds like a job for me! Don''t worry, if you fail I''ll mop them up for you. You can count on it!');
INSERT INTO `quest_text` VALUES ('103','es','¡Caza épica en la jungla!','Caza todos los monstruos grandes','Joven con agallas','He oído que hay un Daimyo Hermitaur y un Yian Kut-Ku en la Jungla. ¡Suena a trabajo para mí! No te preocupes, si fallas, yo los quitaré de enmedio por ti. ¡Puedes contar con ello!');
INSERT INTO `quest_text` VALUES ('104','en','The Remobra Den','Slay 15 Remobras','DesertedArenaManager','I went to open up the big arena that hasn''t been used in a while one morning, and I find that it''s been turned into a Remobra nest! Please, I need you to help me clear them out!');
INSERT INTO `quest_text` VALUES ('104','es','La guarida de Remobra','Mata 15 Remobra','Jefe de la arena','Fui una mañana a abrir la arena grande, que nadie ha usado en mucho tiempo ¡y descubrí que se ha convertido en un nido de Remobra! ¡Ahora necesito que me ayudes a echarlos!');
INSERT INTO `quest_text` VALUES ('105','en','The Sleepy Great Forest','Hunt 2 Hypnocatrices','ShortHairMantledGirl','I got a request to hunt some Hypnocatrices, but I have so many other things to do that I can''t handle it all. Can you handle it in my stead, please? ...But please keep this a secret, OK?');
INSERT INTO `quest_text` VALUES ('105','es','El Gran bosque somnoliento','Caza 2 Hypnocatrice','Chica enm.pelo corto','Recibí una petición para cazar Hypnocatrice, pero tengo tantas cosas que hacer que no puedo con todas. ¿Puedes ocuparte tú en mi lugar? Pero guarda el secreto, ¿de acuerdo?');
INSERT INTO `quest_text` VALUES ('106','en','Eyes in the Underground Lake','Hunt the Plesioth','OldDesertWepnSmiths','We''ve received a rescue request from a poacher out hunting the Plesioth of the underground lake in the Old Desert. We ask that you please hold the Plesioth off while we rescue the person.');
INSERT INTO `quest_text` VALUES ('106','es','Ojos en el lago subterráneo','Caza al Plesioth','Viejo MercArmasDes','Hemos recibido una petición de rescate de un furtivo que perseguía al Plesioth del lago subterráneo del Viejo desierto. Te pedimos que contengas al Plesioth mientras lo rescatamos.');
INSERT INTO `quest_text` VALUES ('107','en','Green Waves of Verdure','Hunt 2 Green Plesioth','Hasty High Official','Help! I''ve received word that a Green Plesioth has appeared along our Queen''s route to another land. Please take care of it in secret for us before she enters the area!');
INSERT INTO `quest_text` VALUES ('107','es','Olas verdes de verdura','Caza 2 Plesioth verdes','Al.ofic.desagradable','¡Ayuda! Hemos sabido que ha aparecido un Plesioth verde en la ruta de nuestra Reina hacia otro territorio. Cuida de ella en secreto, en nuestro lugar, ¡antes de que entre en la zona!');
INSERT INTO `quest_text` VALUES ('108','en','Elegy for a Lone Wolf','Hunt the Yian Garuga','Mantled Lone Hunter','Phew... I barely made it out alive from that Yian Garuga. I''ll tell you what. You keep it a secret and I''ll let you know where you can find this sly, cool-headed beast. Have we got a deal?');
INSERT INTO `quest_text` VALUES ('108','es','Elegía por un lobo solitario','Caza al Yian Garuga','Cazador solit. enm.','Fiu... Casi no escapo vivo de ese Yian Garuga. Voy a decirte algo. Mantenlo en secreto y te diré dónde puedes encontrar a esta bestia fría y artera. ¿Trato hecho?');
INSERT INTO `quest_text` VALUES ('109','en','Battle with the Monoblos','Hunt the Monoblos','Kokoto Village Chief','This is a request to the virtuous hunters of Pokke. A Monoblos is tearing through the desert near my village of Kokoto. Please hunt it down for us!');
INSERT INTO `quest_text` VALUES ('109','es','Batalla con el Monoblos','Caza al Monoblos','Jefe aldea Kokoto','Tenemos una petición para los virtuosos cazadores de Pokke. Un Monoblos está causando estragos en el desierto próximo a mi aldea, Kokoto. ¡Por favor, cazadlo por nosotros!');
INSERT INTO `quest_text` VALUES ('110','en','Secret Request: 2 Monoblos!','Hunt the Monoblos and the White Monoblos','Pretty Mantled Lady','An ancient wall painting our country was researching was destroyed by a Monoblos, and as an art-lover, I won''t stand for it! My father can''t spare any soldiers, so you''re my only hope!');
INSERT INTO `quest_text` VALUES ('110','es','Solic. secreta: ¡2 Monoblos!','Caza al Monoblos y al Monoblos blanco','Bella Sra. enmantada','Una antigua pintura mural que nuestro país investigaba fue destruida por un Monoblos y como amante del arte ¡no pienso tolerarlo! A mi padre no le sobran soldados, así que ¡eres mi esperanza!');
INSERT INTO `quest_text` VALUES ('111','en','Kut-Ku Calamity!','Survive until Time Over or Deliver the Paw Pass Ticket','Riled Villagers','Aaaah!! A Kut-Ku here and a Kut-Ku there! The hillside is covered in a confusion of red and blue! We don''t care if you have to get rid of them one at a time, but please, just do it!');
INSERT INTO `quest_text` VALUES ('111','es','¡Calamidad Kut-Ku!','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Aldeanos irritados','¡Aah! ¡Hay Kut-Ku por todas partes! ¡La ladera está cubierta de una mezcla de rojo y azul! ¡No importa si tienes que acabar con ellos uno a uno pero, por favor, hazlo!');
INSERT INTO `quest_text` VALUES ('112','en','Basarios Season','Survive until Time Over or Deliver the Paw Pass Ticket','Unlucky Journey Lady','I was hiding from a Basarios behind some boulders when it turned out to be another one! I thought I could hide behind some other boulders ahead of me, but it was yet another one! Somebody, help!');
INSERT INTO `quest_text` VALUES ('112','es','Temporada de Basarios','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Mujer viaje desafrt.','Me escondía de un Basarios tras unos pedruscos cuando ¡resultó que había otro! Pensé que podría ocultarme detrás de otras piedras más adelante pero, ¡había otro más! ¡Que alguien me ayude!');
INSERT INTO `quest_text` VALUES ('113','en','A Shogun Tastes Like...?','Survive until Time Over or Deliver the Paw Pass Ticket','Mantled Lady','I''ve had the pleasure of tasting some exotic foods in my social circles, and I''m afraid I''ve grown fond of Shogun meat. They''re experiencing a population boom, so what better timing?');
INSERT INTO `quest_text` VALUES ('113','es','¿A qué sabe el Shogun...?','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Sra. enmantada','He tenido el placer de probar comidas exóticas en mis círculos sociales, y me temo que me he enganchado a la carne de Shogun. Están en plena explosión demográfica así que, ¿qué mejor momento?');
INSERT INTO `quest_text` VALUES ('114','en','Bl-Bl-Blangongas!','Survive until Time Over or Deliver the Paw Pass Ticket','MantledLadyInGreen','My request is this: Please hunt down a few Blangongas in a row! The beasts are too hard for the hunters of my village, so please keep this a secret and spare their pride. Good luck!');
INSERT INTO `quest_text` VALUES ('114','es','¡B-Blangonga!','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Sra. enmantada verde','Mi solicitud es ésta: ¡caza unos cuantos Blangonga seguidos! Las bestias son demasiado difíciles para los cazadores de mi aldea, así que debes guardar el secreto para no herir su orgullo.');
INSERT INTO `quest_text` VALUES ('115','en','Operation Desert Winds','Hunt all of the Large Monsters','Guild Messenger','We''ve received word that an airship made an emergency landing in the Desert, but a Monoblos often walks through the area, and the desert lake is home to a Plesioth. Please hurry to the hunt!');
INSERT INTO `quest_text` VALUES ('115','es','Operac. Viento del desierto','Caza todos los monstruos grandes','Mensajero del Gremio','Nos han dicho que una aeronave aterrizó forzosamente en el Desierto, pero por esa zona suele andar un Monoblos, y en el lago del desierto hay un Plesioth. ¡Apresúrate a cazarlos!');
INSERT INTO `quest_text` VALUES ('116','en','Congalala in a Crab Shell','Hunt all of the Large Monsters','Oblivious Daughter','I spotted that Congalala I ran into last time fighting ferociously with Mr. Crab in the Swamp. I don''t want anyone else to suffer as I have, so please do something about them both!');
INSERT INTO `quest_text` VALUES ('116','es','Congalala en concha cangrejo','Caza todos los monstruos grandes','Hija ingenua','He visto el Congalala que me encontré la última vez peleando furiosamente con el Sr. Cangrejo en el Pantano. No quiero que nadie más sufra como yo, así que ¡haz algo con ellos!');
INSERT INTO `quest_text` VALUES ('117','en','Sleepy Miasma, Poison Mist','Hunt all of the Large Monsters','Jungle Town Diplomat','The Jungle is naturally foggy, but this time, there was something unusual in the air. As it turned out, it''s the fault of two monsters in particular. I wonder if you could hunt them down for us?');
INSERT INTO `quest_text` VALUES ('117','es','Miasma sueño, niebla veneno','Caza todos los monstruos grandes','Diplom. aldea jungla','La jungla es de por sí neblinosa pero, esta vez, había algo raro en el aire. Resulta que es culpa de dos monstruos en particular. ¿Podrías cazarlos para nosotros?');
INSERT INTO `quest_text` VALUES ('118','en','Carnivores of the Old Jungle','Hunt all of the Large Monsters','Honest Retainer','Recently, travelers through the Old Jungle have been disappearing... and we''d like for you to look into this. We believe this to be the work of monsters, but we would like confirmation.');
INSERT INTO `quest_text` VALUES ('118','es','Carnívoros de Vieja jungla','Caza todos los monstruos grandes','Criado honesto','Últimamente, los viajeros que pasan por la Vieja Jungla desaparecen... y nos gustaría que lo investigaras. Creemos que es obra de monstruos, pero nos gustaría confirmarlo.');
INSERT INTO `quest_text` VALUES ('119','en','Attack of the Wind Dragon','Slay the Kushala Daora','Guild Master','A brown Kushala Daora is rapidly closing on the town. Scouts report that outlying areas have already been razed. If we don''t stop this dragon, our town will be annihilated! We need you!');
INSERT INTO `quest_text` VALUES ('119','es','Ataque del dragón del viento','Mata al Kushala Daora','Maestro del Gremio','Se está aproximando a la aldea un Kushala Daora marrón. Los exploradores dicen que ya ha arrasado las zonas periféricas. ¡Si no lo detenemos, nuestra aldea será aniquilada! ¡Ayúdanos!');
INSERT INTO `quest_text` VALUES ('120','en','The Empress''s Blazing Throne','Slay the Lunastra','Elder Dragon Scholar','We''ve received a communique from headquarters. An elder dragon has appeared in the Volcanic Belt. Fight the dragon and collect data on its behavior!');
INSERT INTO `quest_text` VALUES ('120','es','El trono de la emperatriz','Mata al Lunastra','Viejo erudito drag.','Hemos recibido un comunicado del cuartel general. Ha aparecido un Dragón anciano en la región volcánica. ¡Lucha con el dragón y obtén datos sobre su comportamiento!');
INSERT INTO `quest_text` VALUES ('121','en','Indigo Meteor','Slay the Lunastra','Fallen Aristocrat','A perfectly clear desert night sky opened up and she descended down upon me... Her form was that of a breathtaking shooting star. Surely, I am to be her king. Come, she mustn''t escape me!');
INSERT INTO `quest_text` VALUES ('121','es','Meteoro Indigo','Mata al Lunastra','Aristócr. caído','Se abrió un claro perfecto en el cielo de la noche del desierto y ella descendió sobre mí... Su forma era la de una asombrosa estrella fugaz. ¡Ven, no debe escapárseme!');
INSERT INTO `quest_text` VALUES ('122','en','Lao-Shan Lung Draws Near!','Defend the Fortress from Lao-Shan Lung','Guild Master','It seems that once again our land is in crisis. The giant elder dragon Lao-Shan Lung is approaching the village from the mountains. Head to the fort and defend our way of life!');
INSERT INTO `quest_text` VALUES ('122','es','¡Lao-Shan Lung se acerca!','Defiende la fortaleza del Lao-Shang Lung','Maestro del Gremio','Parece que nuestra tierra vuelve a estar en crisis. El anciano dragón gigante, Lao-Shan Lung, se aproxima a la aldea desde las montañas. Ve al fuerte y defiende nuestra forma de vida.');
INSERT INTO `quest_text` VALUES ('123','en','Secret Request: Nargacuga!','Hunt the Nargacuga','Brave Mantled Youth','I couldn''t sit by while the Nargacuga hurt our people, so I snuck out to go slay it... and failed. I can''t face my father like this, so please defeat it for me in secret!');
INSERT INTO `quest_text` VALUES ('123','es','Solic. secreta: ¡Nargacuga!','Caza al Nargacuga','Joven valiente enm.','No podía quedarme sentado mientras el Nargacuga hería a nuestra gente, así que me me decidí a matarlo... y fallé. No puedo enfrentarme así a mi padre, así que ¡mátalo por mí en secreto!');
INSERT INTO `quest_text` VALUES ('124','en','Assassin of the Jungle','Hunt the Nargacuga','Bearded Soldier','Our head drill sergeant was attacked while out on an expedition in the Old Jungle by an unknown assailant. We think it''s probably a monster, but we require the assistance of a hunter!');
INSERT INTO `quest_text` VALUES ('124','es','Asesino de la jungla','Caza al Nargacuga','Soldado barbudo','Nuestro sargento instructor jefe fue atacado durante una expedición a la Vieja jungla por un asaltante desconocido. ¡Creemos que es un monstruo, pero necesitamos la ayuda de un cazador!');
INSERT INTO `quest_text` VALUES ('125','en','Land of the Tremors','Hunt 2 Tigrex','Red&BlackMantledPair','We''re the Mysterious Duo, able to silence even the crying of kids! Normally, the Tigrex is nothing to us, but our stomachs are acting up a bit today, so help us out...? Owahahaha! Hahaha!');
INSERT INTO `quest_text` VALUES ('125','es','Tierra de los temblores','Caza 2 Tigrex','Pareja roja&neg enm.','Somos el dúo misterioso, ¡capaz de silenciar el llanto de los niños! Normalmente, el Tigrex no es nada para nosotros, pero hoy el estómago no está dando guerra. ¿Nos ayudarás...? ¡Jajajaja!');
INSERT INTO `quest_text` VALUES ('126','en','A King, Robed in Smoke','Hunt the Rathalos','MightyMountainMonks','Unbelievably, the king of all wyverns has appeared in the Old Volcano belt. To protect our temple, we went to fight it, but to no avail. Please, we humbly ask for your assistance, hunter!');
INSERT INTO `quest_text` VALUES ('126','es','Un rey, vestido de humo','Caza al Rathalos','Monjes del monte','Increíblemente, el rey de los Wyverns apareció en la falda del Viejo volcán. Para proteger nuestro templo salimos a luchar con él, pero sin éxito. ¡Te pedimos humildemente ayuda, cazador!');
INSERT INTO `quest_text` VALUES ('127','en','Dancing Desert Queen','Hunt the Rathian','Healed Hunter','Wow, nothing like a hunting ground to get the blood pumping and the spirit ready for the hunt! Unfortunately, while I''ve been gone, the requests have been piling up. Can you lend me a hand!?');
INSERT INTO `quest_text` VALUES ('127','es','Reina danzante del desierto','Caza la Rathian','Cazador curado','Guau, ¡nada como un cazadero para que corra la sangre y el espíritu se prepare para la caza! Por desgracia, durante mi ausencia, se me han acumulado las solicitudes. ¿Me puedes echar una mano?');
INSERT INTO `quest_text` VALUES ('128','en','Descendants of the King','Hunt the Azure Rathalos and the Pink Rathian','SharpWittedGentleman','The azure sky-king and the pink, earthly queen. Whoever successfully hunts them both shall be known as the King of Hunters. I await your return with a glass held high!');
INSERT INTO `quest_text` VALUES ('128','es','Descendientes del rey','Caza al Rathalos celeste y a la Rathian rosa','Señor ingenioso','El celeste rey del cielo y la rosa reina terrestre. Quien cace a ambos será conocido como el Rey de los cazadores. ¡Espero que vuelvas levantando una copa!');
INSERT INTO `quest_text` VALUES ('129','en','Diablos, the Demon King','Hunt the Diablos','Wounded Hunter','Ah, I tried to slay it, but I was in way over my head. Still, I can''t let it go, so I ask that if you have the courage to face this beast, to please step forward.');
INSERT INTO `quest_text` VALUES ('129','es','Diablos, el rey demonio','Caza al Diablos','Cazador herido','Ah, intenté matarlo, pero era demasiado para mí. ¡Mas no quiero dejar las cosas así! Te pido que, si tienes la valentía necesaria para enfrentarte a esta bestia, des un paso adelante.');
INSERT INTO `quest_text` VALUES ('130','en','The Four Spires','Hunt 2 Black Diablos','Bandaged-Wrapped Man','I saw four black towers rising up on the dunes... I know what I saw! It was no dream, but reality! Please, save the Old Desert Town and my two dear daughters from those menaces!');
INSERT INTO `quest_text` VALUES ('130','es','Las cuatro espiras','Caza 2 Diablos negros','Hombre con vendas','Vi cuatro torres negras gigantes elevándose en las dunas... ¡Sé lo que vi! ¡No fue un sueño, sino la realidad! ¡Salva la ciudad del Viejo desierto y a mis queridas hijas de esa amenaza!');
INSERT INTO `quest_text` VALUES ('131','en','Armored Supremacy','Hunt the Gravios','Friendly Head Knight','Even us knights can''t stand up to the Gravios''s mighty heat ray. I know this is a big request, but can you please go and hunt this armored beast in our stead?');
INSERT INTO `quest_text` VALUES ('131','es','Supremacía armada','Caza al Gravios','Cab. jefe amable','Ni siquiera nosotros, los caballeros, podemos soportar el poderoso rayo de calor del Gravios. Sé que es pedir mucho pero, ¿puedes ir a cazar esta bestia armada en nuestro lugar?');
INSERT INTO `quest_text` VALUES ('132','en','Two Black Suits of Armor','Hunt 2 Black Gravios','Guild Retiree','All of the hunters who have taken on this request have fallen one by one, until there was no one left who would even consider it. ''Tis lamentable, no? Is there no one who has the guts to try?');
INSERT INTO `quest_text` VALUES ('132','es','Dos armaduras negras','Caza 2 Gravios negros','Retirado del Gremio','Todos los cazadores que han aceptado esta solicitud han caído uno a uno, hasta no quedar ninguno dispuesto siquiera a pensarlo. Es lamentable, ¿no? ¿No hay nadie que se atreva a intentarlo?');
INSERT INTO `quest_text` VALUES ('133','en','Explore the Unexplored','Hunt the Silver Rathalos','Hunchbacked Old Lady','I''ll tell you about a secret hunting ground, I will. It doesn''t matter if it''s day or night, the silver sun always shines, giving would-be hunters a good workout... Heh, heh, heh...!');
INSERT INTO `quest_text` VALUES ('133','es','Explora lo inexplorado','Caza al Rathalos plateado','Anciana jorobada','Te voy a hablar de un cazadero secreto. No importa si es de día o de noche, el sol plateado brilla siempre, sirviendo de entrenamiento a los aspirantes a cazador... ¡Je, je, je...!');
INSERT INTO `quest_text` VALUES ('134','en','A Single Beam of Moonlight','Hunt the Gold Rathian','Well-Dressed Youth','We were dazed and lost in a haze for days when we came upon a mysterious land. There, we spied a golden moon. If I tell you the location, will you look into the area for me in secret?');
INSERT INTO `quest_text` VALUES ('134','es','Un único rayo de luz de luna','Caza la Rathian dorada','Joven bien vestido','Pasamos días aturdidos y perdidos en la bruma hasta llegar a una tierra misteriosa. Allí vimos una luna dorada. Si te digo dónde, ¿investigarás esa zona por mí, en secreto?');
INSERT INTO `quest_text` VALUES ('135','en','Fire Ring, Lunar Ring','Hunt the Silver Rathalos and the Gold Rathian','Big-NosedMantledMan','A gold- and silver-colored wyvern have taken over the area our village was going to develop. We''d like to keep this area a secret, even from hunters we know, so we''re counting on you!');
INSERT INTO `quest_text` VALUES ('135','es','Anillo de fuego anillo lunar','Caza al Rathalos plateado y a la Rathian dorada','Hombre enm. nariz gr','Un Wyvern dorado y plateado se ha apoderado de la zona donde iba a desarrollarse nuestra aldea. Queremos mantener esta zona en secreto, incluso para cazadores conocidos. ¡Contamos contigo!');
INSERT INTO `quest_text` VALUES ('136','en','Attack of the Rajang','Hunt the Rajang','Big-VoicedMantledMan','Wahaha! It is I, the Mystery Man! I came here to drive the Instructor''s Rajang crazy and to hinder the progress of his students! So, come on, take my job! It can be our secret. Wahaha!');
INSERT INTO `quest_text` VALUES ('136','es','Ataque del Rajang','Caza al Rajang','Hombre enm. voz pot.','¡Ajajá! ¡Soy yo, el hombre misterioso! ¡He venido a volver loco al Rajang del Instructor y a obstaculizar el progreso de sus estudiantes. ¡Vamos, acepta mi trabajo! ¡Será nuestro secreto!');
INSERT INTO `quest_text` VALUES ('137','en','It''s Electric','Slay the Kirin','Practicality Scholar','There''s something causing lightning strikes in the heart of the Old Jungle. My theory is that this is proof that the mythical beast has come out of hiding. Isn''t it absolutely fascinating?');
INSERT INTO `quest_text` VALUES ('137','es','Es eléctrico','Mata al Kirin','Erudito práctico','Hay algo que provoca relámpagos en el corazón de la Vieja jungla. Mi teoría es que es la prueba de que la bestia mítica ha salido de su escondite. ¿No es absolutamente fascinante?');
INSERT INTO `quest_text` VALUES ('138','en','Diamond Dust','Hunt all of the Large Monsters','Base Village Elder','Recently, the weather around the Snowy Mountains has been bad nonstop. Further, the monsters are hungry from a lack of food, and have started to violently attack each other. Please help us!');
INSERT INTO `quest_text` VALUES ('138','es','Polvo de diamante','Caza todos los monstruos grandes','Anciano aldea base','Recientemente, el tiempo no ha parado de ser malo en las Montañas Nevadas. Además, los monstruos tienen hambre por la falta de comida y han empezado a atacarse violentamente entre sí. ¡Ayúdanos!');
INSERT INTO `quest_text` VALUES ('139','en','Hard-Shelled Terrors','Hunt all of the Large Monsters','Princess''s Attendant','The princess has run off by herself to dig up some jewels in the Volcano! If someone were to find out, it would cause a huge stink. We haven''t a moment to lose. Please set out at once!');
INSERT INTO `quest_text` VALUES ('139','es','Terrores de concha dura','Caza todos los monstruos grandes','Ayuda de cámara','La princesa ha escapado sola a buscar joyas en el Volcán. Si alguien lo averiguara causaría un problema grave. No tenemos un momento que perder. ¡Sal ahora mismo!');
INSERT INTO `quest_text` VALUES ('140','en','Bird Wyvern All-Stars','Hunt all of the Large Monsters','BittrlyUnlkyJurnyLdy','I absolutely hate birds. I hate their voices, their beaks, their eyes -- everything! And just my luck, 3 bird-like monsters live right next to my house. ARGH! Please help me!');
INSERT INTO `quest_text` VALUES ('140','es','Pájaros estrella Wyvern','Caza todos los monstruos grandes','Dama','Odio a muerte a los pájaros. Odio sus voces, sus picos, sus ojos, ¡todo! Y mira qué suerte, hay 3 monstruos con aspecto de pájaro viviendo junto a mi casa. ¡ARGH! ¡Ayúdame, por favor!');
INSERT INTO `quest_text` VALUES ('141','en','Sand Dune''s Might','Hunt all of the Large Monsters','Half-Wild Mercenary','The scorching sands reveal a Monoblos while a Daimyo surfaces from underground and the roar of a Rathian echoes overhead. This isn''t a request, but a warning. If you head out, return safely!');
INSERT INTO `quest_text` VALUES ('141','es','Fuerza de las dunas de arena','Caza todos los monstruos grandes','Merc. semi-salvaje','La arena quemada revela un Monoblos, mientras surge del suelo un Daimyo Hermitaur y resuena el rugido de una Rathian. Esto no es una solicitud sino una advertencia. ¡Si sales, vuelve sano!');
INSERT INTO `quest_text` VALUES ('142','en','The Elder Dragon of Mist','Slay the Chameleos','Injured Hero','Our intuition told us to turn around, but we thought no one was there... Yet even though no one should''ve been there, we were attacked from behind! Beware! It was an enemy never before seen!');
INSERT INTO `quest_text` VALUES ('142','es','Anciano dragón de la niebla','Mata al Chameleos','Héroe herido','Nuestra intuición nos decía que regresáramos, pero pensábamos que allí no había nadie. Y aunque debería haber sido cierto, nos atacaron. ¡Cuidado! ¡Jamás se ha visto enemigo igual!');
INSERT INTO `quest_text` VALUES ('143','en','Evaporate into the Night','Slay the Chameleos','Jungle Ancient','People think it''s impossible to fight an enemy you cannot see, however, if one were to focus and "see" with your gut instinct... Well, if all else fails, just swing your weapon round and round!');
INSERT INTO `quest_text` VALUES ('143','es','Evapórate en la noche','Mata al Chameleos','Anciano jungla','La gente piensa que es imposible luchar con un enemigo invisible, pero si uno enfocara y "viera" con el instinto... Bien, ¡si todo lo demás falla puedes hacer girar y girar el arma!');
INSERT INTO `quest_text` VALUES ('144','en','Fight for Your Life!','Slay the Teostra','Guild Manager','The Town is under attack from the Teostra! Casualties are high and it''s only a matter of time before the town falls. We''ll pay you whatever you ask; just hurry to their aid!');
INSERT INTO `quest_text` VALUES ('144','es','¡Lucha por tu vida!','Mata al Teostra','Jefe del Gremio','La aldea está siendo atacada por el Teostra. Hay muchas bajas y sólo es cuestión de tiempo que caiga la aldea. Te pagaremos lo que pidas, ¡corre en su ayuda!');
INSERT INTO `quest_text` VALUES ('145','en','A Midnight Audience','Slay the Teostra','Ill-ReputedInformant','The Teostra''s hideaway can only be found during the darkest hour, but I have done it. Now, if you can keep a secret, I''ll tell you where it is, and of course you will be well rewarded...');
INSERT INTO `quest_text` VALUES ('145','es','Una audiencia de medianoche','Mata al Teostra','Soplón mala rep.','El escondite del Teostra sólo se puede encontrar en la hora más oscura. Si sabes guardar un secreto, te diré dónde está y, por supuesto, se te recompensará bien...');
INSERT INTO `quest_text` VALUES ('146','en','The Approaching Gaoren','Defend the Fortress from Shen Gaoren','Mantled Giant','Hmm... This is quite serious. The fort which lies at the heart of our defenses is under siege by a giant monster. We need your strength to hold our position!');
INSERT INTO `quest_text` VALUES ('146','es','El Gaoren se aproxima','Defiende la fortaleza de Shen Gaoren','Gigante enmantado','Umm... Esto es serio. Un Wyvern gigante está asediando el fuerte que se encuentra en el corazón de nuestras defensas. ¡Necesitamos tu fuerza para resistir el ataque!');
INSERT INTO `quest_text` VALUES ('147','en','Monster Hunter','Hunt all of the Large Monsters','Red-Clad Knight','I''m overjoyed at the chance to see a hunter as skilled as yourself. I sense that should you complete this final quest, you will come to know the true meaning of a hunter''s life!');
INSERT INTO `quest_text` VALUES ('147','es','Cazador de monstruos','Caza todos los monstruos grandes','Caballero de rojo','Estoy encantado de tener la oportunidad de ver un cazador tan bueno como tú. Creo que debes completar esta misión final, ¡conocerás el verdadero significado de la vida de un cazador!');
INSERT INTO `quest_text` VALUES ('148','en','Rise to the Summit','Slay the Akantor','Popular Mantled Man','We finally have the mighty Akantor cornered in the Volcano, but our forces are exhausted and there is mass confusion. Please, I humbly request that you secretly slay the beast for us!');
INSERT INTO `quest_text` VALUES ('148','es','Ascenso a la cima','Mata al Akantor','Hombre enmm. popular','Finalmente hemos logrado acorralar al poderoso Akantor en el Volcán. pero nuestras fuerzas se agotan y hay mucha confusión. ¡Te pido humildemente que mates a la bestia en secreto!');
INSERT INTO `quest_text` VALUES ('149','en','A True Foe - The Giadrome!','Hunt the Giadrome','Spirited Boy','Within a group of the sly carnivorous Giaprey, there is a leader. They call it the Giadrome. I need a hunter''s strength to show that pack of beasts and their leader who''s boss!');
INSERT INTO `quest_text` VALUES ('149','es','Todo un enemigo: el Giadrome','Caza al Giadrome','Chico alegre','En los grupos de astutos Giaprey carnívoros, hay un líder. Le llaman el Giadrome. ¡Necesito la fuerza de un cazador para demostrarles a esas bestias y su líder quién manda aquí!');
INSERT INTO `quest_text` VALUES ('150','en','Reckless Bulldrome Hunter','Hunt the Bulldrome','Troubled Father','My son decided to become a hunter and ran off after a Bulldrome on his own! Of course, now the tables have turned and I''m worried! Hunt down the Bulldrome on the snowy mountains!');
INSERT INTO `quest_text` VALUES ('150','es','Cazador de Bulldrome','Caza al Bulldrome','Padre preocupado','¡Mi hijo decidió ser cazador y se fue él solo tras un Bulldrome! Ya ha pasado un tiempo y estoy bastante preocupado. ¡Caza al Bulldrome en las montañas nevadas!');
INSERT INTO `quest_text` VALUES ('151','en','A Pack of Blangos','Slay 15 Blangos','Wise Maiden','A large pack of Blangos are massing nearby. They are violent enough that a large group will quickly become uncontrollable. Please slay 15 of the apes!');
INSERT INTO `quest_text` VALUES ('151','es','Una manada de Blango','Mata a 15 Blango','Doncella sabia','Se está acercando una gran manada de Blango. Son lo bastante listos para ser incontrolables en un grupo tan grande. ¡Mata a 15 de los monos!');
INSERT INTO `quest_text` VALUES ('152','en','Mountain Herb Picking','Deliver 20 Mountain Herbs','Loving Sibling','I want to pick some of this village''s famous Mountain Herbs for my brother in town, but there are too many monsters! Could you please go out for me and bring back 20 Mountain Herbs?');
INSERT INTO `quest_text` VALUES ('152','es','Recogida de Hierbas','Entrega 20 Hierbas de montaña','Hermano cariñoso','Quiero enviar unas Hierbas de montaña a mi hermano de la ciudad, pero hay demasiados monstruos. Tráeme 20 Hierbas de montaña.');
INSERT INTO `quest_text` VALUES ('153','en','Rarest of the Rare Beasts','Hunt the Congalala','Village Grocer','Do you know of a pink, fanged beast that roams the jungle? That beast has dirtied my shop beyond hope! It''s impossible to clean up! Get rid of it before I''m soiled again!');
INSERT INTO `quest_text` VALUES ('153','es','La más rara de las bestias','Caza al Congalala','Tendero de la aldea','¿Conoces a una bestia rosa con colmillos que vive en la jungla? ¡Me ha dejado la tienda hecha una porquería! ¡No hay quien la limpie! ¡Cázala antes de que lo vuelva a hacer!');
INSERT INTO `quest_text` VALUES ('154','en','Hunt the Rare Forest Congas!','Slay 15 Congas','Oblivious Daughter','I took a trip to the jungle and saw some beautiful pink animals with fangs. But when I tried to pet them from my carriage, the beasts made a stink on me! I can''t get it off! Punish those meanies!');
INSERT INTO `quest_text` VALUES ('154','es','¡Caza al Conga del bosque!','Mata a 15 Conga','Hija ingenua','Cuando fui a la jungla, vi unos bonitos animales rosas con colmillos. Esas cosas me lanzaron una peste que no me puedo quitar de encima. ¡Castígalos!');
INSERT INTO `quest_text` VALUES ('155','en','A Mushroom Goldrush!','Deliver 20 Special Mushrooms','Greedy Merchant','Mushrooms from the jungle are skyrocketing in price! If you were to gather 20 of them for me, you would be justly compensated. However, I hear the area is infested with carnivores, so beware!');
INSERT INTO `quest_text` VALUES ('155','es','¡La fiebre de la seta!','Entrega 20 Setas especiales','Mercader ávido','¡Las setas de la jungla están por las nubes! Si me traes 20 de esas setas, te recompensaré generosamente. Pero me han dicho que la zona está llena de carnívoros. ¡Ten cuidado!');
INSERT INTO `quest_text` VALUES ('156','en','The Land Shark','Hunt the Cephadrome','Oasis Village Chief','A villager was tracking a pack of monsters, but lost sight of them in the desert. Please find the leader of the pack and hunt it down for us.');
INSERT INTO `quest_text` VALUES ('156','es','El tiburón terrestre','Caza al Cephadrome','Jefe de aldea Oasis','Un aldeano seguía a una manada de monstruos, pero los perdió en el desierto. Busca al líder de la manada y cázalo por nosotros.');
INSERT INTO `quest_text` VALUES ('157','en','The Giant Enemy Crab','Hunt the Daimyo Hermitaur','Defeated Warrior','A giant crab is wandering around the desert! However, no normal sword is capable of cracking its shell! I hate to ask for help from other hunters, but please lend me your skills!');
INSERT INTO `quest_text` VALUES ('157','es','El terrible cangrejo gigante','Caza al Daimyo Hermitaur','Guerrero derrotado','¡Por el desierto anda suelto un cangrejo gigante! Pero ninguna espada normal puede romper su concha. No me gusta pedir ayuda a otros cazadores, pero te ruego que me prestes tus habilidades.');
INSERT INTO `quest_text` VALUES ('158','en','The Lady Gourmet','Deliver 8 Piscine Livers','The Lady Gourmet','I travel the world for new tastes and flavors. Now I want to try the liver of a Piscine Wyvern, a taste few others have experienced. Please bring me 8 of these livers!');
INSERT INTO `quest_text` VALUES ('158','es','La Señora Gourmet','Entrega 8 Hígados de Piscine','La Señora Gourmet','Recorro el mundo en busca de nuevos sabores. Me gustaría probar el Hígado de un Piscine Wyvern, una delicia que pocos han saboreado. ¡Por favor, tráeme 8 de esos Hígados!');
INSERT INTO `quest_text` VALUES ('159','en','The Shadow in the Mountains','Hunt the Khezu','Old Geologist','We were exploring a snow-covered mountain near here, but stumbled on this disgusting blob-like monster! If you can''t get rid of that thing, our research is doomed! Help us!');
INSERT INTO `quest_text` VALUES ('159','es','La sombra de las montañas','Caza al Khezu','Viejo geólogo','Estábamos explorando una montaña cubierta de nieve cerca de aquí y apareció ese asqueroso monstruo. ¡Si no lo cazas, nuestra investigación está perdida! ¡Ayúdanos!');
INSERT INTO `quest_text` VALUES ('160','en','The King of the Mountains','Hunt the Blangonga','Foothills Villager','A Blangonga has staked its claim to a piece of the snowy mountains. Now we can''t enter the area to gather firewood. Exterminate the Blangonga!');
INSERT INTO `quest_text` VALUES ('160','es','El rey de las montañas','Caza al Blangonga','Montañés','Un Blangonga ha reclamado su derecho a una parte de las montañas nevadas. Ya no podemos entrar en esa zona para buscar leña. ¡Caza al Blangonga!');
INSERT INTO `quest_text` VALUES ('161','en','A Swarm of Hermitaurs','Slay 10 Hermitaurs','Jungle Fisherman','Fishing is no easy endeavor, but lately things have gotten out of hand! While unloading my ship, a swarm of Hermitaurs appeared. Slay 10 of them and let me get on with my work!');
INSERT INTO `quest_text` VALUES ('161','es','Un enjambre de Hermitaur','Mata a 10 Hermitaur','Pescadores de jungla','¡Pescar no es una tarea fácil, pero últimamente las cosas se han complicado! Al descargar el barco, apareció un enjambre de Hermitaur. ¡Mata a 10 para que pueda seguir haciendo mi trabajo!');
INSERT INTO `quest_text` VALUES ('162','en','Water Wyvern in the Desert','Hunt the Plesioth','Proud Hunter','I found a giant water wyvern in a cave in the desert! I can''t defeat it because it stays underwater. Slay it for me and the glory is all yours!');
INSERT INTO `quest_text` VALUES ('162','es','Wyvern de agua en desierto','Caza al Plesioth','Cazador orgulloso','¡Encontré un Wyvern de agua gigante en una cueva del desierto! No puedo matarlo porque está bajo el agua. ¡Cázalo por mí y la gloria será toda tuya!');
INSERT INTO `quest_text` VALUES ('163','en','Gypceros: Venomous Terror','Hunt the Gypceros','Swamp Farmer','The fields all around the town are getting torn to shreds by a gigantic poisonous bird-like monster. Exterminate it for us! Its poison can melt crops, so be careful it doesn''t melt you!');
INSERT INTO `quest_text` VALUES ('163','es','Gypceros: terror venenoso','Caza al Gypceros','Granjero del pantano','Los campos que rodean la ciudad están siendo arrasados por un monstruo similar a un pájaro. ¡Cázalo por nosotros! Su veneno funde las cosechas. ¡Que no te funda a ti!');
INSERT INTO `quest_text` VALUES ('164','en','Supreme Ruler of the Swamp','Hunt the Shogun Ceanataur','Scheming Strategist','Hunters! It is time to hunt down the Shogun Ceanataur. Let us rid the swamp zone of this menace and expand our strategic possibilities. This is a highly classified hunt. So don''t tell a soul!');
INSERT INTO `quest_text` VALUES ('164','es','El gran rey del pantano','Caza al Shogun Ceanataur','Estratega maquinador','¡Cazadores! Es hora de cazar al Shogun Ceanataur. Vamos a librar al pantano de esa amenaza y mejorar nuestra posición estratégica. Se trata de una caza de alto secreto.');
INSERT INTO `quest_text` VALUES ('165','en','Slay the Great Kut-Ku!','Hunt the Yian Kut-Ku','Foothills Guardsman','A bird-like Yian Kut-Ku is attacking people the world over! It has even shown up in these very hills! If it isn''t eliminated soon, we''re finished! Show me what you''re made of!');
INSERT INTO `quest_text` VALUES ('165','es','¡Caza al gran Kut-Ku!','Caza al Yian Kut-Ku','Guarda forestal','¡Un Yian Kut-Ku con forma de pájaro está atacando el mundo entero! ¡Incluso ha pasado por estas colinas! Si no lo cazamos pronto, estamos acabados. ¡Vamos a ver lo que vales!');
INSERT INTO `quest_text` VALUES ('166','en','Eliminate the Rathalos!','Hunt the Rathalos','The Kindly Lord','I request the assistance of only the bravest of hunters to find and hunt the Rathalos that has appeared near here. Of course, a handsome reward will be paid upon success.');
INSERT INTO `quest_text` VALUES ('166','es','¡Caza al Rathalos!','Caza al Rathalos','El bondadoso señor','Solicito la ayuda de los cazadores más valientes para buscar y cazar al Rathalos que ha aparecido cerca de aquí. Obviamente, si lo consiguen, recibirán una buena recompensa.');
INSERT INTO `quest_text` VALUES ('167','en','Attack of the Rathian','Hunt the Rathian','Caravan Leader','My caravan was wiped out by the queen of the skies, the killer Rathian! I''ll pay you whatever you ask if you hunt down that foul creature! Help me kind hunter, you''re my only hope!');
INSERT INTO `quest_text` VALUES ('167','es','Ataque de Rathian','Caza la Rathian','Líder de caravana','Mi caravana fue aniquilada por la reina de los cielos, una Rathian asesina. ¡Te pagaré lo que quieras si cazas a esa criatura! Ayúdame, amable cazador. ¡Eres mi última esperanza!');
INSERT INTO `quest_text` VALUES ('168','en','Gathering - Snowy Mountains','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A daytime gathering quest on the snowy mountains. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('168','es','Recogida – Montañas nevadas','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida diurna en las montañas nevadas. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('169','en','Gathering - Jungle Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A daytime gathering quest in the jungle. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('169','es','Recogida – Zona de jungla','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida diurna en la jungla. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('170','en','Gathering - Desert Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A daytime gathering quest in the desert. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('170','es','Recogida – Zona desértica','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida diurna en el desierto. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('171','en','Giadrome Assault','Hunt the Giadrome','Young Guardsman','After you killed those Giaprey, their leader showed up and it''s not a happy camper! It''s bigger, and has a green crest. Find it and kill it!');
INSERT INTO `quest_text` VALUES ('171','es','Asalto de Giadrome','Caza al Giadrome','Guardia joven','¡Después de matar a esos Giaprey, apareció su líder, que no parece estar muy contento! Es más grande y tiene una cresta verde. ¡Encuéntralo y cázalo!');
INSERT INTO `quest_text` VALUES ('172','en','The Mountain Roughrider','Hunt the Bulldrome','Familiar Villager','The thick skinned Bulldrome is well adapted to life in the mountains. Yet it''s nothing but a pest for those of us living amongst the peaks! Which is why I''d like you to get rid of it!');
INSERT INTO `quest_text` VALUES ('172','es','El domador de caballos','Caza al Bulldrome','Aldeano familiar','El Bulldrome está muy bien adaptado a la vida en las montañas. ¡Pero es una plaga para todos los que vivimos entre los picos! ¡Por eso me gustaría que lo cazaras!');
INSERT INTO `quest_text` VALUES ('173','en','Slay the Giaprey!','Slay 20 Giaprey','Proud Farmer','I chased off a Giaprey that was feeding on my Popos, but now it''s back with 19 of its buddies! I can''t take on the whole lot of them! Hunters, this is your chance! Please get rid of them for me!');
INSERT INTO `quest_text` VALUES ('173','es','¡Mata a los Giaprey!','Mata a 20 Giaprey','Granjero orgulloso','¡Ahuyenté al Giaprey que se comía a mis Popo! ¡Pero regresó con 19 amigos suyos y son demasiados para mí! ¡Por favor, deshazte de ellos por mí! ¡Cazadores, ésta es vuestra oportunidad!');
INSERT INTO `quest_text` VALUES ('174','en','Find the Mountain Herbs!','Deliver 20 Mountain Herbs','Loudmouth Lady','Steeping Mountain Herbs in this special brew has miraculous medical effects. However, I''ve run out of the herbs essential to the concoction. Find 20 of them and bring them to me!');
INSERT INTO `quest_text` VALUES ('174','es','¡Busca Hierbas de montaña!','Entrega 20 Hierbas de montaña','Señora chillona','Si se remojan estas Hierbas en este brebaje especial, se consiguen efectos médicos milagrosos. Pero me he quedado sin las hierbas de la cocción. ¡Encuentra 20 y tráemelas!');
INSERT INTO `quest_text` VALUES ('175','en','Hunt Down the Velocidrome!','Hunt the Velocidrome','Newly Wedded Husband','It seems that whenever my wife goes to pick mushrooms in the Jungle, a large carnivore appears! There''s no way I can let her go pick mushrooms now... Please! Make the Jungle safe again!');
INSERT INTO `quest_text` VALUES ('175','es','¡Caza al Velocidrome!','Caza al Velocidrome','Hombre recién casado','¡Cuando mi mujer está recogiendo setas, aparece un carnívoro enorme! No va a volver a salir a recoger setas en su vida... ¡Ayúdanos a proteger a los aldeanos!');
INSERT INTO `quest_text` VALUES ('176','en','Blue Menace of the Jungle','Hunt the Blue Yian Kut-Ku','Jungle Envoy','I want you to hunt and kill the giant bird-like monster that has appeared in our jungle. It''s wreaking havoc on our environment!');
INSERT INTO `quest_text` VALUES ('176','es','La amenaza azul de la jungla','Caza al Yian Kut-Ku azul','Enviado de la jungla','Quiero que caces y mates al monstruo gigante con forma de pájaro que apareció en la jungla. ¡Está arrasando nuestras tierras!');
INSERT INTO `quest_text` VALUES ('177','en','Cunning Raiders','Slay 20 Velociprey','Resident Farmers','A group of blue scaled, pack hunting carnivores called Velociprey have infested the jungle. Please slay 20 of them for us... But beware of their boss!');
INSERT INTO `quest_text` VALUES ('177','es','Astutos atacantes','Mata a 20 Velociprey','Granjeros residentes','Un grupo de carnívoros de escamas azules que cazan en grupo llamados Velociprey ha infestado la jungla. Mata a 20 por nosotros... ¡Pero cuidado con su jefe!');
INSERT INTO `quest_text` VALUES ('178','en','Attack of the Giant Bugs!','Slay 50 Vespoids','Jungle Envoy','My village is under attack by a swarm of bug monsters! It seems there are about 50 of them. One on one they are not a threat, but as a group they are deadly. So be careful.');
INSERT INTO `quest_text` VALUES ('178','es','¡Atacan los bichos gigantes!','Mata a 50 Vespoid','Enviado de la jungla','¡Una manada de monstruos bicho está atacando mi aldea! Parece que hay unos 50. Individualmente no son una amenaza, pero como grupo son mortales. Ten cuidado.');
INSERT INTO `quest_text` VALUES ('179','en','The Mushroom Hunt!','Deliver 20 Special Mushrooms','The Lady Gourmet','My doggie just looooves Special Mushrooms! I''d like you to bring me 20 of them, as I can''t resist his puppy dog eyes. However, beware of that filthy pink vagrant brute!');
INSERT INTO `quest_text` VALUES ('179','es','¡La caza de setas!','Entrega 20 Setas especiales','La Señora Gourmet','¡Mi perrito adoora las Setas especiales! Me gustaría que me trajeras 20. No resisto esos ojitos que me pone. ¡Pero ten cuidado con esa asquerosa bestia rosa!');
INSERT INTO `quest_text` VALUES ('180','en','Panning for Goldenfish','Deliver 3 Goldenfish','The Collector','I''d do anything to get my hands on some legendary Goldenfish! I''m begging you to bring me 2 of them! Wait! Make that 3! Please catch these fish and bring them here!');
INSERT INTO `quest_text` VALUES ('180','es','Lavar Peces dorados','Entrega 3 Peces dorados','El coleccionista','¡Daría lo que fuera por hacerme con un legendario Pez dorado! ¡Te suplico que me traigas 2! ¡No! ¡Que sean 3! ¡Por favor, péscalos y tráemelos aquí!');
INSERT INTO `quest_text` VALUES ('181','en','Hunt the Gendrome!','Hunt the Gendrome','Ambitious Noble','My caravans are being hit by packs of Genprey. It appears there is an extraordinarily powerful boss among them! Hunt down the monster and make the roads safe again for all!');
INSERT INTO `quest_text` VALUES ('181','es','¡Caza al Gendrome!','Caza al Gendrome','Noble ambicioso','Las manadas de Genprey están atacando mis caravanas. ¡Al parecer, tienen un jefe extraordinariamente fuerte! ¡Caza a ese monstruo y haz que las carreteras vuelvan a ser seguras para todos!');
INSERT INTO `quest_text` VALUES ('182','en','The Land Shark','Hunt the Cephadrome','Oasis Village Chief','Our pack-animals were eaten by something in the desert. But nobody actually saw the monster attack! Track down this vile beast and take it out!');
INSERT INTO `quest_text` VALUES ('182','es','El tiburón terrestre','Caza al Cephadrome','Jefe de aldea Oasis','Algo se ha comido a nuestras bestias de carga en el desierto. Pero nadie vio el ataque. ¡Localiza a esa malvada bestia y cázala!');
INSERT INTO `quest_text` VALUES ('183','en','The Lurking Desert Giant','Hunt the Daimyo Hermitaur','Lynian Clan Leader','When some of my clan went gathering in the desert, they were attacked by an enormous crab, nya! As long as he''s around, we can''t do business. Help us, nya!');
INSERT INTO `quest_text` VALUES ('183','es','El gigante del desierto','Caza al Daimyo Hermitaur','Líder clan Lynian','¡Algunos de mi clan fueron atacados por un enorme cangrejo cuando estaban de recogida! Mientras esté por aquí, no podremos trabajar. ¡Ayúdanos, miau!');
INSERT INTO `quest_text` VALUES ('184','en','Slay the Genprey!','Slay 20 Genprey','Injured Soldier','I''m too injured to go on... The Genprey living in the desert have the power to paralyze their foes. I''d like you to find the pack that did this to me and kill 20 of the fiends!');
INSERT INTO `quest_text` VALUES ('184','es','¡Mata a los Genprey!','Mata a 20 Genprey','Soldado herido','Estoy muy malherido para continuar... Los Genprey que viven en el desierto pueden paralizar a su enemigo. ¡Me gustaría que encontraras a la manada que me hizo esto y que mates a 20 de ellos!');
INSERT INTO `quest_text` VALUES ('185','en','Liver of Legend!','Deliver 10 Piscine Livers','Foreign Peddler','Hello sirs and madams! I deal in rare items that I find in the desert. Recently I''ve got a buyer for Piscine Wyvern and Sand Wyvern livers. Deliver 10 of them to me!');
INSERT INTO `quest_text` VALUES ('185','es','¡Hígado de leyenda!','Entrega 10 Hígados de Piscine','Vend amb extranjero','¡Hola, damas y caballeros! Vendo objetos raros del desierto. Acabo de encontrar un comprador de Hígados de Piscine Wyvern y Wyvern de arena. ¡Tráiganme 10 de esos Hígados!');
INSERT INTO `quest_text` VALUES ('186','en','Gone Fishin''','Deliver 3 Goldenfish','Twilight Fisherman','Fishing. It carries on in the hearts of children and remains a simple pleasure for adults. Hearken back to a simpler time and bring me back 3 of the desert''s most precious gift... Goldenfish!');
INSERT INTO `quest_text` VALUES ('186','es','De pesca','Entrega 3 Peces dorados','Pescador del ocaso','La pesca. Está en el corazón de los niños y es un placer sencillo para los adultos. Rememora aquellos tiempos y tráeme 3 de los regalos más preciados del desierto... ¡Peces dorados!');
INSERT INTO `quest_text` VALUES ('187','en','Attack of the Yian Kut-Ku','Hunt the Yian Kut-Ku','Novice Hunter','That big eared Yian Kut-Ku really made mincemeat out of me! It''s out of my league, so I want you to hunt it down for me! He''s all yours!');
INSERT INTO `quest_text` VALUES ('187','es','Ataque del Yian Kut-Ku','Caza al Yian Kut-Ku','Cazador novato','¡Ese Yian Kut-Ku de las orejas grandes me ha hecho puré! No estoy a su nivel. ¡Quiero que lo caces por mí! ¡Es todo tuyo!');
INSERT INTO `quest_text` VALUES ('188','en','Charge... Charge... Charge!','Hunt the Bulldrome','The Shocked Lord','We have a plan to rid the swamp of the scourge of the Bulldrome; however, we do not have enough hunters for the job. That is why we need your help! Let us rid the swamp of this foul beast!');
INSERT INTO `quest_text` VALUES ('188','es','¡Carga... carga!','Caza al Bulldrome','Señor horrorizado','Tenemos un plan para librar al pantano del azote del Bulldrome, pero no tenemos suficientes cazadores para el trabajo. ¡Por eso necesitamos tu ayuda! ¡Vamos a cazar a esa bestia!');
INSERT INTO `quest_text` VALUES ('189','en','The Mischief-maker','Hunt the Congalala','Oblivious Daughter','I took a trip to the swamp and saw a pretty pink animal with fangs. But when I tried to call it to the carriage, it threw something dirty at me and now I can''t get the smell off! Punish it!');
INSERT INTO `quest_text` VALUES ('189','es','El travieso','Caza al Congalala','Hija ingenua','En el pantano, vi un lindo animal rosa con colmillos. Pero cuando lo llamé desde el carro, me lanzó algo asqueroso. ¡Ahora no me puedo quitar ese olor de encima! ¡Castígalo!');
INSERT INTO `quest_text` VALUES ('190','en','Gathering - Swamp Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A daytime gathering quest in the swamp. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('190','es','Recogida – Zona pantanosa','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida diurna en el pantano. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('191','en','Gathering - Forest and Hills','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A daytime gathering quest in the forest and hills. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('191','es','Recogida – Bosque y colinas','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida diurna en el bosque y colinas. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('192','en','Gathering - Volcanic Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A daytime gathering quest in the volcanic zone. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up.');
INSERT INTO `quest_text` VALUES ('192','es','Recogida – Zona volcánica','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida diurna en la región volcánica. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar.');
INSERT INTO `quest_text` VALUES ('193','en','The Ruler of the Snow','Hunt the Blangonga','Guild Master','As the representative of the Hunter''s Guild, allow me to lay out our request. We would like you to hunt down the proud ruler of the mountains, the Blangonga... But you must be prepared!');
INSERT INTO `quest_text` VALUES ('193','es','El regente de la nieve','Caza al Blangonga','Maestro del Gremio','Como representante del Gremio de cazadores, deja que te exponga nuestra petición. Nos gustaría que cazaras al señor de las montañas, el Blangonga... ¡Pero debes estar preparado!');
INSERT INTO `quest_text` VALUES ('194','en','The Shadow in the Cave','Hunt the Khezu','Old Geologist','We were exploring a cave near here, but stumbled on this disgusting blob-like monster! If you can''t get rid of that thing, our research is doomed! Help us!');
INSERT INTO `quest_text` VALUES ('194','es','La sombra de la cueva','Caza al Khezu','Viejo geólogo','Estábamos explorando una cueva cerca de aquí y apareció ese asqueroso monstruo. ¡Si no le cazas, nuestra investigación está perdida! ¡Ayúdanos!');
INSERT INTO `quest_text` VALUES ('195','en','Red Shadow in the Snow','Hunt the Red Khezu','Uncomfortable Butler','I''ve always longed to venture into the snowy mountains! I think I could hunt down an Anteka, but I could never fight a wyvern. Maybe you could take care of a special monster for me...');
INSERT INTO `quest_text` VALUES ('195','es','Sombra roja en la nieve','Caza al Khezu rojo','Mayor. indispuesto','¡Siempre deseé aventurarme en las montañas nevadas! Creo que podría cazar un Anteka, pero nunca podría enfrentarme a un Wyvern. Quizá puedas encargarte de un monstruo especial por mí.');
INSERT INTO `quest_text` VALUES ('196','en','Blango Slaying Tactics','Slay 20 Blangos','Armory Owner','The pelt of a Blango can be made into various pieces of armor that are useful in everyday life. Slay 20 of the beasts and bring me their pelts. Beware of the Blangonga.');
INSERT INTO `quest_text` VALUES ('196','es','Tácticas Blango','Mata a 20 Blango','Propietario armería','El pelo del Blango sirve para fabricar varios tipos de armaduras muy útiles para la vida cotidiana. Mata a 20 y tráemelos, pero cuidado con el Blangonga.');
INSERT INTO `quest_text` VALUES ('197','en','The Subterranean Glutton','Deliver 5 Khezu Whelps','Delicacy Collector','I''m after the rare larvae of the Khezu. They should be on the summit, so search there. These whelps aren''t to be taken lightly. If you run out of Pickaxes, combine a bone with a rock!');
INSERT INTO `quest_text` VALUES ('197','es','El glotón subterráneo','Entrega 5 Larvas de Khezu','Coleccionista obj.','Estoy buscando larvas del Khezu. Deberían de estar en la cima, así que busca allí. No subestimes a esas crías. ¡Si te quedas sin picos, combina un hueso con una roca!');
INSERT INTO `quest_text` VALUES ('198','en','Master of the Giant Lake','Hunt the Plesioth','Master Shipwright','Hunt down the water wyvern that keeps harassing my shipyard! Your target is a monster that can shoot water with incredible force, so beware! Heh heh heh!');
INSERT INTO `quest_text` VALUES ('198','es','Maestro del lago gigante','Caza al Plesioth','Maestro astillero','¡Caza al Wyvern de agua que está atacando mi astillero! Tu objetivo es un monstruo que lanza agua con una fuerza increíble, así que ten cuidado. ¡Je je je!');
INSERT INTO `quest_text` VALUES ('199','en','The Pink Fur Party','Slay 20 Congas','Curly Haired Girl','A huge group of Congas, along with one of their big pink bosses are gathering together. Please get rid of 20 of them... I think it will drive the rest away! Help me, pretty please!');
INSERT INTO `quest_text` VALUES ('199','es','Fiesta de las pieles rosas','Mata a 20 Conga','Chica de pelo rizado','Se está formando un gran grupo de Conga en torno a uno de sus inmensos jefes rosas. Acaba con 20 de ellos... ¡Creo que eso ahuyentará al resto! ¡Ayúdame, te lo ruego!');
INSERT INTO `quest_text` VALUES ('200','en','The Hidden Jungle Clouds','Slay 50 Hornetaurs','Pale Boy','I thought dark clouds had covered the moon, but it was actually a swarm of Hornetaurs! The jungle is covered with the bugs and I need you to exterminate 50 of the Hornetaur pests!');
INSERT INTO `quest_text` VALUES ('200','es','Las nubes de la jungla','Mata a 50 Hornetaurs','Chico pálido','Pensaba que la luna estaba cubierta por nubes oscuras, pero era un enjambre de Hornetaur. ¡La jungla está llena de esos bichos! ¡Necesito que extermines a 50 Hornetaur!');
INSERT INTO `quest_text` VALUES ('201','en','The Underwater Terror','Hunt the Green Plesioth','The Old Misanthrope','The lake underneath the desert is connected to an underground river and patrolled by a green-scaled water wyvern... If you are truly a hunter, then it should pose no problem.');
INSERT INTO `quest_text` VALUES ('201','es','El terror submarino','Caza al Plesioth verde','El viejo misántropo','El lago que hay bajo el desierto está conectado a un río subterráneo por el que patrulla un Wyvern de agua de escamas verdes... Si de verdad eres un cazador, no será problema para ti.');
INSERT INTO `quest_text` VALUES ('202','en','Evening Hermitaur Sonata','Slay 20 Hermitaurs','Merchant Envoy','Those pesky Hermitaurs are starting to get in the way of business. They hide in the sand and ambush you at a moment''s notice. I also spotted a Daimyo Hermitaur, so be extremely careful!');
INSERT INTO `quest_text` VALUES ('202','es','Sonata del Hermitaur','Mata a 20 Hermitaur','Enviado del mercader','Esos Hermitaur están empezando a molestar bastante. Se ocultan en la arena y te atacan sin que te des cuenta. ¡He visto un Daimyo Hermitaur, así que ten mucho cuidado!');
INSERT INTO `quest_text` VALUES ('203','en','The Purple Poison Menace','Hunt the Purple Gypceros','Guarded Merchant','I saw a gigantic bird-like monster deep in the swamp! It scared everyone so bad that I can''t do business with a thing like that out there! Please hunt it down so I can work in peace!');
INSERT INTO `quest_text` VALUES ('203','es','La amenaza del veneno morado','Caza al Gypceros morado','Mercader protegido','¡He visto un monstruo con forma de pájaro en el pantano! Ha asustado tanto a la gente que no puedo comerciar con esa cosa por ahí suelta. ¡Cázalo para que pueda trabajar en paz!');
INSERT INTO `quest_text` VALUES ('204','en','Pincer through the Sky','Hunt the Shogun Ceanataur','Furious Merchant','A Shogun Ceanataur is running rampant over the swamp zone! Whether it be human or animal, it is attacking everything in sight. Head to the swamp and end its reign of terror!');
INSERT INTO `quest_text` VALUES ('204','es','Pinzas en el cielo','Caza al Shogun Ceanataur','Mercader furioso','¡Un Shogun Ceanataur está causando estragos en la zona pantanosa! Ataca a todo lo que se le pone por delante, ya sea humano o animal. ¡Ve al pantano y acaba con su reinado de terror!');
INSERT INTO `quest_text` VALUES ('205','en','Chase the Poison Gypceros!','Hunt the Gypceros','The Gem Hunter','The Gypceros is known to have a fondness for shiny objects. It is also known to occasionally steal ore from humans. Slaying a Gypceros may net you some great treasures.');
INSERT INTO `quest_text` VALUES ('205','es','¡Sigue al Gypceros venenoso!','Caza al Gypceros','El buscador de gemas','Se sabe que al Gypceros le encantan los objetos brillantes. También se sabe que de vez en cuando roba minerales a los humanos. Caza a un Gypceros para obtener grandes tesoros.');
INSERT INTO `quest_text` VALUES ('206','en','Trouble in the Forest','Slay 20 Bullfangos','Lumberjack','I''m a lumberjack and I''m not OK. Those boar-monsters, the Bullfangos, have been a lot of trouble lately. Can you thin the herd by 20? Much obliged.');
INSERT INTO `quest_text` VALUES ('206','es','Problemas en el bosque','Mata a 20 Bullfango','Leñador','Soy leñador y esto no va bien. Esos monstruos cerdos, los Bullfango, me causan muchos problemas. ¿Puedes matar a 20 de la manada? Muchas gracias.');
INSERT INTO `quest_text` VALUES ('207','en','Seeking the Strange Mask','Slay 10 Shakalakas','Princess''s Attendant','This is awful! The princess saw some strange masked monsters that made her run for the hills! We''re sending troops on a hunt for the fiends, so track down the masked marauders!');
INSERT INTO `quest_text` VALUES ('207','es','En busca de la máscara','Mata a 10 Shakalaka','Ayuda de cámara','¡Es espantoso! ¡La princesa vio unos extraños monstruos enmascarados que huyeron a las colinas! Hemos enviado tropas para matarlos, ¡así que encuentra a esos intrusos enmascarados!');
INSERT INTO `quest_text` VALUES ('208','en','The Ioprey Leader','Hunt the Iodrome','Hardened Mercenary','We were just in a fight with a pack of Ioprey, but were routed and had to retreat before we could defeat their leader. Hunt it down for us, but beware of its poison attacks.');
INSERT INTO `quest_text` VALUES ('208','es','El líder de los Ioprey','Caza al Iodrome','Mercenario curtido','Estábamos luchando contra una manada de Ioprey, pero cambiaron de dirección y tuvimos que retirarnos antes de derrotar a su líder. ¡Cázalo, pero ten cuidado con sus ataques venenosos!');
INSERT INTO `quest_text` VALUES ('209','en','Commander in the Flames','Hunt the Shogun Ceanataur','Chief Weapon smith','Upon our trip into the cave at the volcano, an enormous Shogun Ceanataur dropped down from the ceiling right on top of us! Its ambush caused massive damage! Rid the world of that scourge!');
INSERT INTO `quest_text` VALUES ('209','es','Comandante en llamas','Caza al Shogun Ceanataur','Jefe herrero armas','Cuando estábamos en la cueva del volcán, un Shogun Ceanataur inmenso se lanzó directamente encima de nosotros. ¡Su emboscada ha hecho mucho daño! ¡Libra al mundo de ese azote!');
INSERT INTO `quest_text` VALUES ('210','en','Basarios: Unseen Peril','Hunt the Basarios','Survivor','A wyvern attacked my team from out of the blue while we were on an expedition to the Volcanic Belt. Where did it come from? Please slay it!');
INSERT INTO `quest_text` VALUES ('210','es','Basarios: peligro oculto','Caza al Basarios','Superviviente','Un Wyvern ha atacado a mi equipo de repente mientras estábamos en una expedición en la región volcánica. ¿De dónde salió? ¡Por favor, mátalo!');
INSERT INTO `quest_text` VALUES ('211','en','A Band of Ceanataurs','Slay 20 Ceanataurs','Digging Fanatic','I wanted to keep digging in search of the ultimate treasure trove... But some Ceanataurs smashed my Pickaxe! If you don''t get rid of them, there will be no digging for me! Help me!');
INSERT INTO `quest_text` VALUES ('211','es','Banda de Ceanataur','Mata a 20 Ceanataur','Fanático excavación','Estaba cavando en busca de un gran tesoro, cuando un Ceanataur se cargó mi pico. ¡Si no te deshaces de ellos, no podré volver a picar en toda mi vida! ¡Ayúdame!');
INSERT INTO `quest_text` VALUES ('212','en','Great Ore Discovery','Deliver 20 pcs of Coal','Famed Ore Merchant','In a corner of the volcanic belt, I discovered a great vein of coal in the rocks. I''d like you to mine the coal, but beware the Shogun Ceanataur! Take care and get mining!');
INSERT INTO `quest_text` VALUES ('212','es','Descubrimiento de minerales','Entrega 20 trozos de carbón','Mercader minerales','En una esquina de la región volcánica, descubrí una veta de carbón en las rocas. Me gustaría que lo extrajeras, pero ten cuidado con el Shogun Ceanataur. ¡Ten cuidado y a la mina!');
INSERT INTO `quest_text` VALUES ('213','en','A Giant Dragon Invades!','Defend the Fortress from Lao-Shan Lung','Loyal Minister','A giant dragon has attacked our fort! If the fort falls, so too do our lands! Use its installed weaponry to make this beast pay for its indiscretions!');
INSERT INTO `quest_text` VALUES ('213','es','Invasión del dragón gigante','Defiende la fortaleza del Lao-Shang Lung','Ministro leal','Un dragón gigante ha atacado nuestro fuerte. ¡Si cae ese bastión, también caerán nuestras tierras! Usa las armas del fuerte para que esa bestia pague por su indiscreción.');
INSERT INTO `quest_text` VALUES ('214','en','The Meeting of Daimyo','Survive until Time Over or Deliver the Paw Pass Ticket','Tanned Fisherman','Help! There has been an explosion of so many Daimyo Hermitaurs near our fishing grounds that we can''t handle things by ourselves! Get rid of as many as you can so we can get back to fishing!');
INSERT INTO `quest_text` VALUES ('214','es','La reunión de Daimyo','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Pescador moreno','¡Ayuda! Han aparecido tantos Daimyo Hermitaur cerca de nuestra zona de pesca que no podemos acabar con ellos nosotros solos. ¡Deshazte de todos los que puedas para que podamos volver a pescar!');
INSERT INTO `quest_text` VALUES ('215','en','Go Fish Goldenfish!','Deliver 8 Goldenfish','Foreign Peddler','I''ve come from across the sands to sell all manners of strange and unusual wares, but I have a request. Please deliver to me 8 Goldenfish from the desert. I promise to reward you well!');
INSERT INTO `quest_text` VALUES ('215','es','¡A pescar Peces dorados!','Entrega 8 Peces dorados','Vend amb extranjero','He venido cruzando las arenas para vender todo tipo de artículos extraños y especiales, pero tengo una solicitud. Entrégame 8 Peces dorados del desierto. ¡Prometo recompensarte bien!');
INSERT INTO `quest_text` VALUES ('216','en','Absolute Power','Hunt the Tigrex','Guild Master','At last, the Tigrex has appeared! It is said the beast''s origins are as a flying wyvern. It is too powerful to be allowed to run free. The village is in danger! Hunt it quickly!');
INSERT INTO `quest_text` VALUES ('216','es','Poder absoluto','Caza al Tigrex','Maestro del Gremio','¡Por fin ha aparecido el Tigrex! Se dice que es el ancestro de los Wyverns voladores. Es demasiado fuerte para dejarlo en libertad. ¡La aldea está en peligro! ¡Cázalo enseguida!');
INSERT INTO `quest_text` VALUES ('217','en','The Tigrex''s Roar','Hunt the Tigrex','Guild Messenger','I have an urgent request from a hunter on an expedition in the desert! It seems he has encountered the mighty Tigrex! Go to his aid and crush this beast at once!');
INSERT INTO `quest_text` VALUES ('217','es','El rugido del Tigrex','Caza al Tigrex','Mensajero del Gremio','He recibido una petición urgente de un cazador que está de expedición en el desierto. ¡Ha encontrado al poderoso Tigrex! ¡Ve en su ayuda y caza a esa bestia de una vez por todas!');
INSERT INTO `quest_text` VALUES ('218','en','The Runaway Diablos','Hunt the Diablos','Border Captain','A giant wyvern smashed the border-wall and ran into this area. We need to find and kill it before it causes any more trouble!');
INSERT INTO `quest_text` VALUES ('218','es','El Diablos huido','Caza al Diablos','Capitán de frontera','Un Wyvern gigante rompió el muro fronterizo y se coló en esta zona. ¡Hay que buscarlo y cazarlo antes de que cause más problemas!');
INSERT INTO `quest_text` VALUES ('219','en','The Fierce Black Horn','Hunt the Black Diablos','Failed Millionaire','I had hired the most skilled hunters imaginable, and went on a safari for the famed Diablos... But what we found was no mere Diablos! We must slay that black horned wyvern! No matter what!');
INSERT INTO `quest_text` VALUES ('219','es','El fiero cuerno negro','Caza al Diablos negro','Millonario fracasado','Había contratado a los mejores cazadores, quienes partieron en busca del famoso Diablos. ¡Pero eso no era un simple Diablos! Hay que cazar a ese Wyvern negro con cuernos. ¡Como sea!');
INSERT INTO `quest_text` VALUES ('220','en','Valor in the Swamp Zone','Hunt the Gravios','Swamp Townsman','Even in the relative calm of the swamp zone, something has stirred up the monsters. In particular, heavily armored wyverns have been attacking us. Can you help us out?');
INSERT INTO `quest_text` VALUES ('220','es','¡Valor en el pantano!','Caza al Gravios','Ciudadano pantano','En la relativa calma del pantano, algo ha despertado a los monstruos. En concreto, nos han atacado Wyverns con fuertes conchas. ¿Podrías ayudarnos?');
INSERT INTO `quest_text` VALUES ('221','en','Terror of the Gravios','Hunt the Black Gravios','Troubled Noble','A fearsome Gravios has appeared amidst the magma and desolation of the Volcanic Belt. Hunt down the fire breather for us!');
INSERT INTO `quest_text` VALUES ('221','es','Terror del Gravios','Caza al Gravios negro','Noble preocupado','Ha aparecido un Gravios terrible en medio del magma y la desolación de la región volcánica. ¡Caza a ese escupefuego por nosotros!');
INSERT INTO `quest_text` VALUES ('222','en','The King''s Domain','Hunt the Rathalos','Brave Boys','Did you hear it!? That voice that shook the ground? It even scared the fearless mercenaries! It must have been the king of the skies! But if you''re a real hunter, it won''t be a problem!');
INSERT INTO `quest_text` VALUES ('222','es','El dominio del rey','Caza al Rathalos','Chicos valientes','¿¡Lo has oído!? ¿Esa voz que ha hecho temblar el suelo? ¡Ha asustado hasta a los valientes mercenarios! ¡Debe de ser el rey de los cielos! ¡Pero si de verdad eres un cazador, no hay problema!');
INSERT INTO `quest_text` VALUES ('223','en','Attack of the Rathalos','Hunt the Azure Rathalos','Proud Soldier','It cannot be... We tried so hard to kill it... But... My entire war band was wiped out by a wyvern. Now it all rests upon your shoulders, monster hunter! Slay it!');
INSERT INTO `quest_text` VALUES ('223','es','Ataque del Rathalos','Caza al Rathalos celeste','Soldado orgulloso','No puede ser... Intentamos matarlo... Pero... Ese Wyvern acabó con todo mi batallón. ¡Ahora todo depende de ti, cazador de monstruos! ¡Mátalo!');
INSERT INTO `quest_text` VALUES ('224','en','The Queen''s Descent','Hunt the Rathian','Nomadic Botanist','A Rathian is making its nest in the jungle. This protective mother has made even stepping into the jungle a death sentence. Please clear the jungle of her threat.');
INSERT INTO `quest_text` VALUES ('224','es','El descenso de la reina','Caza la Rathian','Botánico nómada','Una Rathian está construyendo su nido en la jungla. Ahora el mero hecho de entrar en la jungla es una sentencia a muerte. Por favor, libra a la jungla de su amenaza.');
INSERT INTO `quest_text` VALUES ('225','en','The Cherry Blossom Rathian','Hunt the Pink Rathian','Sharp Eyed Count','A remarkably fierce Pink Rathian has rampaged through lands held by other monsters and caused a great upheaval. You must hunt down and eliminate her to restore order!');
INSERT INTO `quest_text` VALUES ('225','es','La Rathian de color cereza','Caza la Rathian rosa','Conde Buenavista','Una Rathian enormemente feroz ha arrasado estas tierras junto a otros monstruos y ha causado una gran consternación. ¡Debes cazarla y eliminarla para restablecer el orden!');
INSERT INTO `quest_text` VALUES ('226','en','The Legendary Kirin','Slay the Kirin','Mountain Explorer','That must have been the phantom beast... The faint glow, and how it seemed to glide over land... There''s no doubt that amazing riches await its slayer!');
INSERT INTO `quest_text` VALUES ('226','es','El legendario Kirin','Mata al Kirin','Montañero','Ha debido de ser la bestia fantasma... Ese brillo y el modo en que parecía deslizarse... ¡Sin duda habrá una gran recompensa para quien la mate!');
INSERT INTO `quest_text` VALUES ('227','en','The Red and Green Wyverns','Hunt the Rathalos and Rathian','Braided Maiden','I must gather Herbs from the hillside if I am to cure my mother''s illness. However, a fire breathing wyvern has settled into the area... If I do nothing, mama will only get worse. Please! Help me!');
INSERT INTO `quest_text` VALUES ('227','es','Los Wyvern rojos y verdes','Da caza al Rathalos y la Rathian','Doncella con trenzas','Tengo que recoger hierbas de la ladera de la colina para curar a mi madre. Pero en la zona se ha instalado un Wyvern escupefuego... Si no hago nada, mamá empeorará. ¡Ayúdame!');
INSERT INTO `quest_text` VALUES ('228','en','Attack of the Wind Dragon','Slay the Kushala Daora','Guild Master','A brown metal dragon is rapidly closing on the town. Scouts report that outlying areas have already been razed. If we don''t stop this dragon, our town will be annihilated! We need you!');
INSERT INTO `quest_text` VALUES ('228','es','Ataque del dragón del viento','Mata al Kushala Daora','Maestro del Gremio','Se está aproximando a la ciudad un dragón de metal. Los exploradores dicen que ya ha arrasado las zonas periféricas. ¡Si no lo detenemos, nuestra ciudad será aniquilada! ¡Ayúdanos!');
INSERT INTO `quest_text` VALUES ('229','en','A Sun with Fangs','Slay the Teostra','Wyverian Pioneer','While in the secluded desert village, I spotted an elder dragon with red scales! While I do know some hunters, it would be wrong to make this request of them... So it''s up to you!');
INSERT INTO `quest_text` VALUES ('229','es','Un Sol con colmillos','Mata al Teostra','Pionero Wyverian','Cuando estuve en la aldea del desierto, vi a un viejo dragón de escamas rojas. Aunque conozco a algunos cazadores, no estaría bien pedírselo a ellos... ¡Así que es cosa tuya!');
INSERT INTO `quest_text` VALUES ('230','en','Emperor of Flame','Slay the Teostra','Heroic General','I have an earnest request of you... As the last of my responsibilities, I request your help. I want you to fight the elder fire dragon we cornered in the Volcanic Belt, but beware its flames!');
INSERT INTO `quest_text` VALUES ('230','es','Emperador de las llamas','Mata al Teostra','General heroico','Tengo una importante tarea para ti... Como último trabajo, solicito tu ayuda. Necesito que luches contra el viejo dragón de fuego que acorralamos en la región volcánica. ¡Ten cuidado!');
INSERT INTO `quest_text` VALUES ('231','en','The Elder Dragon of Mist','Slay the Chameleos','Injured Hero','Our intuition told us to turn around, but we thought no one was there... Yet even though no one should''ve been there, we were attacked from behind! Beware! It was an enemy never before seen!');
INSERT INTO `quest_text` VALUES ('231','es','Anciano dragón de la niebla','Mata al Chameleos','Héroe herido','Nuestra intuición nos decía que regresáramos, pero pensábamos que allí no había nadie. Y aunque debería haber sido cierto, nos atacaron. ¡Cuidado! ¡Jamás se vio un enemigo igual!');
INSERT INTO `quest_text` VALUES ('232','en','Towards the Silence','Slay the Chameleos','Grim Aristocrat','It seems an unknown elder dragon has appeared in the swamp zone. However, no one truly got a clear look at it. What could the beast have been? Slay it, but proceed with caution!');
INSERT INTO `quest_text` VALUES ('232','es','Hacia el silencio','Mata al Chameleos','Aristócr. siniestro','Parece que en la zona del pantano ha aparecido un viejo dragón. Sin embargo, nadie lo ha visto bien del todo. ¿Qué será esa bestia? ¡Mátala, pero ve con cuidado!');
INSERT INTO `quest_text` VALUES ('233','en','The Approaching Gaoren','Defend the Fortress from Shen Gaoren','Guild Master','Hmm... This is quite serious. The fort which lies at the heart of our defenses is under siege by a giant monster. We need your strength to hold our position!');
INSERT INTO `quest_text` VALUES ('233','es','El Gaoren se aproxima','Defiende la fortaleza de Shen Gaoren','Maestro del Gremio','Umm... Esto es serio. Un Wyvern gigante está asediando el fuerte que se encuentra en el corazón de nuestras defensas. ¡Necesitamos tu fuerza para resistir el ataque!');
INSERT INTO `quest_text` VALUES ('234','en','Two Little Shadows','Hunt 2 Khezu','Old Geologist','I was exploring the caverns with my assistants when two small, white shadows popped out of nowhere. Please do something about them as they are hindering my research! ...Actually, what are they??');
INSERT INTO `quest_text` VALUES ('234','es','Dos pequeñas sombras','Caza 2 Khezu','Viejo geólogo','Estaba explorando las cavernas con mis ayudantes cuando dos pequeñas sombras blancas salieron de no sé dónde. ¡Haz algo, perjudican mi investigación! ¿Qué son, en realidad?');
INSERT INTO `quest_text` VALUES ('235','en','A Horde of Congalalas','Survive until Time Over or Deliver the Paw Pass Ticket','Swamp Townsman','Large Congalalas continue to gather, and at this rate, they''ll completely trash the Swamp and affect our town''s way of life. I''m not asking that you get rid of them all, but even 2 would help!');
INSERT INTO `quest_text` VALUES ('235','es','Una horda de Congalalas','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Ciudadano pantano','Continúan reuniéndose grandes Congalalas. A este ritmo arrasarán por completo el pantano y afectarán a nuestra forma de vida. No te pido que te libres de todos ellos, con 2 bastaría.');
INSERT INTO `quest_text` VALUES ('236','en','Gathering - Snowy Mountains','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A nighttime gathering quest in the snowy mountains. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Be careful! Large monsters lurk nearby!');
INSERT INTO `quest_text` VALUES ('236','es','Recogida: montañas nevadas','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida nocturna en las montañas nevadas. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar. ¡Ten cuidado! ¡Hay monstruos cerca!');
INSERT INTO `quest_text` VALUES ('237','en','Gathering - Jungle Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A nighttime gathering quest in the jungle. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Be careful! Large monsters lurk nearby!');
INSERT INTO `quest_text` VALUES ('237','es','Recogida – Zona de jungla','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida nocturna en la jungla. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar. ¡Ten cuidado! ¡Hay monstruos cerca!');
INSERT INTO `quest_text` VALUES ('238','en','Gathering - Desert Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A nighttime gathering quest in the desert. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Be careful! Large monsters lurk nearby!');
INSERT INTO `quest_text` VALUES ('238','es','Recogida – Zona desértica','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida nocturna en el desierto. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar. ¡Ten cuidado! ¡Hay monstruos cerca!');
INSERT INTO `quest_text` VALUES ('239','en','A True Foe - The Giadrome!','Hunt the Giadrome','Spirited Boy','Within a group of the sly carnivorous Giaprey, there is a leader. They call it the Giadrome. I need a hunter''s strength to show that pack of beasts and their leader who''s boss!');
INSERT INTO `quest_text` VALUES ('239','es','Todo un enemigo: el Giadrome','Caza al Giadrome','Chico alegre','En los grupos de astutos Giaprey carnívoros, hay un líder. Le llaman el Giadrome. ¡Necesito la fuerza de un cazador para demostrarles a esas bestias y su líder quién manda aquí!');
INSERT INTO `quest_text` VALUES ('240','en','Reckless Bulldrome Hunter','Hunt the Bulldrome','Troubled Father','My son decided to become a hunter and ran off after a Bulldrome on his own! Of course, now the tables have turned and I''m worried! Hunt down the Bulldrome on the snowy mountains!');
INSERT INTO `quest_text` VALUES ('240','es','Cazador de Bulldrome','Caza al Bulldrome','Padre preocupado','¡Mi hijo decidió ser cazador y se fue él solo tras un Bulldrome! Ya ha pasado un tiempo y estoy bastante preocupado. ¡Caza al Bulldrome en las montañas nevadas!');
INSERT INTO `quest_text` VALUES ('241','en','Flanked by Velocidrome','Hunt 2 Velocidrome','Village Children','All the children in the village have gathered their allowances to pay you to get rid of two carnivores. Our parents couldn''t do it, so it''s up to you to defend our fields and animals!');
INSERT INTO `quest_text` VALUES ('241','es','Rodeado de Velocidrome','Caza 2 Velocidromes','Niños de la aldea','Los niños de la aldea han juntado todo su dinero para pagarte para que te caces a 2 carnívoros. Nuestros padres no pudieron. ¡Tú eres el único que puede defender nuestros campos y animales!');
INSERT INTO `quest_text` VALUES ('242','en','Aim for the Jungle Crab','Hunt the Daimyo Hermitaur','Uncomfortable Butler','I''ve always longed to go hunting in the jungle! However, if a huge monster appeared, I''d be finished! Maybe you could take out the Daimyo Hermitaur for me?');
INSERT INTO `quest_text` VALUES ('242','es','El cangrejo de la jungla','Caza al Daimyo Hermitaur','Mayord. indispuesto','¡Siempre deseé ir de caza a la jungla! ¡Pero si aparece un monstruo enorme, estoy acabado! Quizá tú podrías cazar al Daimyo Hermitaur por mí...');
INSERT INTO `quest_text` VALUES ('243','en','The Poison Fanged Duo','Hunt 2 Gendrome','Desert Lover','There appears to be two Gendrome among the pack of Genprey ravaging the desert. This has caused the Genprey to become frenzied and attack humans. You must get rid of the leaders!');
INSERT INTO `quest_text` VALUES ('243','es','Dúo de colmillos venenosos','Caza 2 Gendrome','Amante del desierto','Parece que hay dos Gendrome entre la manada de Genprey que están arrasando el desierto. Por eso los Genprey están tan nerviosos y atacan a los humanos. ¡Hay que cazar a los líderes!');
INSERT INTO `quest_text` VALUES ('244','en','Pursuit of the Sand Wyvern','Hunt the Cephadrome','Desert Millionaire','A giant sand wyvern has appeared in the desert along with a pack of Genprey. Forget about the Genprey, but take care of the Cephadrome so the merchants can return to work!');
INSERT INTO `quest_text` VALUES ('244','es','Búsqueda del Wyvern de arena','Caza al Cephadrome','Millonario desierto','Ha aparecido un Wyvern de arena gigante en el desierto junto a una manada de Genprey. ¡Olvídate de los Genprey y ocúpate de los Cephadrome para que los mercaderes puedan trabajar!');
INSERT INTO `quest_text` VALUES ('245','en','Ultimate Crab Dinner','Hunt 2 Daimyo Hermitaurs','The Lady Gourmet','I am a true connoisseur of crab cuisine, and as such a connoisseur, I suspect the Daimyo Hermitaurs found in the desert are incredibly tasty! One is never enough, so hunt down two!');
INSERT INTO `quest_text` VALUES ('245','es','Última cena con cangrejo','Caza 2 Daimyo Hermitaur','La Señora Gourmet','Soy todo un experto en platos de cangrejo y, como tal, sospecho que el Daimyo Hermitaur del desierto es enormemente sabroso. ¡Con uno no basta, así que caza dos!');
INSERT INTO `quest_text` VALUES ('246','en','Trapped by Yian Kut-Ku','Hunt the Yian Kut-Ku and Blue Yian Kut-Ku','Beautiful Lady','The Yian Kut-Ku are circling, screaming in their shrill voices. Everyone is trapped inside the town! Please do something!');
INSERT INTO `quest_text` VALUES ('246','es','Asediados por Yian Kut-Ku','Caza al Yian Kut-Ku y al Yian Kut-Ku azul','Mujer hermosa','Los Yian Kut-Ku nos rodean y gritan con sus agudas voces. ¡Todo el mundo está atrapado en la ciudad! ¡Por favor, haz algo!');
INSERT INTO `quest_text` VALUES ('247','en','Conga Counterattack!','Hunt the Congalala','The Skinny Lord','I asked some hunters to slay a Congalala for me; however, they met defeat at the hooves of a Bulldrome. I didn''t think it would come to this, but I need your help!');
INSERT INTO `quest_text` VALUES ('247','es','¡Contraataque de Conga!','Caza al Congalala','El Señor flaco','Le pedí a unos cazadores que cazaran un Congalala por mí, pero acabaron bajo las pezuñas de un Bulldrome. No pensé que llegaría a esto, pero necesito tu ayuda.');
INSERT INTO `quest_text` VALUES ('248','en','The Beating of Royal Wings','Slay the Vespoid Queen','Jungle Researcher','It''s no use. No matter where I look, I can''t seem to find the Vespoid Queen! Perhaps if you slayed a large number of Vespoids to make her feel that her swarm was in grave danger, she might appear...');
INSERT INTO `quest_text` VALUES ('248','es','El batir de alas reales','Mata al Vespoid reina','Investigador jungla','No hay nada que hacer. ¡Da igual donde mire, no encuentro al Vespoid reina! Quizá aparezca si matas a muchos Vespoid y crea que los suyos están en grave peligro..');
INSERT INTO `quest_text` VALUES ('249','en','Gathering - Swamp Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A nighttime gathering quest in the swamp. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Be careful! Large monsters lurk nearby!');
INSERT INTO `quest_text` VALUES ('249','es','Recogida – Pantano','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida nocturna en el pantano. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar. ¡Ten cuidado! ¡Hay monstruos cerca!');
INSERT INTO `quest_text` VALUES ('250','en','Gathering - Forest and Hills','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A daytime gathering quest in the forest and hills. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Be careful! Large monsters lurk nearby!');
INSERT INTO `quest_text` VALUES ('250','es','Recogida – Bosque y colinas','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida diurna en el bosque y las colinas. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar. ¡Ten cuidado! ¡Hay monstruos cerca!');
INSERT INTO `quest_text` VALUES ('251','en','Gathering - Volcanic Zone','Survive until Time Over or Deliver the Paw Pass Ticket','Pokke Village Chief','A nighttime gathering quest in the volcanic zone. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Be careful! Large monsters lurk nearby!');
INSERT INTO `quest_text` VALUES ('251','es','Recogida – Zona volcánica','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe de aldea Pokke','Misión de recogida nocturna en la zona volcánica. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar. ¡Ten cuidado! ¡Hay monstruos cerca!');
INSERT INTO `quest_text` VALUES ('252','en','Two Roars in the Snow','Hunt 2 Blangongas','Alpine Survivor','It happened in an instant... Two Blangongas destroyed all the trees around my house. Now all I want to do is hunt them down so I can get my revenge. Please help me!');
INSERT INTO `quest_text` VALUES ('252','es','Dos rugidos en la nieve','Caza 2 Blangonga','Superviviente alpino','Sucedió en un instante... Dos Blangonga destruyeron todos los árboles alrededor de mi casa. Quiero cazarlos para poder vengarme de ellos. ¡Por favor, ayúdame!');
INSERT INTO `quest_text` VALUES ('253','en','The King of the Mountains','Hunt the Blangonga','Foothills Villager','A Blangonga has staked its claim to a piece of the snowy mountains. Now we can''t enter the area to gather firewood. Exterminate the Blangonga!');
INSERT INTO `quest_text` VALUES ('253','es','El rey de las montañas','Caza al Blangonga','Montañés','Un Blangonga ha reclamado su derecho a una parte de las montañas nevadas. Ya no podemos entrar en esa zona para buscar leña. ¡Extermina al Blangonga!');
INSERT INTO `quest_text` VALUES ('254','en','The Electrified Wyvern','Hunt the Khezu','Shocked Child','I wanted to test myself, so I went off in search of spotting a Bulldrome in the snowy mountains. But all of a sudden, a weird wyvern appeared and it shocked me! I''m still smoking!');
INSERT INTO `quest_text` VALUES ('254','es','El Wyvern eléctrico','Caza al Khezu','Niño espantado','Quería ponerme a prueba, así que fui en busca de un Bulldrome en las montañas nevadas. Pero, de repente, apareció un extraño Wyvern que me dejó pasmado. ¡Todavía me sale humo!');
INSERT INTO `quest_text` VALUES ('255','en','Red Shadow in the Swampland','Hunt the Red Khezu','Uncomfortable Butler','I''ve always longed to venture into the swamp! I think I could hunt down a Kelbi, but I could never fight a wyvern. Maybe you''d take care of this special monster for me...');
INSERT INTO `quest_text` VALUES ('255','es','Sombra roja en el pantano','Caza al Khezu rojo','Mayord. indispuesto','¡Siempre deseé aventurarme en el pantano! Creo que puedo cazar un Kelbi, pero jamás podría enfrentarme a un Wyvern. Quizá puedas ocuparte de este monstruo especial por mí...');
INSERT INTO `quest_text` VALUES ('256','en','The Poison Gas','Hunt the Gypceros and Purple Gypceros','Poisoned Soldier','*cough* While I was practicing in the jungle, I was attacked by two poison wyverns! You can see their thick poison gas before your very eyes... They are tough, please defeat them! *cough*');
INSERT INTO `quest_text` VALUES ('256','es','El gas venenoso','Caza al Gypceros y al Gypceros morado','Soldado envenenado','*tos* ¡Mientras estaba practicando en la jungla, me atacaron dos Wyverns venenosos! Puedes ver su gas venenoso delante de tus ojos... Son fuertes. ¡Cázalos! *tos*');
INSERT INTO `quest_text` VALUES ('257','en','Dual Plesioth','Hunt the Plesioth and Green Plesioth','Lovely Princess','The water wyvern known as Plesioth is raging in the jungle. And not just one of them! Head off immediately to slay them!');
INSERT INTO `quest_text` VALUES ('257','es','Plesioth doble','Caza al Plesioth y al Plesioth verde','Princesa encantadora','Hay varios Wyverns de agua llamados Plesioth enfurecidos en la jungla. ¡Ve allí inmediatamente para matarlos!');
INSERT INTO `quest_text` VALUES ('258','en','Attack of the Rathian','Hunt the Rathian','Caravan Leader','My caravan was wiped out by the queen of the skies, the killer Rathian! I''ll pay you whatever you ask if you hunt down that foul creature! Help me kind hunter, you''re my only hope!');
INSERT INTO `quest_text` VALUES ('258','es','Ataque de Rathian','Caza la Rathian','Líder de caravana','Mi caravana fue aniquilada por la reina de los cielos, una Rathian asesina. ¡Te pagaré lo que quieras si cazas a esa criatura! Ayúdame, amable cazador. ¡Eres mi última esperanza!');
INSERT INTO `quest_text` VALUES ('259','en','Water Wyvern in the Desert','Hunt the Plesioth','Proud Hunter','I found a giant water wyvern in a cave in the desert! I can''t defeat it because it stays underwater. Slay it for me and the glory is all yours!');
INSERT INTO `quest_text` VALUES ('259','es','Wyvern de agua en desierto','Caza al Plesioth','Cazador orgulloso','¡Encontré un Wyvern de agua gigante en una cueva del desierto! No puedo cazarlo porque está bajo el agua. ¡Mátalo por mí y la gloria será toda tuya!');
INSERT INTO `quest_text` VALUES ('260','en','The Underwater Terror','Hunt the Green Plesioth','The Old Misanthrope','The lake underneath the desert is connected to an underground river and patrolled by a green-scaled water wyvern... If you are truly a hunter, then it should pose no problem.');
INSERT INTO `quest_text` VALUES ('260','es','El terror submarino','Caza al Plesioth verde','El viejo misántropo','El lago que hay bajo el desierto está conectado a un río subterráneo por el que patrulla un Wyvern de agua de escamas verdes... Si de verdad eres un cazador, no será un problema para ti.');
INSERT INTO `quest_text` VALUES ('261','en','An Evening Soaked in Poison','Hunt the Iodrome','Mercenary Officer','The swamp''s poison is mixing with the Iodrome''s poison... It is a terrible scene! We need a professional hunter to assist us... Show us your skills!');
INSERT INTO `quest_text` VALUES ('261','es','Una tarde mojada en veneno','Caza al Iodrome','Oficial mercenario','El veneno del pantano se está mezclando con el del Iodrome. ¡Menuda escena! Necesitamos que nos ayude un cazador profesional... ¡Muéstranos tus habilidades!');
INSERT INTO `quest_text` VALUES ('262','en','Supreme Ruler of the Swamp','Hunt the Shogun Ceanataur','Scheming Strategist','Hunters! It is time to hunt down the Shogun Ceanataur. Let us rid the swamp zone of this menace and expand our strategic possibilities. This is a highly classified hunt. So don''t tell a soul!');
INSERT INTO `quest_text` VALUES ('262','es','El gran rey del pantano','Caza al Shogun Ceanataur','Estratega maquinador','¡Cazadores! Es hora de cazar al Shogun Ceanataur. Vamos a librar al pantano de esa amenaza y mejorar nuestra buena posición. Se trata de una caza de alto secreto. ¡Chitón!');
INSERT INTO `quest_text` VALUES ('263','en','The Purple Poison Menace','Hunt the Purple Gypceros','Guarded Merchant','I saw a gigantic bird-like monster deep in the swamp! It scared everyone so bad that I can''t do business with a thing like that out there! Please hunt it down so I can work in peace!');
INSERT INTO `quest_text` VALUES ('263','es','La amenaza del veneno morado','Caza al Gypceros morado','Mercader protegido','¡He visto un monstruo con forma de pájaro en el pantano! Ha asustado tanto a la gente que no puedo comerciar con esa cosa por ahí suelta. ¡Cázalo para que pueda trabajar en paz!');
INSERT INTO `quest_text` VALUES ('264','en','Eliminate the Rathalos!','Hunt the Rathalos','The Kindly Lord','I request the assistance of only the bravest of hunters to find and hunt the Rathalos that has appeared near here. Of course, a handsome reward will be paid upon success.');
INSERT INTO `quest_text` VALUES ('264','es','¡Caza al Rathalos!','Caza al Rathalos','El bondadoso señor','Solicito la ayuda de los cazadores más valientes para buscar y cazar al Rathalos que ha aparecido cerca de aquí. Obviamente, si lo consiguen, recibirán una buena recompensa.');
INSERT INTO `quest_text` VALUES ('265','en','The Shogun''s Encampment','Hunt 2 Shogun Ceanataurs','Hunter In Training','Hey! Hey! Have you heard the news!? There''s a rumor that two enormous monsters with thick shells have appeared in the Volcanic Belt! There must be a hunter somewhere who can face them!');
INSERT INTO `quest_text` VALUES ('265','es','El campamento de Shogun','Caza 2 Shogun Ceanataur','Cazador en prácticas','¡Eh! ¡Eh! ¿¡Has oído las noticias!? ¡Se dice que en la región volcánica han aparecido 2 enormes monstruos con conchas! ¡Debe de haber algún cazador que pueda enfrentarse a ellos!');
INSERT INTO `quest_text` VALUES ('266','en','Basarios: Unseen Peril','Hunt the Basarios','Survivor','A wyvern attacked my team from out of the blue while we were on an expedition to the Volcanic Belt. Where did it come from? Please slay it!');
INSERT INTO `quest_text` VALUES ('266','es','Basarios: peligro oculto','Caza al Basarios','Superviviente','Un Wyvern ha atacado a mi equipo de repente mientras estábamos en una expedición en la región volcánica. ¿De dónde salió? ¡Por favor, mátalo!');
INSERT INTO `quest_text` VALUES ('267','en','Envoy to Disaster','Slay 20 Remobras','Foreign Monk','The volcano has erupted with a deluge of black snake-like wyverns. They are the envoys to disaster. Hunt 20 of these Remobras down and appease the mountain gods.');
INSERT INTO `quest_text` VALUES ('267','es','Mensajero de la desgracia','Mata a 20 Remobra','Monje extranjero','Del volcán ha salido una marea de Wyverns negros en forma de serpiente. Son los mensajeros de la desgracia. Caza a 20 de estos Remobra para apaciguar a los dioses de la montaña.');
INSERT INTO `quest_text` VALUES ('268','en','Lao-Shan Lung Draws Near!','Defend the Fortress from Lao-Shan Lung','Guild Master','It seems that once again our land is in crisis. The giant elder dragon Lao-Shan Lung is approaching the village from the mountains. Head to the fort and defend our way of life!');
INSERT INTO `quest_text` VALUES ('268','es','¡Lao-Shan Lung se acerca!','Defiende la fortaleza del Lao-Shang Lung','Maestro del Gremio','Parece que nuestra tierra vuelve a estar en crisis. El viejo dragón gigante, Lao-Shan Lung, se aproxima a la aldea desde las montañas. Ve al fuerte y defiende nuestra forma de vida.');
INSERT INTO `quest_text` VALUES ('269','en','Meeting of the Blangongas','Survive until Time Over or Deliver the Paw Pass Ticket','Snow-Covered Boy','It-it-it''s awful! A group of Blangongas are gathering on the mountain! With all those brutes in one spot, it means trouble for the village! Please help us!');
INSERT INTO `quest_text` VALUES ('269','es','Reunión de los Blangonga','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Chico lleno de nieve','¡Es horrible! ¡Se está formando un grupo de Blangonga en la montaña! ¡Tantas bestias en un solo sitio, significa problemas! ¡Por favor, ayúdanos!');
INSERT INTO `quest_text` VALUES ('270','en','The White Brute','Slay the Kirin','King''s Surveyors','We came to this land seeking the fabled Kirin, and at last we had found it! But the heavens opened and lightning struck, scattering our team. We need your help to save our co-workers!');
INSERT INTO `quest_text` VALUES ('270','es','La bestia blanca','Mata al Kirin','Inspectores del rey','¡Vinimos a esta tierra en busca del famoso Kirin y por fin lo encontramos! Pero el cielo se abrió y cayó un rayó que dispersó a nuestro equipo. ¡Necesitamos tu ayuda para salvarlos!');
INSERT INTO `quest_text` VALUES ('271','en','Pricy Mushrooms, Shaka!','Deliver 3 Select Mushrooms','Shifty Merchant','Have you ever heard of "Select Mushrooms"? Collect just 3 of them and you''ll be rich beyond belief! Although I have heard that the King Shakalaka keeps a tight watch over those things...');
INSERT INTO `quest_text` VALUES ('271','es','¡Una setas caras, Shaka!','Entrega 3 setas selectas','Mercader sospechoso','¿Has oído hablar de las "Setas selectas"? ¡Recoge 3 y serás más rico de lo que puedas imaginar! Aunque he oído que el King Shakalaka las vigila muy de cerca...');
INSERT INTO `quest_text` VALUES ('272','en','The Big Dirt Nap','Hunt the Hypnocatrice','Shifty Merchant','The Hypnocatrice, the sleep-inducing bird wyvern of the Great Forest. Those who face it usually end up taking a dirt nap, so its materials are highly coveted. So... You gonna give it a shot?');
INSERT INTO `quest_text` VALUES ('272','es','Criando malvas','Caza al Hypnocatrice','Mercader sospechoso','Hypnocatrice, el pájaro Wyvern inductor de sueño del Gran bosque. Los que se enfrentan a él acaban criando malvas, así que sus materiales son codiciados. ¿Quieres probar?');
INSERT INTO `quest_text` VALUES ('273','en','Twin Walls of the Jungle','Hunt all of the Large Monsters','Jungle Psychic','Oh, the atmosphere is abuzz, and the land tells me of the monsters'' fury! Great Hunter, I call upon you to put a stop to the Blue Yian Kut-Ku and the Rathian that appears after it falls!');
INSERT INTO `quest_text` VALUES ('273','es','Muros gemelos de la jungla','Caza todos los monstruos grandes','Vidente de jungla','Oh, la atmósfera está agitada, ¡y la tierra me habla de la furia de los monstruos! Gran cazador, ¡te convoco para que detengas al Yian Kut-Ku azul y a la Rathian que traerán la calamidad!');
INSERT INTO `quest_text` VALUES ('274','en','The Meeting of Sea and Air','Hunt all of the Large Monsters','Desert Zone Chief','Oh me, oh my! A Daimyo Hermitaur and a Green Plesioth have both appeared in the same area. I''m in search of a hunter who''ll rid me of them one by one. Won''t anyone step forward?');
INSERT INTO `quest_text` VALUES ('274','es','Encuentro del mar y el aire','Caza todos los monstruos grandes','Jefe zona desierto','¡Pobre de mí! Un Daimyo Hermitaur y un Plesioth verde han aparecido en la misma zona. Busco un cazador que me libre de ellos, uno por uno. ¿Algún voluntario?');
INSERT INTO `quest_text` VALUES ('275','en','Red Lightning, Violet Blade','Hunt all of the Large Monsters','Swamp Envoy','A Khezu and a Shogun Ceanataur have descended upon the swampland and are really going at it! If we don''t put an end to them quick, we may end up with a lot of casualties! Heeeeelp!');
INSERT INTO `quest_text` VALUES ('275','es','Relámpago rojo, hoja violeta','Caza todos los monstruos grandes','Enviado pantano','Un Khezu y un Shogun Ceanataur han descendido sobre el pantano y se han puesto manos a la obra. Si no acabamos con ellos puede que acabemos con un montón de bajas. ¡Ayuuda!');
INSERT INTO `quest_text` VALUES ('276','en','Land of the Tremors','Hunt 2 Tigrex','Guild Master','A group of highly skilled hunters went off to slay two Tigrex, but they became the hunted. Please destroy the two Tigrex and open a clear route for our rescue team.');
INSERT INTO `quest_text` VALUES ('276','es','Tierra de los temblores','Caza 2 Tigrex','Maestro del Gremio','Un grupo de cazadores experimentados salió a cazar un Tigrex, pero los cazados fueron ellos. Caza a los dos Tigrex y abre un camino para nuestro equipo de rescate.');
INSERT INTO `quest_text` VALUES ('277','en','The Rajang in the Snow','Hunt the Rajang','Wounded Guard','I had never seen the fanged beast with two horns on its head before, and I never want to again with the way it was rampaging across the snow!');
INSERT INTO `quest_text` VALUES ('277','es','El Rajang en la nieve','Caza al Rajang','Guardia herido','¡Jamás había visto a esa bestia con colmillos y dos cuernos en la cabeza! ¡Y no quiero volver a verla jamás por la forma en que avanza por la nieve!');
INSERT INTO `quest_text` VALUES ('278','en','The Tigrex''s Roar','Hunt the Tigrex','Guild Messenger','I have an urgent request from a hunter on an expedition in the desert! It seems he has encountered the mighty Tigrex! Go to his aid and crush this beast at once!');
INSERT INTO `quest_text` VALUES ('278','es','El rugido del Tigrex','Caza al Tigrex','Mensajero del Gremio','He recibido una petición urgente de un cazador que está de expedición en el desierto. ¡Ha encontrado al poderoso Tigrex! ¡Ve en su ayuda y acaba con esa bestia de una vez por todas!');
INSERT INTO `quest_text` VALUES ('279','en','Pink Dance in the Jungle','Hunt the Pink Rathian','Uncomfortable Butler','I''ve always longed to be a hunter, but a meeting with a Rathian ended that! Now that I know what it takes, I''ll start over, but you have the spirit to hunt down that Rathian!');
INSERT INTO `quest_text` VALUES ('279','es','Danza rosa en la jungla','Caza la Rathian rosa','Mayord. indispuesto','¡Siempre deseé ser cazador, pero tras un encuentro con una Rathian, eso se acabó! ¡Ahora que sé lo que es, volveré a empezar, pero hay que tener valor para cazar a esa Rathian!');
INSERT INTO `quest_text` VALUES ('280','en','The Runaway Diablos','Hunt the Diablos','Border Captain','A giant wyvern smashed the border-wall and ran into this area. We need to find and kill it before it causes any more trouble!');
INSERT INTO `quest_text` VALUES ('280','es','El Diablos huido','Caza al Diablos','Capitán de frontera','Un Wyvern gigante rompió el muro fronterizo y se coló en esta zona. ¡Hay que buscarlo y cazarlo antes de que cause más problemas!');
INSERT INTO `quest_text` VALUES ('281','en','The Fierce Black Horn','Hunt the Black Diablos','Failed Millionaire','I had hired the most skilled hunters imaginable, and went on a safari for the famed Diablos... But what we found was no mere Diablos! We must slay that black horned wyvern! No matter what!');
INSERT INTO `quest_text` VALUES ('281','es','El fiero cuerno negro','Caza al Diablos negro','Millonario fracasado','Había contratado a los mejores cazadores, quienes partieron en busca del famoso Diablos. ¡Pero eso no era un simple Diablos! Hay que cazar a ese Wyvern negro con cuernos. ¡Como sea!');
INSERT INTO `quest_text` VALUES ('282','en','Four Horns','Hunt the Diablos and Black Diablos','Lovely Princess','I simply can''t bear to think about the terror and pain those Diablos are causing my people. I can''t sleep at night with that worry! Hunt down those 2 Diablos for me!');
INSERT INTO `quest_text` VALUES ('282','es','Cuatro cuernos','Caza al Diablos y al Diablos negro','Princesa encantadora','No puedo soportar pensar en el terror y el dolor que esos Diablos están causando a mi gente. ¡No duermo por la noche! ¡Caza a 20 de esos Diablos por mí!');
INSERT INTO `quest_text` VALUES ('283','en','Rajang of Mountain Flames','Hunt the Rajang','Selfish Princess','I went up to the snowy mountains to view the aurora, but the truth is that I hate the cold! That''s when it hit me! I should have a coat made from Rajang fur! Hunt one for me!');
INSERT INTO `quest_text` VALUES ('283','es','Rajang de llamas de montaña','Caza al Rajang','Princesa egoísta','¡Subí a las montañas nevadas para ver la aurora, pero la verdad es que odio el frío! ¡Fue entonces cuando me atacó! ¡Quiero un abrigo hecho de piel de Rajang! ¡Cázame uno!');
INSERT INTO `quest_text` VALUES ('284','en','Terror of the Gravios','Hunt the Gravios','Troubled Noble','A fearsome Gravios has appeared amidst the magma and desolation of the Volcanic Belt. Hunt down the fire breather for us!');
INSERT INTO `quest_text` VALUES ('284','es','Terror del Gravios','Caza al Gravios','Noble preocupado','Ha aparecido un Gravios terrible en medio del magma y la desolación de la región volcánica. ¡Caza a ese escupefuego por nosotros!');
INSERT INTO `quest_text` VALUES ('285','en','Black Rock in the Swamp','Hunt the Black Gravios','Swamp Townsman','Even in the relative calm of the swamp zone, something has stirred up the monsters. In particular, heavily armored wyverns have been attacking us. Can you help us out?');
INSERT INTO `quest_text` VALUES ('285','es','Roca negra en el pantano','Caza al Gravios negro','Ciudadano pantano','En la relativa calma de la zona pantanosa, algo ha despertado a los monstruos. En concreto, nos han atacado Wyverns con fuertes conchas. ¿Podrías ayudarnos?');
INSERT INTO `quest_text` VALUES ('286','en','A Troublesome Pair','Hunt the Rathalos and Rathian','Brave Prince','A Rathalos and Rathian have paired up and are ravaging my country! I wanted to end their reign of terror, but my father will not allow it! Please! Defeat them for me!');
INSERT INTO `quest_text` VALUES ('286','es','Una pareja problemática','Da caza al Rathalos y la Rathian','Príncipe valiente','¡Un Rathalos y un Rathian se han aliado y están arrasando mi país! ¡Quiero acabar con su reinado de terror, pero mi padre no me deja! ¡Por favor, véncelos por mí!');
INSERT INTO `quest_text` VALUES ('287','en','Blue Sky, Pink Earth','Hunt the Azure Rathalos and the Pink Rathian','Gambling Shopkeep','Did you see the two wyverns that appeared in the hills? An azure-shelled Rathalos and a pink-scaled Rathian... Hunting them down would surely make you a top hunter! ...Try your luck?');
INSERT INTO `quest_text` VALUES ('287','es','Cielo azul, tierra rosa','Caza al Rathalos celeste y a la Rathian rosa','Tendero jugador','¿Has visto los 2 Wyverns que aparecieron en las colinas? El Rathalos azul celeste y la Rathian de escamas rosas. ¡Si los cazas, no hay duda de que serás un cazador de primera! ¿Lo intentas?');
INSERT INTO `quest_text` VALUES ('288','en','Attack of the Rathalos','Hunt the Azure Rathalos','Proud Soldier','It cannot be... We tried so hard to kill it... But... My entire war band was wiped out by a wyvern. Now it all rests upon your shoulders, monster hunter! Slay it!');
INSERT INTO `quest_text` VALUES ('288','es','Ataque del Rathalos','Caza al Rathalos celeste','Soldado orgulloso','No puede ser... Intentamos matarlo... Pero... Ese Wyvern acabó con todo mi batallón. ¡Ahora todo depende de ti, cazador de monstruos! ¡Cázalo!');
INSERT INTO `quest_text` VALUES ('289','en','Deny the Silver Rathalos','Hunt the Silver Rathalos','Wyverian Maiden','I have a request to all excellent hunters. I would like you to hunt down the silver wyvern that lives in the forgotten tower. OK... You don''t even have to be excellent.');
INSERT INTO `quest_text` VALUES ('289','es','Detiene al Rathalos plateado','Caza al Rathalos plateado','Doncella Wyverian','Tengo una tarea para todos los buenos cazadores. Me gustaría que cazárais al Wyvern plateado que vive en la torre olvidada. Vale... No hace falta ser tan bueno.');
INSERT INTO `quest_text` VALUES ('290','en','Find the Golden Phantom','Hunt the Gold Rathian','Aloof Adventurer','All of my rations were gone and I was fading out of consciousness when out of the corner of my eye I saw ancient ruins and a golden wyvern up above. Was it all a dream? Find the truth!');
INSERT INTO `quest_text` VALUES ('290','es','Busca al fantasma dorado','Caza la Rathian dorada','Aventurero distante','Me quedé sin comida pero, cuando estaba a punto de caer inconsciente, por el rabillo del ojo vi unas antiguas ruinas y, encima, un Wyvern. ¿Habrá sido un sueño? ¡Busca la verdad!');
INSERT INTO `quest_text` VALUES ('291','en','The Fleeting Shadow','Slay 2 Kirin','Eccentric Old Man','I saw them! I really did! The ground was bathed in sparks as two phantom beasts bathed in a lava pool! It was not a dream! You''ve gotta believe me! Go see for yourself!');
INSERT INTO `quest_text` VALUES ('291','es','La sombra fugaz','Mata a 2 Kirin','Anciano excéntrico','¡Lo vi! ¡De verdad! ¡El suelo estaba lleno de chispas y 2 bestias fantasma se bañaban en lava! ¡No fue un sueño! ¡Tienes que creerme! ¡Ve a verlo tú mismo!');
INSERT INTO `quest_text` VALUES ('292','en','The Frozen Dictator','Slay the Kushala Daora','Fleeing Villager','I saw it! I saw it! In the middle of a blinding snow storm, there it was; dark black wings were dancing in the sky... No mere human could stand up to it! Don''t even think of hunting it!');
INSERT INTO `quest_text` VALUES ('292','es','El dictador glacial','Mata al Kushala Daora','Aldeano huidizo','¡Lo vi! ¡Lo vi! En medio de una tormenta de nieve, allí estaba; sus oscuras alas bailaban en el cielo... ¡Ningún humano podría compararse con él! ¡Y mucho menos matarlo!');
INSERT INTO `quest_text` VALUES ('293','en','The Elder Dragon of Wind','Slay the Kushala Daora','Jungle Psychic','There was surely a vortex inside of that downpour. The wind wrapped around and revealed the elder dragon, Kushala Daora! There isn''t a single soul who can combat it alone, so fight together!');
INSERT INTO `quest_text` VALUES ('293','es','Anciano dragón del viento','Mata al Kushala Daora','Vidente de jungla','Seguro que había un vórtice dentro de ese chubasco. ¡El viento que lo envolvía dejaba entrever al dragón anciano Kushala Daora! No hay una sola alma que lo iguale, ¡luchemos juntos!');
INSERT INTO `quest_text` VALUES ('294','en','The War of Immolation','Slay the Teostra','Guild Master','This is truly an emergency! A red fire-breathing dragon is approaching this very town! This is no time to dilly-dally! We need the help of every skilled hunter in this land!');
INSERT INTO `quest_text` VALUES ('294','es','La guerra de la inmolación','Mata al Teostra','Maestro del Gremio','¡Es una emergencia! Un dragón escupefuego rojo se aproxima a esta ciudad! ¡No es momento de entretenerse! ¡Necesitamos la ayuda de todos los cazadores!');
INSERT INTO `quest_text` VALUES ('295','en','Emperor of Flame','Slay the Teostra','Heroic General','I have an earnest request of you... As the last of my responsibilities, I request your help. I want you to fight the elder fire dragon we cornered in the Volcanic Belt, but beware its flames!');
INSERT INTO `quest_text` VALUES ('295','es','Emperador de las llamas','Mata al Teostra','General heroico','Tengo una importante tarea para ti... Solicito tu ayuda. Necesito que luches contra el viejo dragón de fuego que acorralamos en la región volcánica. ¡Ten cuidado!');
INSERT INTO `quest_text` VALUES ('296','en','The Elder Dragon of Mist','Slay the Chameleos','Injured Hero','Our intuition told us to turn around, but we thought no one was there... Yet even though no one should''ve been there, we were attacked from behind! Beware! It was an enemy never before seen!');
INSERT INTO `quest_text` VALUES ('296','es','Anciano dragón de la niebla','Mata al Chameleos','Héroe herido','Nuestra intuición nos decía que regresáramos, pero pensábamos que allí no había nadie. Y aunque debería haber sido cierto, nos atacaron. ¡Cuidado! ¡Jamás se ha visto enemigo igual!');
INSERT INTO `quest_text` VALUES ('297','en','Towards the Silence','Slay the Chameleos','Grim Aristocrat','It seems an unknown elder dragon has appeared in the swamp zone. However, no one truly got a clear look at it. What could the beast have been? Slay it, but proceed with caution!');
INSERT INTO `quest_text` VALUES ('297','es','Hacia el silencio','Mata al Chameleos','Aristócr, siniestro','Parece que en la zona del pantano ha aparecido un viejo dragón. Sin embargo, nadie lo ha visto bien del todo. ¿Qué será esa bestia? ¡Mátala, pero ve con cuidado!');
INSERT INTO `quest_text` VALUES ('298','en','Legendary Black Dragon','Slay the Fatalis','Benevolent Monarch','The legendary black dragon... It really exists then? We''ve prepared all instruments of war to assist you in your quest to destroy the dragon. The fate of the nation lies in your hands.');
INSERT INTO `quest_text` VALUES ('298','es','Dragón negro legendario','Mata a Fatalis','Monarca benevolente','El legendario dragón negro... ¿De verdad existe? Hemos preparado todas nuestras armas para ayudarte a destruir al dragón. El destino de la nación está en tus manos.');
INSERT INTO `quest_text` VALUES ('299','en','The End Times','Slay the Fatalis','Scarlet Mystery Man','It appears the time has finally come. The bloodstained scales of the red dragon have graced the earth again in flaming glory. If you can stop this beast...');
INSERT INTO `quest_text` VALUES ('299','es','El fin de los tiempos','Mata a Fatalis','Hombre mister. esc.','Parece que por fin ha llegado la hora. Las sangrientas escamas del dragón rojo han vuelto a honrar la tierra en su llameante gloria. Si detuvieras a la bestia...');
INSERT INTO `quest_text` VALUES ('300','en','The Approaching Gaoren','Defend the Town from Shen Gaoren','Guild Master','Our town is embroiled in an unprecedented conflict. A fortress-like shelled monster is threatening our safety. We need help immediately!');
INSERT INTO `quest_text` VALUES ('300','es','El Gaoren se aproxima','Defiende la ciudad del Shen Gaoren','Maestro del Gremio','Nuestra ciudad está en un conflicto sin precedentes. Un monstruo del tamaño de una fortaleza amenaza nuestra seguridad. ¡Que alguien nos ayude!');
INSERT INTO `quest_text` VALUES ('301','en','Rise to the Summit','Slay the Akantor','Guild Master','The combined strength of the Hunter''s Guild has successfully cornered an Akantor in the Volcanic Belt. Now all that is left is to slay the beast, a task for only the most valiant.');
INSERT INTO `quest_text` VALUES ('301','es','Ascenso a la cima','Mata al Akantor','Maestro del Gremio','La unión de la fuerza del Gremio de cazadores ha logrado acorralar a un Akantor en la región volcánica. Ahora sólo queda matar a la bestia, una tarea sólo para los más valientes.');
INSERT INTO `quest_text` VALUES ('302','en','Ancestral Dragon','Slay the Fatalis','Scarlet Mystery Man','Hee hee hee... The time has come. Here is your invitation to the ball. Wear your Sunday best and bring your greatest weapon, for it is time to go to the dance with the king of disaster.');
INSERT INTO `quest_text` VALUES ('302','es','Dragón ancestral','Mata al Fatalis','Hombre mister. esc.','Je, je, je... Ha llegado la hora. Aquí está tu invitación al baile. Ponte la ropa de domingo y trae el arma más grande que tengas, porque es hora de bailar con la reina de la fiesta.');
INSERT INTO `quest_text` VALUES ('303','en','Wyvern of the Wind','Hunt the Nargacuga','Wounded Hunter','The Nargacuga of the Great Forest... It''s so fast, I could barely see it. But please, if there is one request that needs to be fulfilled, it''s this one!');
INSERT INTO `quest_text` VALUES ('303','es','Wyvern del viento','Caza al Nargacuga','Cazador herido','El Nargacuga del Gran Bosque... Es tan rápido que apenas pude verlo. Por favor, si hay una solicitud que deba ser atendida, ¡es ésta!');
INSERT INTO `quest_text` VALUES ('304','en','Born of Darkness','Hunt the Nargacuga','Dazed Traveler','All of my friends... gone. I saw a tail swish through the air, and 2 red lights. That''s all. That thing''s not a monster; it''s a demon! Someone exorcise it, please!');
INSERT INTO `quest_text` VALUES ('304','es','Nacido de la oscuridad','Caza al Nargacuga','Viajante aturdido','Todos mis amigos... perdidos. Vi un coletazo en el aire y 2 luces rojas. Eso es todo. ¡Eso no es un monstruo, es un demonio! ¡Necesitamos un exorcista!');
INSERT INTO `quest_text` VALUES ('305','en','Two Queens','Hunt the Rathian and the Pink Rathian','Arena Manager','Think you can handle two Rathian at the same time!? Then come on down to the Arena, the only place to test your might! We eagerly await your arrival, Hunter!');
INSERT INTO `quest_text` VALUES ('305','es','Dos reinas','Caza la Rathian y la Rathian rosa','Jefe arena','¿¡Crees que puedes con dos Rathian a la vez!? Entonces ven a la Arena, ¡el único lugar donde puedes probar tu fuerza! ¡Esperamos con impaciencia tu llegada, cazador!');
INSERT INTO `quest_text` VALUES ('306','en','One-Horned Demon King','Hunt the Diablos','Wounded Hunter','Ah, I tried to slay it, but I was in way over my head. Still, I can''t let it go, so I ask that if you have the courage to face this beast, to please step forward.');
INSERT INTO `quest_text` VALUES ('306','es','El rey demonio unicornio','Caza al Diablos','Cazador herido','Ah, intenté matarlo, pero era demasiado para mí. ¡Mas no quiero dejar las cosas así! Te pido que, si tienes la valentía necesaria para enfrentarte a esta bestia, des un paso adelante.');
INSERT INTO `quest_text` VALUES ('307','en','Phantasmic Battle','Slay the Kirin','King''s Surveyors','I''ve received an urgent communique from my colleague who went to investigate deep inside the volcano. Please hurry, but be careful. The monster is a bit... unique.');
INSERT INTO `quest_text` VALUES ('307','es','Batalla fantasmal','Mata al Kirin','Inspectores del rey','He recibido un comunicado urgente de mi colega que fue a investigar las profundidades del volcán. Date prisa pero ten cuidado. El monstruo es algo... único.');
INSERT INTO `quest_text` VALUES ('308','en','Furious Beauties','Hunt all of the Large Monsters','Slashed L Cheek Hntr','Wh-What''s going on...? All of a sudden, a ton of monsters just showed up in the Snowy Mountains! Any hunter willing to lend a hand, please come help us on the hunt!');
INSERT INTO `quest_text` VALUES ('308','es','Bellezas feroces','Caza todos los monstruos grandes','Cazador cicatriz','¿Q-qué pasa...? De repente, han aparecido un montón de monstruos en las Montañas Nevadas. ¡Por favor, que vengan a ayudarnos en la caza todos los cazadores dispuestos a echar una mano!');
INSERT INTO `quest_text` VALUES ('309','en','Fight for the Throne','Hunt all of the Large Monsters','Maiden of Sorrows','Help! There are some dangerous monsters lurking in the Forest and Hills, making it impossible for me to enter the area. But if I don''t gather what I need, my mother''s illness will...');
INSERT INTO `quest_text` VALUES ('309','es','Lucha por el trono','Caza todos los monstruos grandes','Doncella del pesar','¡Ayuda! Hay monstruos peligrosos acechando en el Bosque y las Colinas, y me hacen imposible entrar en la zona. Pero, si no reúno lo que necesito, la enfermedad de mi madre...');
INSERT INTO `quest_text` VALUES ('310','en','Hotter than Hell Itself','Hunt all of the Large Monsters','Volcano Investi Team','We''ve received word that a Basarios and a Gravios are going wild inside due to volcanic activity. This is a very dire situation, and we require the immediate dispatch of a hunter.');
INSERT INTO `quest_text` VALUES ('310','es','Más caliente que el infierno','Caza todos los monstruos grandes','Eq. invest. volcanes','Nos han informado de que un Basarios y un Gravios se están poniendo furiosos por la actividad volcánica. Es una situación muy arriesgada, y necesitamos que se envíe inmediatamente un cazador.');
INSERT INTO `quest_text` VALUES ('311','en','Desert Unifier','Hunt all of the Large Monsters','Selfish Princess','My sister and I are in an argument over which is the most beautiful: Daimyo shells, Cephadrome scales, or Diablos horns. Seeing is believing, so I demand you bring all three to me!');
INSERT INTO `quest_text` VALUES ('311','es','Unificador del desierto','Caza todos los monstruos grandes','Princesa egoísta','Mi hermana y yo estamos discutiendo qué es más bonito: las conchas de Daimyo, las escamas de Cephadrome o los cuernos de Diablos. ¡Ver es creer, así que te pido que me traigas los tres!');
INSERT INTO `quest_text` VALUES ('312','en','G-Lvl Gathering - Grt Forest','Survive until Time Over or Deliver the Paw Pass Ticket','Guild Manager','A daytime gathering quest in the Great Forest. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Just be aware of the G-Level monsters, OK?');
INSERT INTO `quest_text` VALUES ('312','es','Reunión nv G - Gran bosque','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe del Gremio','Una misión de reunión diurna en el Gran bosque. Reúne todos los materiales que puedas en el campo y entrega el Ticket zarpa para terminar. Ten cuidado con los monstruos de nivel G, ¿vale?');
INSERT INTO `quest_text` VALUES ('313','en','G-Lvl Gathering - Old Jungle','Survive until Time Over or Deliver the Paw Pass Ticket','Guild Manager','A gathering quest in the Old Jungle. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Just be aware of the G-Level monsters, OK?');
INSERT INTO `quest_text` VALUES ('313','es','Reunión nv G - Vieja jungla','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe del Gremio','Una misión de reunión diurna en la Vieja jungla. Reúne todos los materiales que puedas en el campo y entrega el Ticket zarpa para terminar. Ten cuidado con los monstruos de nivel G, ¿vale?');
INSERT INTO `quest_text` VALUES ('314','en','G-Lvl Gathering - Old Desert','Survive until Time Over or Deliver the Paw Pass Ticket','Guild Manager','A gathering quest in the Old Desert. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Just be aware of the G-Level monsters, OK?');
INSERT INTO `quest_text` VALUES ('314','es','Reunión nv G- Viejo desierto','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe del Gremio','Una misión de reunión diurna en el Viejo desierto. Reúne todos los materiales que puedas en el campo y entrega el Ticket zarpa para terminar. Ten cuidado con los monstruos de nivel G, ¿vale?');
INSERT INTO `quest_text` VALUES ('315','en','G-Lvl Gathering - Old Swamp','Survive until Time Over or Deliver the Paw Pass Ticket','Guild Manager','A gathering quest in the Old Swamp. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Just be aware of the G-Level monsters, OK?');
INSERT INTO `quest_text` VALUES ('315','es','Reunión nv G - Viejo pantano','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe del Gremio','Una misión de reunión diurna en el Viejo pantano. Reúne todos los materiales que puedas en el campo y entrega el Ticket zarpa para terminar. Ten cuidado con los monstruos de nivel G, ¿vale?');
INSERT INTO `quest_text` VALUES ('316','en','G-Lvl Gathering - Snowy Mts.','Survive until Time Over or Deliver the Paw Pass Ticket','Guild Manager','A gathering quest in the Snowy Mountains. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Just be aware of the G-Level monsters, OK?');
INSERT INTO `quest_text` VALUES ('316','es','Reunión nv G - Montañas Nev.','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe del Gremio','Una misión de reunión diurna en las Montañas Nevadas. Reúne los materiales que puedas en el campo y entrega el Ticket zarpa para terminar. Ten cuidado con los monstruos de nivel G, ¿vale?');
INSERT INTO `quest_text` VALUES ('317','en','Shakalaka Showdown!','Slay 20 Shakalakas','Shifty Merchant','This time, I need a hunter to come with us as we go in search of treasure in the heart of the Great Forest. More specifically, I need you to be on the look-out for Shakalakas as we travel.');
INSERT INTO `quest_text` VALUES ('317','es','¡Confrontación Shakalaka!','Mata a 20 Shakalaka','Mercader sospechoso','Esta vez necesito un cazador que nos acompañe para ir en busca de un tesoro en el corazón del Gran bosque. Más específicamente, te necesito como oteador de Shakalaka mientras viajamos.');
INSERT INTO `quest_text` VALUES ('318','en','The Beating of Royal Wings','Slay the Vespoid Queen','Jungle Researcher','It''s no use. No matter where I look, I can''t seem to find the Vespoid Queen! Perhaps if you slayed a large number of Vespoids to make her feel that her swarm was in grave danger, she might appear...');
INSERT INTO `quest_text` VALUES ('318','es','El batir de alas reales','Mata al Vespoid reina','Investigador jungla','No hay nada que hacer. ¡Da igual donde mire, no encuentro al Vespoid reina! Quizá aparezca si matas muchos Vespoid para que piense que su prole está en grave peligro...');
INSERT INTO `quest_text` VALUES ('319','en','The Big Dirt Nap','Hunt the Hypnocatrice','Shifty Merchant','The Hypnocatrice, the sleep-inducing bird wyvern of the Great Forest. Those who face it usually end up taking a dirt nap, so its materials are highly coveted. So... You gonna give it a shot?');
INSERT INTO `quest_text` VALUES ('319','es','Criando malvas','Caza al Hypnocatrice','Mercader sospechoso','Hypnocatrice, el pájaro Wyvern inductor de sueño del Gran bosque. Los que se enfrentan a él acaban criando malvas, así que sus materiales son codiciados. ¿Quieres probar?');
INSERT INTO `quest_text` VALUES ('320','en','Hypno, Hypno!','Hunt 2 Hypnocatrices','Brave Prince','The Hypnocatrice is hurting so many people, so I tried to sneak out to the Great Forest. Unfortunately, I was spotted by a guard. Please, I ask that someone deal with that menace in my stead!');
INSERT INTO `quest_text` VALUES ('320','es','¡Hypno, Hypno!','Caza 2 Hypnocatrice','Príncipe valiente','El Hypnocatrice está hiriendo a tanta gente que intenté escaparme al Gran Bosque. Por desgracia, me vio un guardia. ¡Por favor, que alguien se ocupe de esa amenaza en mi lugar!');
INSERT INTO `quest_text` VALUES ('321','en','Trapped by Yian Kut-Ku','Hunt the Yian Kut-Ku and Blue Yian Kut-Ku','Beautiful Lady','The Yian Kut-Ku are circling, screaming in their shrill voices. Everyone is trapped inside the town! Please do something!');
INSERT INTO `quest_text` VALUES ('321','es','Atrapado por Yian Kut-Ku','Caza al Yian Kut-Ku y al Yian Kut-Ku azul','Mujer hermosa','Los Yian Kut-Ku rodean la ciudad, chillando con sus voces estridentes. ¡Todo el mundo está atrapado dentro! ¡Por favor, haz algo!');
INSERT INTO `quest_text` VALUES ('322','en','Giant Crab of the Old Jungle','Hunt the Daimyo Hermitaur','Lynian Clan Leader','We came here to the Old Jungle in search of some materials when a giant crab chased us out of the area, nya! We can''t make a living as long as that cretin is there. Please help us, nya!!');
INSERT INTO `quest_text` VALUES ('322','es','Gran cangr. Vieja jungla','Caza al Daimyo Hermitaur','Líder clan Lynian','Vinimos aquí a la Vieja jungla buscando materiales y un enorme cangrejo nos echó fuera, ¡miau! No podemos ganarnos la vida mientras ese cretino esté ahí. ¡Por favor, ayúdanos, miau!');
INSERT INTO `quest_text` VALUES ('323','en','Daimyo of Sengoku Fame','Hunt the Plum D.Hermitaur','Merchant of the East','I spotted an unusual variety of Daimyo Hermitaur out in the Old Desert. I don''t know what it was, but I swear it was evil! Anyway, here''s my proposition: Hunt the crab and make a fortune. Deal?');
INSERT INTO `quest_text` VALUES ('323','es','Daimyo de fama Sengoku','Caza al D.Hermitaur cereza','Mercader del este','He detectado una rara variedad de Daimyo Hermitaur en el Viejo desierto. ¡No sé qué era, pero seguro que era malo! Bueno, ésta es mi propuesta: caza al cangrejo y gana un fortuna.');
INSERT INTO `quest_text` VALUES ('324','en','Wag the Dog!','Hunt the Daimyo Hermitaur and the Plum D.Hermitaur','TrinketLover''sGrddtr','My grandfather stumbled on a fight between two famous warriors. They say that it''s the dream of a warrior to die on the battlefield, but not by their own hands! Please go and help them!');
INSERT INTO `quest_text` VALUES ('324','es','¡El mundo al revés!','Caza al Daimyo Hermitaur y al D.Hermitaur cereza','Nieta amante tesoros','Mi abuelo se encontró una pelea entre dos famosos guerreros. Dicen que el sueño de un guerrero es morir en el campo de batalla, ¡pero no por sus propias manos! ¡Por favor, ve a ayudarlos!');
INSERT INTO `quest_text` VALUES ('325','en','Old Jungle Lightning','Hunt the Khezu','Madam Merchant','Just when I thought that maybe this time the peace would last, this happens! As long as that Khezu just sits there, we can''t get out of the Old Jungle. Please, come to our rescue, hunter!');
INSERT INTO `quest_text` VALUES ('325','es','Relámpago de la Vieja jungla','Caza al Khezu','Dama mercader','¡Justo cuando pensaba que quizá esta vez la paz fuera duradera, ocurre esto! Mientras el Khezu esté ahí no podemos salir de la Vieja jungla. ¡Por favor, ven a rescatarnos, cazador!');
INSERT INTO `quest_text` VALUES ('326','en','Red Shadow in the Snow','Hunt the Red Khezu','Uncomfortable Butler','I''ve always longed to venture into the Snowy Mountains! I think I could hunt down an Anteka, but I could never fight a wyvern. Maybe you could take care of a special monster for me...');
INSERT INTO `quest_text` VALUES ('326','es','Sombra roja en la nieve','Caza al Khezu rojo','Mayor. indispuesto','Siempre quise aventurarme en las Montañas Nevadas. Creo que podría cazar un Anteka, pero nunca podría luchar con un Wyvern. Quizá tú puedas ocuparte por mí de ese monstruo...');
INSERT INTO `quest_text` VALUES ('327','en','Tales from the Old Swamp','Hunt 2 Red Khezu','Horror-Loving Youth','Ever since a long time ago, 2 gruesome wyverns have lived in the depths of the cave in the Old Swamp, their blood-red bodies surrounded in a sharp, blue glow... *gasp!* Look, behind you!');
INSERT INTO `quest_text` VALUES ('327','es','Cuentos del Viejo pantano','Caza 2 Khezu rojos','Joven amante terror','Desde hace algún tiempo 2 atroces Wyverns han vivido en lo profundo de la cueva del Viejo pantano, sus cuerpos rojo sangre rodeados de un fulgor nítido y azul... *¡Ag!* ¡Mira, detrás de ti!');
INSERT INTO `quest_text` VALUES ('328','en','Eyes in the Underground Lake','Hunt the Plesioth','OldDesertWepnSmiths','The Plesioth of the Old Desert''s underground lake... We''ve received an SOS from the group of secret hunters who were hunting this beast. Can you keep the Plesioth at bay while we rescue them?');
INSERT INTO `quest_text` VALUES ('328','es','Ojos en el lago subterráneo','Caza al Plesioth','Viejo MercArmasDes','El Plesioth del lago subterráneo del Viejo desierto... Hemos recibido un SOS del grupo de cazadores secretos que cazaban a la bestia. ¿Contendrás al Plesioth hasta que los rescatemos?');
INSERT INTO `quest_text` VALUES ('329','en','Giant Green Waves of Verdure','Hunt the Green Plesioth','Hasty High Official','Help! I''ve received word that a Green Plesioth has appeared along our Queen''s route to another land. Please take care of it in secret for us before she enters the area!');
INSERT INTO `quest_text` VALUES ('329','es','Olas gigantes de verdura','Caza al Plesioth verde','Al.ofic.desagradable','¡Ayuda! Hemos sabido que ha aparecido un Plesioth verde en la ruta de nuestra Reina hacia otro territorio. ¡Ócupate de él antes de que entre en la zona!');
INSERT INTO `quest_text` VALUES ('330','en','Prodigal Pack Attack!','Hunt the Congalala','Very Suspect Peddler','Congas have gathered in the Swamp and are destroying all the good mining points. Now, I''d hate for this to leak, but there''s a great mining point in a secret place. Just keep that mum, OK?');
INSERT INTO `quest_text` VALUES ('330','es','¡Generoso ataque en equipo!','Caza al Congalala','Vendedor sospechoso','Los Conga se han reunido en el pantano y están destruyendo los Puntos de minería. No quiero que se sepa, pero hay un Punto de minería excelente en un lugar secreto.');
INSERT INTO `quest_text` VALUES ('331','en','Pelagus Pride','Hunt the Emerald Congalala','Beautiful Swordsman','Hmph, how rude! Can you believe that awful beast spewed some nasty gunk at me three times in a row!? ...I beg your pardon? I still stink!? How dare you, you uncouth heathen!?');
INSERT INTO `quest_text` VALUES ('331','es','Orgullo de Pelagus','Caza al Congalala esmeralda','Hermoso espadachín','¡Hmph, qué grosero! ¿Puedes creer que esa horrible bestia me ha escupido alguna porquería tres veces seguidas? ¿Qué...? ¿¡Que todavía huele!? ¿Cómo te atreves, bárbaro inculto?');
INSERT INTO `quest_text` VALUES ('332','en','Trickster!','Hunt the Emerald Congalala','Distinguished Lady','There is a child wandering lost deep in the Great Forest. Our rescue efforts have thus far failed due to a strange and rare, bearded beast... I ask that someone please hunt that thing down!');
INSERT INTO `quest_text` VALUES ('332','es','¡Timador!','Caza al Congalala esmeralda','Señora distinguida','Hay un niño que vaga perdido por lo profundo del Gran bosque. Nuestros esfuerzos por rescatarle han fracasado por culpa de una extraña y escasa bestia barbuda... Por favor, ¡que alguien la cace!');
INSERT INTO `quest_text` VALUES ('333','en','Stealing in the Jungle!','Hunt the Gypceros','Compassionate Hunter','That Gypceros stole my very important Book of Combos, and then, right after that, a band of Melynx stole my BBQ Spit! At this rate, I''m going to be forced into early retirement! Heeeeelp!');
INSERT INTO `quest_text` VALUES ('333','es','¡Robando en la jungla!','Caza al Gypceros','Cazador compasivo','¡Ese Gypceros robó mi importantísimo Libro de combos y luego, justo después, una banda de Melynx robó mi Asador de barbacoa! A este paso voy a tener que retirarme antes de tiempo. ¡Ayuuda!');
INSERT INTO `quest_text` VALUES ('334','en','Old Swamp, Shrouded in Mist','Hunt 2 Purple Gypceros','Wyverian Workshop','Gypceros are covered in a rubbery skin that''s mostly waterproof, yet despite this, they like to live in areas of high humidity. Hmm... To solve this riddle, I''ll require more data!');
INSERT INTO `quest_text` VALUES ('334','es','Viejo pantano neblinoso','Caza 2 Gypceros morados','Taller Wyverian','Los Gypceros están cubiertos de una piel gomosa que es casi impermeable pero, a pesar de ello, les gusta vivir en zonas muy húmedas. Mmm... ¡Para solucionar este enigma voy a necesitar más datos!');
INSERT INTO `quest_text` VALUES ('335','en','Subspecies Three!','Hunt all of the Large Monsters','Materials Old-Timer','Add a Blue Yian Kut-Ku to a Green Plesioth and you get a Plum D.Hermitaur. Seriously, uniquely-colored equipment is selling like hotcakes, especially with young folks. Wish I could get in on that.');
INSERT INTO `quest_text` VALUES ('335','es','¡Subespecie tres!','Caza todos los monstruos grandes','Veterano vendedor','Añade un Yian Kut-Ku a un Plesioth verde y tendrás un D.Hermitaur cereza. Los equipos de color único se venden como rosquillas, especialmente entre jóvenes. Ojalá pudiera entrar yo ahí.');
INSERT INTO `quest_text` VALUES ('336','en','Predators of the Swamp','Hunt all of the Large Monsters','Honest Retainer','Recently, the number of people disappearing in the swamplands has been on the rise and we think the reason is linked to monsters in the area. If you can, please help look into this for us.');
INSERT INTO `quest_text` VALUES ('336','es','Predadores del pantano','Caza todos los monstruos grandes','Criado honesto','Últimamente ha aumentado el número de personas que se pierden en los pantanos, y creemos que el motivo está ligado a los monstruos de la zona. Si puedes, por favor, ayúdanos a investigarlo.');
INSERT INTO `quest_text` VALUES ('337','en','G-Lvl Gathering - Frst&Hills','Survive until Time Over or Deliver the Paw Pass Ticket','Guild Manager','A gathering quest in the Forest & Hills. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Just be aware of the G-Level monsters, OK?');
INSERT INTO `quest_text` VALUES ('337','es','Reunión nv G - Bosque y col.','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe del Gremio','Misión de recogida en los Bosques y colinas. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar. Cuidado con los monstruos de nivel G, ¿vale?');
INSERT INTO `quest_text` VALUES ('338','en','G-Lvl Gathering - OldVolcano','Survive until Time Over or Deliver the Paw Pass Ticket','Guild Manager','A gathering quest in the Old Volcano. Gather all the materials you can from the field, then deliver the Paw Pass Ticket to finish up. Just be aware of the G-Level monsters, OK?');
INSERT INTO `quest_text` VALUES ('338','es','Reunión nv G - Viejo volcán','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Jefe del Gremio','Misión de recogida en el Viejo volcán. Recoge todos los materiales que puedas del campo y entrega el Ticket zarpa para terminar. Cuidado con los monstruos de nivel G, ¿vale?');
INSERT INTO `quest_text` VALUES ('339','en','Ever-Present Shadow','Hunt the Nargacuga','PrivilegedLadyKnight','I saw a demon in the Great Forest so fast that I could barely even register its shadow as it flew by. My trusty partner is my sword, and I hate to beg, but I need some backup here!');
INSERT INTO `quest_text` VALUES ('339','es','Sombra omnipresente','Caza al Nargacuga','Caballero mujer prv.','Vi en el Gran bosque un demonio tan rápido que apenas pude registrar su sombra cuando pasó. Mi fiel compañera es mi Espada y odio suplicar pero, ¡Necesito la ayuda de alguien!');
INSERT INTO `quest_text` VALUES ('340','en','Assassin of the Swamp','Hunt the Nargacuga','Bearded Soldier','Our head drill sergeant was attacked while out on an expedition in the Old Swamp by an unknown assailant. We think it''s probably a monster, but we require the assistance of a hunter!');
INSERT INTO `quest_text` VALUES ('340','es','Asesino del pantano','Caza al Nargacuga','Soldado barbudo','Nuestro sargento instructor jefe fue atacado durante una expedición al Viejo pantano por un asaltante desconocido. ¡Creemos que es un monstruo, pero necesitamos la ayuda de un cazador!');
INSERT INTO `quest_text` VALUES ('341','en','Ancient Beauty, Black Beast','Hunt 2 Nargacugas','Terrified Aristocrat','From within the midst of the Great Forest''s mist, I saw two blood-red eyes! Rest assured I will pay you well, just please, someone come defeat this creature quick!');
INSERT INTO `quest_text` VALUES ('341','es','Antigua beldad, bestia negra','Caza 2 Nargacugas','Aristócr. aterror.','En el interior de la niebla del Gran bosque, ¡vi dos ojos rojo sangre! Estad bien seguros de que pagaré bien pero, por favor, ¡que venga alguien rápidamente a vencer a esta criatura!');
INSERT INTO `quest_text` VALUES ('342','en','Lavasioth Sighting!','Hunt the Lavasioth','Selfish Princess','I''m in a fishing competition with my elder brother. We agreed to compare rubbings to determine the winner. Well, imagine how much I''d win by if I had a Lavasioth rubbing! I''m a genius!');
INSERT INTO `quest_text` VALUES ('342','es','¡Avistamiento de Lavasioth!','Caza al Lavasioth','Princesa egoísta','Estoy en una competición de pesca con mi hermano mayor. Hemos acordado comparar calcos para determinar el ganador. ¡Imagina cuánto ganaría si tuviera uno de un Lavasioth! ¡Soy un genio!');
INSERT INTO `quest_text` VALUES ('343','en','River of Fire','Hunt 2 Lavasioths','Mine Owner','From out of the rivers of lava came 2 Lavasioths! I am dead serious. And right in front of a good Powderstone deposit! Please, dear hunter! Hunt these two down so we may get back to work!');
INSERT INTO `quest_text` VALUES ('343','es','Río de fuego','Caza 2 Lavasioths','Propietario de mina','¡De los ríos de lava salieron 2 Lavasioth! Hablo muy en serio. ¡Justo delante de un buen depósito de Piedra polvo! ¡Por favor, querido cazador! ¡Cázalos para que podamos volver al trabajo!');
INSERT INTO `quest_text` VALUES ('344','en','Strong Sword, Strong Shield','Hunt the Daimyo Hermitaur and Shogun Ceanataur','Arena Manager','The Arena! A place to show your skills to the world! For this event, we have released two crab-like enemies into the arena! All those ready to test their skills are welcome!');
INSERT INTO `quest_text` VALUES ('344','es','Fuerte espada, fuerte escudo','Caza al Daimyo Hermitaur y al Shogun Ceanataur','Jefe arena','¡La Arena! ¡Un lugar donde mostrar tus habilidades al mundo! Para este evento, hemos soltado en la arena dos enemigos con aspecto de cangrejo. ¡Los que quieran probar son bienvenidos!');
INSERT INTO `quest_text` VALUES ('345','en','Commander in the Flames','Hunt the Shogun Ceanataur','Chief Weapon Smith','Upon our trip into the cave at the volcano, an enormous Shogun Ceanataur dropped down from the ceiling right on top of us! Its ambush caused massive damage! Rid the world of that scourge!');
INSERT INTO `quest_text` VALUES ('345','es','Comandante en llamas','Caza al Shogun Ceanataur','Jefe herrero armas','En nuestro viaje a la cueva del volcán, ¡cayó del techo, justo sobre nosotros, un enorme Shogun Ceanataur! ¡Su emboscada produjo enormes daños! ¡Libra al mundo de ese azote!');
INSERT INTO `quest_text` VALUES ('346','en','Dark-Shelled Ceanataur','Hunt the Terra S.Ceanataur','Selfish Felyne','I was going to get some materials after my catnap from what I thought was an empty black shell, but it took off, nya! I''m so mad that I didn''t get anything! You''d better help me, nya!');
INSERT INTO `quest_text` VALUES ('346','es','Ceanataur de concha oscura','Caza al S.Ceanataur tierra','Felyne egoísta','Después de mi siesta, iba a buscar materiales en lo que parecía una concha negra vacía, ¡pero salió volando, miau! ¡Estoy furioso porque no conseguí nada! ¡Más vale que me ayudes, miau!');
INSERT INTO `quest_text` VALUES ('347','en','Under the Gaze of Heaven','Hunt the Shogun Ceanataur and the Terra S.Ceanataur','TrinketLover''sGrddtr','My grandfather stumbled on a fight between two famous warriors. They say that it''s the dream of a warrior to die on the battlefield, but not by their own hands! Please go and help them!');
INSERT INTO `quest_text` VALUES ('347','es','Bajo la mirada del cielo','Caza al Shogun Ceanataur y al S.Ceanataur tierra','Nieta amante tesoros','Mi abuelo se encontró una pelea entre dos famosos guerreros. Dicen que el sueño de un guerrero es morir en el campo de batalla, ¡pero no por sus propias manos! ¡Por favor, ve a ayudarlos!');
INSERT INTO `quest_text` VALUES ('348','en','At Birds'' Hill...','Hunt the Yian Kut-Ku?','Gaggle of Mistresses','We were enjoying a lovely picnic in the forest, where even the small birds had come out of hiding to bathe in the sunlight. But then, a lick of flame came out of nowhere! What was that!?');
INSERT INTO `quest_text` VALUES ('348','es','En la colina de los pájaros','¿Caza al Yian Kut-Ku?','Bandada de amas','Disfrutábamos de un picnic en el bosque con los pajaritos saliendo de las sombras para tomar la luz del sol. Pero, entonces, ¡algo que respiraba fuego salió de no sé dónde! ¿¡Qué era eso!?');
INSERT INTO `quest_text` VALUES ('349','en','A King, Robed in Smoke','Hunt the Rathalos','MightyMountainMonks','Unbelievably, the king of all wyverns has appeared in the Old Volcano belt. To protect our temple, we went to fight it, but to no avail. Please, we humbly ask for your assistance, hunter!');
INSERT INTO `quest_text` VALUES ('349','es','Un rey, vestido de humo','Caza al Rathalos','Monjes del monte','Increíblemente, el rey de los Wyverns apareció en la falda del Viejo volcán. Para proteger nuestro templo salimos a luchar con él, pero sin éxito. ¡Te pedimos humildemente ayuda, cazador!');
INSERT INTO `quest_text` VALUES ('350','en','The King''s Domain','Hunt the Azure Rathalos','Brave Boys','Do you hear that? A voice that makes the earth tremble. Soldiers who have never known defeat are knocked about by this sky king''s roar, but that''s what hunters are for, right?');
INSERT INTO `quest_text` VALUES ('350','es','El dominio del rey','Caza al Rathalos celeste','Chicos valientes','¿Lo has oído? Una voz que hace temblar la tierra. Soldados que no conocían la derrota caen abatidos por este rugido del rey del cielo. Pero para eso están los cazadores, ¿verdad?');
INSERT INTO `quest_text` VALUES ('351','en','Her Eternal Majesty','Hunt the Rathian','Powerful Ambassador','In order to hunt down the ferocious Rathian in our lands, we are asking for volunteers. Hunters! Show us your strength and hunt that which is called "Empress".');
INSERT INTO `quest_text` VALUES ('351','es','Su eterna majestad','Caza la Rathian','Embajador poderoso','Para cazar la feroz Rathian en nuestras tierras, pedimos voluntarios. ¡Cazadores, mostradnos vuestra fuerza y cazad a la que llaman "Emperatriz"!');
INSERT INTO `quest_text` VALUES ('352','en','The Cherry Blossom Rathian','Hunt the Pink Rathian','Sharp Eyed Count','The terrible Pink Rathian. It invades other monsters'' territory and throws them into disarray, and picks fights with them as well. We must quickly rid the world of such a dangerous monster!');
INSERT INTO `quest_text` VALUES ('352','es','El Rathian de flor de cerezo','Caza la Rathian rosa','Conde Buenavista','La terrible Rathian rosa. Invade el territorio de otros monstruos y luchando con ellos y haciéndolos huir. ¡Debemos librar al mundo rápidamente de un monstruo tan peligroso!');
INSERT INTO `quest_text` VALUES ('353','en','Howling at the Moon','Hunt the Yian Garuga','Lone Wolf Hunter','Heh, at long last I have laid eyes upon my prey, the Great Forest''s Yian Garuga, though never in my wildest dreams did I think it would be so strong! Hunter, I call upon your assistance now.');
INSERT INTO `quest_text` VALUES ('353','es','Aullando a la luna','Caza al Yian Garuga','Cazador lobos solit.','Eh, por fin le he puesto la vista encima a mi presa, el Yian Garuga del Gran bosque, aunque ni en mis sueños más osados creí que fuera tan fuerte. Cazador, solicito ahora tu ayuda.');
INSERT INTO `quest_text` VALUES ('354','en','The Yian Garuga Twins','Hunt 2 Yian Garuga','Lovely Princess','Yian Garuga have appeared in the forest areas one by one. Unending cycles of inflamed violence has caused many casualties in the area. For the sake of the people, please do something quick!');
INSERT INTO `quest_text` VALUES ('354','es','Los gemelos Yian Garuga','Caza 2 Yian Garuga','Princesa encantadora','Han aparecido Yian Garuga en las zonas de bosque, una a una. Interminables ciclos de violencia inflamada han provocado muchas bajas en la zona. ¡Por la gente, por favor, haz algo rápidamente!');
INSERT INTO `quest_text` VALUES ('355','en','The King of the Mountains','Hunt the Blangonga','Foothills Villager','A Blangonga has staked its claim to a piece of the snowy mountains. Now we can''t enter the area to gather firewood. Exterminate the Blangonga!');
INSERT INTO `quest_text` VALUES ('355','es','El rey de las montañas','Caza al Blangonga','Montañés','Un Blangonga ha reclamado para sí una parte de las montañas nevadas. Ahora no podemos entrar en la zona para recoger leña. ¡Extermina al Blangonga!');
INSERT INTO `quest_text` VALUES ('356','en','Copper Sands','Hunt the Copper Blangonga','ForgttnScholarStudnt','My teacher believed that a subspecies of Blangonga lives in the arid sands of a desert, and went in search of it. People have forgotten about my teacher, but I want to know what happened!');
INSERT INTO `quest_text` VALUES ('356','es','Arenas de cobre','Caza al Blangonga cobre','Estudiante erd. olv.','Mi profesor creía que una subespecie de Blangonga vive en las áridas arenas de un desierto, y se fue a buscarla. La gente ha olvidado a mi profesor, ¡pero yo quiero saber qué ocurrió!');
INSERT INTO `quest_text` VALUES ('357','en','Wild Monk of the Dunes','Hunt the Copper Blangonga','Confused Bar Owner','Oh my! I''m sure that was a Blangonga, but they only live in areas of extreme cold! What is one doing out here!? Ahh, I have no idea what''s going on anymore, but please do something!');
INSERT INTO `quest_text` VALUES ('357','es','Monje salvaje de las dunas','Caza al Blangonga cobre','Dueño bar confundido','¡Madre mía! Estoy seguro de que era un Blangonga, pero sólo viven en zonas de frío extremo. ¿¡Qué está haciendo aquí!? Ahh, ya no tengo ni idea de lo que pasa pero, por favor, ¡haz algo!');
INSERT INTO `quest_text` VALUES ('358','en','Basarios Season','Survive until Time Over or Deliver the Paw Pass Ticket','Unlucky Journey Lady','I was hiding from a Basarios behind some boulders when it turned out to be another one! I thought I could hide behind some other boulders ahead of me, but it was yet another one! Somebody, help!');
INSERT INTO `quest_text` VALUES ('358','es','Temporada de Basarios','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Mujer viaje desafrt.','Me escondía de un Basarios tras unos pedruscos cuando ¡resultó que había otro! Pensé que podría ocultarme detrás de otras piedras más adelante pero, ¡había otro más! ¡Que alguien me ayude!');
INSERT INTO `quest_text` VALUES ('359','en','Operation Tropical Storm','Hunt all of the Large Monsters','Guild Messenger','We''ve received word that an airship made an emergency landing in the Jungle, but the area is home to a Daimyo Hermitaur, a Gypceros, and a Rathian. Hurry to the region and help hunt them down!');
INSERT INTO `quest_text` VALUES ('359','es','Operación Tormenta tropical','Caza todos los monstruos grandes','Mensajero del Gremio','Nos han dicho que una aeronave aterrizó forzosamente en la Jungla, pero esa zona alberga un Daimyo Hermitaur, un Gypceros y un Rathian. ¡Corre allí y ayúdanos a cazarlos!');
INSERT INTO `quest_text` VALUES ('360','en','Save the Great Forest Town!','Hunt all of the Large Monsters','Guild Big-Wig','There''s something strange in the air, and it''s attracting all manner of monsters all at once! Right now, there''s only 1 hunter for every 3 monsters so any help you can give would be fantastic!');
INSERT INTO `quest_text` VALUES ('360','es','Salva la aldea de G. bosque','Caza todos los monstruos grandes','Jefazo Gremio','Hay algo extraño en el aire, ¡y atrae a todo tipo de monstruos a la vez! Ahora mismo sólo hay 1 cazador por cada 3 monstruos, así que ¡cualquier ayuda que puedas prestarnos será fantástica!');
INSERT INTO `quest_text` VALUES ('361','en','Three Walls','Hunt all of the Large Monsters','Uncomfortable Butler','The young master has gone on a most impossible hunt, I''m afraid; all for the hand of a certain beautiful lady knight. I fear it will not end well, so I ask that you please help him along!');
INSERT INTO `quest_text` VALUES ('361','es','Tres muros','Caza todos los monstruos grandes','Mayor. indispuesto','El joven maestro se ha ido a una cacería imposible. Todo por la mano de cierta bella doncella. ¡Temo que no termine bien, así que te pido que le ayudes!');
INSERT INTO `quest_text` VALUES ('362','en','A Hunter''s Feast','Hunt all of the Large Monsters','DesertedArenaManager','I went to open up the arena that no one has used in a while. Lo and behold, it''s now a den of monsters! They seem to like it there so much they were immediately up in arms. Please help me!');
INSERT INTO `quest_text` VALUES ('362','es','Un banquete de cazador','Caza todos los monstruos grandes','Jefe arena desierta','Fui a abrir la arena, que nadie ha usado en mucho tiempo. ¡Resulta que se ha convertido en una guarida de monstruos! ¡Les gusta tanto que la van a defender a muerte! ¡Por favor, ayúdame!');
INSERT INTO `quest_text` VALUES ('363','en','Lao-Shan Lung Draws Near!','Defend the Fortress from Lao-Shan Lung','Guild Master','It seems that once again our land is in crisis. The giant elder dragon Lao-Shan Lung is approaching the village from the mountains. Head to the fort and defend our way of life!');
INSERT INTO `quest_text` VALUES ('363','es','¡Se acerca Lao-Shan Lung!','Defiende la fortaleza del Lao-Shang Lung','Maestro del Gremio','Parece ser que, una vez más, estamos en crisis. El dragón anciano gigante Lao-Shan Lung se acerca a la aldea desde las montañas. ¡Ve al fuerte y defiende nuestra forma de vida!');
INSERT INTO `quest_text` VALUES ('364','en','Absolute Power','Hunt the Tigrex','Guild Master','At last, the Tigrex has appeared! It is said the beast''s origins are as a flying wyvern. It is too powerful to be allowed to run free. The village is in danger! Hunt it quickly!');
INSERT INTO `quest_text` VALUES ('364','es','Poder absoluto','Caza al Tigrex','Maestro del Gremio','¡Por fin ha aparecido el Tigrex! Se dice que los orígenes de la bestia están en un Wyvern volador. Es demasiado poderoso como para dejarlo libre. ¡La aldea está en peligro! ¡Cázalo rápido!');
INSERT INTO `quest_text` VALUES ('365','en','Land of the Tremors','Hunt 2 Tigrex','Guild Master','A group of highly skilled hunters went off to slay two Tigrex, but they became the hunted. Please destroy the two Tigrex and open a clear route for our rescue team.');
INSERT INTO `quest_text` VALUES ('365','es','Tierra de los temblores','Caza 2 Tigrex','Maestro del Gremio','Un grupo de cazadores muy hábiles salió a matar dos Tigrex, pero ellos se convirtieron en las presas. Destruye los dos Tigrex y abre una ruta limpia para nuestro equipo de rescate.');
INSERT INTO `quest_text` VALUES ('366','en','Sandstorm Summoner','Hunt the Diablos','Envoy to the King','I have heard that there is a hunter in this village of great skill. We have sent scores of soldiers, yet they are no match for the Diablos of the Old Desert. Please lend us your power, Hunter!');
INSERT INTO `quest_text` VALUES ('366','es','Invocador de tormentas','Caza al Diablos','Enviado al rey','He oído que hay un cazador muy hábil en esta aldea. Hemos mandado montones de soldados, pero no son rival para el Diablos del Viejo desierto. ¡Préstanos tu poder, cazador!');
INSERT INTO `quest_text` VALUES ('367','en','The Fierce Black Horn','Hunt the Black Diablos','Failed Millionaire','I had hired the most skilled hunters imaginable, and went on a safari for the famed Diablos... But what we found was no mere Diablos! We must slay that black horned wyvern! No matter what!');
INSERT INTO `quest_text` VALUES ('367','es','El fiero cuerno negro','Caza al Diablos negro','Millonario fracasado','Contraté los cazadores más hábiles que pude y me fui de safari a por el famoso Diablos... ¡Pero lo que encontré no era un mero Diablos! ¡Tenemos que matar ese Wyvern negro con cuernos!');
INSERT INTO `quest_text` VALUES ('368','en','Black Phalanges','Hunt 2 Black Diablos','Surviving Trooper','SOS! Two gigantic black towers came rising out of the ground and threw us into disarray. The pressure of tens of thousands of troops on us; so this is a wyvern''s might. Please help us out!');
INSERT INTO `quest_text` VALUES ('368','es','Falanges negras','Caza 2 Diablos negros','Soldado superv.','¡SOS! Dos torres negras gigantes se levantaron del suelo y nos pusieron en fuga. La presión de decenas de miles de tropas sobre nosotros, así es la fuerza de un Wyvern. ¡Ayúdanos!');
INSERT INTO `quest_text` VALUES ('369','en','Armored Supremacy','Hunt the Gravios','Friendly Head Knight','Even us knights can''t stand up to the Gravios''s mighty heat ray. I know this is a big request, but can you please go and hunt this armored beast in our stead?');
INSERT INTO `quest_text` VALUES ('369','es','Supremacía armada','Caza al Gravios','Cab. jefe amable','Ni siquiera nosotros, los caballeros, podemos soportar el poderoso rayo de calor del Gravios. Sé que es pedir mucho pero, ¿puedes ir a cazar esta bestia armada por nosotros?');
INSERT INTO `quest_text` VALUES ('370','en','Terror of the Gravios','Hunt the Black Gravios','Troubled Noble','A fearsome Gravios has appeared amidst the magma and desolation of the Volcanic Belt. Hunt down the fire breather for us!');
INSERT INTO `quest_text` VALUES ('370','es','Terror del Gravios','Caza al Gravios negro','Noble preocupado','Un temible Gravios ha aparecido entre el magma y la desolación del Cinturón volcânico. ¡Caza por nosotros al que respira fuego!');
INSERT INTO `quest_text` VALUES ('371','en','The Dark Cataphracts','Hunt 2 Black Gravios','Guild Messenger','Hunters who were escorting some scholars were attacked by a few Gravios. They managed to fend them off, but they are unable to leave the area. Please hurry to their rescue!');
INSERT INTO `quest_text` VALUES ('371','es','Los oscuros catafractos','Caza 2 Gravios negros','Mensajero del Gremio','Cazadores que escoltaban a unos estudiosos fueron atacados por unos pocos Gravios. Consiguieron rechazarlos, pero no fueron capaces de abandonar la zona. ¡Apresúrate a rescatarlos!');
INSERT INTO `quest_text` VALUES ('372','en','Explore the Unexplored','Hunt the Silver Rathalos','Hunchbacked Old Lady','I''ll tell you about a secret hunting ground, I will. It doesn''t matter if it''s day or night, the silver sun always shines, giving would-be hunters a good workout... Heh, heh, heh...!');
INSERT INTO `quest_text` VALUES ('372','es','Explora lo inexplorado','Caza al Rathalos plateado','Anciana jorobada','Te voy a hablar de un cazadero secreto. No importa si es de día o de noche, el sol plateado brilla siempre, sirviendo de entrenamiento a los aspirantes a cazador... ¡Je, je, je...!');
INSERT INTO `quest_text` VALUES ('373','en','A Single Beam of Moonlight','Hunt the Gold Rathian','Well-Dressed Youth','We were dazed and lost in a haze for days when we came upon a mysterious land. There, we spied a golden moon. If I tell you the location, will you look into the area for me in secret?');
INSERT INTO `quest_text` VALUES ('373','es','Un único rayo de luz de luna','Caza la Rathian dorada','Joven bien vestido','Pasamos días aturdidos y perdidos en la bruma hasta llegar a una tierra misteriosa. Allí vimos una luna dorada. Si te digo dónde, ¿investigarás esa zona por mí secretamente?');
INSERT INTO `quest_text` VALUES ('374','en','Descendants of the King','Hunt the Silver Rathalos and the Gold Rathian','SharpWittedGentleman','The silver-winged king and his gold-bodied queen. Whoever successfully hunts them both shall be known as the King of Hunters. I await your return with a glass held high!');
INSERT INTO `quest_text` VALUES ('374','es','Descendientes del rey','Caza la Rathian dorada y al Rathalos plateado','Señor ingenioso','El rey de alas de plata y su reina de cuerpo de oro. Quien tenga éxito cazando a ambos será conocido como el Rey de los cazadores. ¡Espero que vuelvas levantando una copa!');
INSERT INTO `quest_text` VALUES ('375','en','Child of Destruction','Hunt the Rajang','Elite Hunter','The legendary Rajang has appeared at last, however, I will leave it for you other hunters as I have other matters to attend to. I have people back home waiting for my return, after all.');
INSERT INTO `quest_text` VALUES ('375','es','Hijo de la destrucción','Caza al Rajang','Cazador élite','El legendario Rajang ha aparecido al fin, pero se lo dejaré a otros cazadores porque tengo otros asuntos que atender. Hay gente que me espera de vuelta en casa, después de todo.');
INSERT INTO `quest_text` VALUES ('376','en','The Final Invitation','Hunt 2 Rajang','Scarlet Mystery Man','There are two Rajang, each with golden fur. Hunters, I have prepared a special stage for your grandest performance. Demonstrate your true power... He he he...');
INSERT INTO `quest_text` VALUES ('376','es','La invitación final','Caza 2 Rajang','Hombre mister. esc.','Hay dos Rajang, ambos de piel dorada. Cazadores, he preparado un escenario especial para vuestra más grandiosa actuación. Demostrad vuestro verdadero poder. Je, je, je...');
INSERT INTO `quest_text` VALUES ('377','en','A Scenic Locale','Slay the Kirin','Exploration Junkie','They say there''s a secret place where all manners of ancient monsters live together, and I have found it at long last... If you want, I will show this virgin land to you!');
INSERT INTO `quest_text` VALUES ('377','es','Un lugar pintoresco','Mata al Kirin','Adicto exploración','Dicen que hay un lugar secreto donde todo tipo de monstruos viven juntos, y por fin lo he encontrado. Si lo deseas, ¡te mostraré esta tierra virgen!');
INSERT INTO `quest_text` VALUES ('378','en','It''s Electric','Slay the Kirin','Practicality Scholar','There''s something causing lightning strikes in the heart of the Old Swamp. My theory is that this is proof that the mythical beast has come out of hiding. Isn''t it absolutely fascinating?');
INSERT INTO `quest_text` VALUES ('378','es','Es eléctrico','Mata al Kirin','Erudito práctico','Hay algo que provoca relámpagos en el corazón del Viejo pantano. Mi teoría es que es la prueba de que la bestia mítica ha salido de su escondite. ¿No es absolutamente fascinante?');
INSERT INTO `quest_text` VALUES ('379','en','Deathmatch on the Dunes!','Hunt all of the Large Monsters','Guild Master','The sprawling city in the oasis is under siege by a number of monsters. This is unprecedented! We must do what we can before something terrible befalls the city!');
INSERT INTO `quest_text` VALUES ('379','es','Duelo a muerte en las dunas','Caza todos los monstruos grandes','Maestro del Gremio','La caótica aldea del oasis está sitiada por varios monstruos. ¡Esto no tiene precedentes! ¡Debemos hacer lo que podamos antes de que a la aldea le suceda algo terrible!');
INSERT INTO `quest_text` VALUES ('380','en','Fire, Electricity, Heat Ray','Hunt all of the Large Monsters','Guild Heavyweight','I''m checking out the disturbance in the Swamp. The large monsters are going crazy and there are a ton of casualties. Help fend them off so that we can find the source of the trouble.');
INSERT INTO `quest_text` VALUES ('380','es','Fuego, electricidad, calor','Caza todos los monstruos grandes','Pez gordo Gremio','Hay algún tipo de perturbación en el Pantano. Los grandes monstruos se están volviendo locos y hay muchas bajas. Ayuda a ahuyentarlos para que podamos encontrar el origen del problema.');
INSERT INTO `quest_text` VALUES ('381','en','The 3 Masters of the Volcano','Hunt all of the Large Monsters','Mantled Huntress','I don''t usually make requests, but today''s an exception since I don''t feel my best. ...What? H-How dare you!? I-I could do this job in my sleep! It''s that easy! Ah, just come back safe...');
INSERT INTO `quest_text` VALUES ('381','es','Los 3 maestros del volcán','Caza todos los monstruos grandes','Cazadora enmant.','No suelo hacer solicitudes, pero haré una excepción porque no estoy en mi mejor momento... ¿Qué? ¿¡C-cómo te atreves? ¡P-podría hacer el trabajo dormido! ¡Es tan fácil! Vuelve de una pieza...');
INSERT INTO `quest_text` VALUES ('382','en','Diamond Dust','Hunt all of the Large Monsters','Base Village Elder','Recently, the weather around the Snowy Mountains has been bad nonstop. Further, the monsters are hungry from a lack of food, and have started to violently attack each other. Please help us!');
INSERT INTO `quest_text` VALUES ('382','es','Polvo de diamante','Caza todos los monstruos grandes','Anciano aldea base','Recientemente, el tiempo no ha parado de ser malo en las Montañas Nevadas. Además, los monstruos tienen hambre por la falta de comida y han empezado a atacarse violentamente entre sí. ¡Ayúdanos!');
INSERT INTO `quest_text` VALUES ('383','en','Hunter''s Funeral','Hunt all of the Large Monsters','DesertedArenaManager','I went to open up the arena that no one has used in a while. Lo and behold, it''s now a den of monsters! They seem to like it there so much they were immediately up in arms. Please help me!');
INSERT INTO `quest_text` VALUES ('383','es','El funeral del cazador','Caza todos los monstruos grandes','Jefe arena desierta','Fui a abrir la arena, que nadie ha usado en mucho tiempo. ¡Resulta que se ha convertido en una guarida de monstruos! ¡Les gusta tanto que la van a defender a muerte! ¡Por favor, ayúdame!');
INSERT INTO `quest_text` VALUES ('384','en','Pride on the Line','Hunt all of the Large Monsters','PrivilegedLadyKnight','If I don''t pass this exercise, my father will force me to marry. But I''ve already sworn to myself that my only partner in life would be my trusty sword. Please, I need your help!');
INSERT INTO `quest_text` VALUES ('384','es','Orgullo en juego','Caza todos los monstruos grandes','Caballero mujer prv.','Si no apruebo este ejercicio mi padre me obligará a casarme. ¡Pero me he jurado que la única compañera de mi vida sería mi fiel espada! ¡Por favor, necesito tu ayuda!');
INSERT INTO `quest_text` VALUES ('385','en','The Dragon of Steel','Slay the Kushala Daora','Old Tribe''s Prince','If you see a giant twister at night out on the dunes, you''d best run. That is no ordinary sandstorm, but a legendary Elder Dragon. But if you think you can defeat it, then please go ahead!');
INSERT INTO `quest_text` VALUES ('385','es','El dragón de acero','Mata al Kushala Daora','Príncipe vieja tribu','Si ves un tornado gigante por la noche en las dunas, es mejor que corras. No es una tormenta de arena normal sino un legendario Dragón anciano. Si piensas que puedes derrotarlo, ¡adelante!');
INSERT INTO `quest_text` VALUES ('386','en','The Elder Dragon of Wind','Slay the Kushala Daora','Jungle Psychic','There was surely a vortex inside of that downpour. The wind wrapped around and revealed the elder dragon, Kushala Daora! There isn''t a single soul who can combat it alone, so fight together!');
INSERT INTO `quest_text` VALUES ('386','es','El Dragón anciano de viento','Mata al Kushala Daora','Vidente de jungla','Seguro que había un vórtice dentro de ese aguacero. ¡El viento cambió y reveló el Dragón Anciano, Kushala Daora! No hay nadie que pueda combatirlo solo, así que ¡luchad juntos!');
INSERT INTO `quest_text` VALUES ('387','en','A Midnight Audience','Slay the Teostra','Ill-ReputedInformant','The Teostra''s hideaway can only be found during the darkest hour, but I have done it. Now, if you can keep a secret, I''ll tell you where it is, and of course you will be well rewarded...');
INSERT INTO `quest_text` VALUES ('387','es','Una audiencia de medianoche','Mata al Teostra','Soplón mala rep.','El escondite del Teostra sólo se puede encontrar en la hora más oscura. Si sabes guardar un secreto, te diré dónde está y, por supuesto, se te recompensará bien...');
INSERT INTO `quest_text` VALUES ('388','en','Emperor of Flame','Slay the Teostra','Heroic General','I have an earnest request of you... As the last of my responsibilities, I request your help. I want you to fight the elder fire dragon we cornered in the Volcanic Belt, but beware its flames!');
INSERT INTO `quest_text` VALUES ('388','es','Emperador de las llamas','Mata al Teostra','General heroico','Tengo algo importante que pedirte. Como última de mis responsabilidades, te pido ayuda. Quiero que luches con el Dragón anciano de fuego acorralado en el volcán. ¡Cuidado con sus llamas!');
INSERT INTO `quest_text` VALUES ('389','en','Evaporate into the Night','Slay the Chameleos','Jungle Ancient','People think it''s impossible to fight an enemy you cannot see, however, if one were to focus and "see" with their gut instinct... Well, if all else fails, just swing your weapon round and round!');
INSERT INTO `quest_text` VALUES ('389','es','Evapórate en la noche','Mata al Chameleos','Anciano jungla','La gente piensa que es imposible luchar con un enemigo invisible, pero si uno enfocara y "viera" con el instinto... Bien, ¡si todo lo demás falla puedes hacer girar y girar el arma!');
INSERT INTO `quest_text` VALUES ('390','en','Towards the Silence','Slay the Chameleos','Grim Aristocrat','It seems an unknown elder dragon has appeared in the swamp zone. However, no one truly got a clear look at it. What could the beast have been? Slay it, but proceed with caution!');
INSERT INTO `quest_text` VALUES ('390','es','Hacia el silencio','Mata al Chameleos','Aristócr. siniestro','Parece que ha aparecido un Dragón anciano desconocido en la zona pantanosa. Nadie ha conseguido verlo claramente. ¿Qué puede haber sido esa bestia? ¡Mátala, pero ten cuidado!');
INSERT INTO `quest_text` VALUES ('391','en','The Floating Dragon','Slay the Yama Tsukami','E. Dragon Obs Office','We have confirmed the Yama Tsukami''s location at the old Tower! There is so much we have yet to understand about this floating dragon that we can''t let this chance escape! Move out!');
INSERT INTO `quest_text` VALUES ('391','es','El dragón flotante','Mata al Yama Tsukami','Ofic.obs. drag. anc.','¡Hemos confirmado la ubicación del Yama Tsukami en la vieja Torre! Nos queda tanto por comprender sobre este dragón flotante que no podemos dejar escapar esta oportunidad. ¡Muévete!');
INSERT INTO `quest_text` VALUES ('392','en','The Approaching Gaoren','Defend the Town from Shen Gaoren','Guild Master','Our town is embroiled in an unprecedented conflict. A fortress-like shelled monster is threatening our safety. We need help immediately!');
INSERT INTO `quest_text` VALUES ('392','es','El Gaoren se aproxima','Defiende la ciudad del Shen Gaoren','Maestro del Gremio','Nuestra tierra está inmersa en un conflicto sin precedentes. Un monstruo acorazado como una fortaleza amenaza nuestra seguridad. ¡Necesitamos ayuda inmediatamente!');
INSERT INTO `quest_text` VALUES ('393','en','Legendary Black Dragon','Slay the Fatalis','Benevolent Monarch','The legendary black dragon... It really exists then? We''ve prepared all instruments of war to assist you in your quest to destroy the dragon. The fate of the nation lies in your hands.');
INSERT INTO `quest_text` VALUES ('393','es','Legendario dragón negro','Mata al Fatalis','Monarca benevolente','El legendario dragón negro. ¿Existe entonces realmente? Hemos preparado todos los instrumentos de guerra para destruir al dragón. El destino de la nación está en tus manos.');
INSERT INTO `quest_text` VALUES ('394','en','The End Times','Slay the Fatalis','Scarlet Mystery Man','It appears the time has finally come. The bloodstained scales of the red dragon have graced the earth again in flaming glory. If you can stop this beast...');
INSERT INTO `quest_text` VALUES ('394','es','El tiempo del fin','Mata al Fatalis','Hombre mister. esc.','Parece que por fin ha llegado el momento. Las escamas manchadas de sangre del dragón rojo han vuelto a adornar la tierra con gloria ardiente. Si eres capaz de detener a esa bestia...');
INSERT INTO `quest_text` VALUES ('395','en','Ancestral Dragon','Slay the Fatalis','Scarlet Mystery Man','Hee hee hee... The time has come. Here is your invitation to the ball. Wear your Sunday best and bring your greatest weapon, for it is time to go to the dance with the king of disaster.');
INSERT INTO `quest_text` VALUES ('395','es','Dragón ancestral','Mata al Fatalis','Hombre mister. esc.','Je, je, je... Ha llegado la hora. Aquí tienes tu invitación al baile. Ponte la ropa de domingo y trae el arma más grande que tengas, porque es hora de bailar con la reina de la fiesta.');
INSERT INTO `quest_text` VALUES ('396','en','Absolute Zero','Slay the Ukanlos','Pokke Village Chief','This village already owes you so much, but we need you now more than ever. I truly believe it has to be you. Please, go forth to the Snowy Mountain Peaks and fight the final fight!');
INSERT INTO `quest_text` VALUES ('396','es','Cero absoluto','Mata al Ukanlos','Jefe de aldea Pokke','Esta aldea te debe ya mucho, pero te necesitamos más que nunca. Creo de veras que tienes que ser tú. Por favor, avanza hasta los picos de las Montañas Nevadas y ¡lucha en la lucha final!');
INSERT INTO `quest_text` VALUES ('397','en','Treasure in the Mountains!','2000 Pts Before Time Over or 2000 Pts Plus Ltd Paw Pass','Treshi','Gather the treasure that lies sleeping in the field to earn points. I will calculate your total and reward you based on how much you can collect. Leave no treasure undiscovered!');
INSERT INTO `quest_text` VALUES ('397','es','¡Tesoro en las montañas!','2000pts. antes de fin tiempo o 2000pts. + Pase zarpa lim.','Treshi','Encuentra el tesoro escondido en el campo para conseguir puntos. Yo calcularé el total y te recompensaré en función de la cantidad que recojas. ¡No me falles!');
INSERT INTO `quest_text` VALUES ('398','en','Treasure in the Jungle!','2000 Pts Before Time Over or 2000 Pts Plus Ltd Paw Pass','Treshi','Gather the treasure that lies sleeping in the field to earn points. I will calculate your total and reward you based on how much you can collect. Leave no treasure undiscovered!');
INSERT INTO `quest_text` VALUES ('398','es','¡Tesoro en la jungla!','2000pts. antes de fin tiempo o 2000pts. + Pase zarpa lim.','Treshi','Encuentra el tesoro escondido en el campo para conseguir puntos. Yo calcularé el total y te recompensaré en función de la cantidad que recojas. ¡No me falles!');
INSERT INTO `quest_text` VALUES ('399','en','Treasure in the Desert!','2000 Pts Before Time Over or 2000 Pts Plus Ltd Paw Pass','Treshi','Gather the treasure that lies sleeping in the field to earn points. I will calculate your total and reward you based on how much you can collect. Leave no treasure undiscovered!');
INSERT INTO `quest_text` VALUES ('399','es','¡Tesoro en el desierto!','2000pts. antes de fin tiempo o 2000pts. + Pase zarpa lim.','Treshi','Encuentra el tesoro escondido en el campo para conseguir puntos. Yo calcularé el total y te recompensaré en función de la cantidad que recojas. ¡No me falles!');
INSERT INTO `quest_text` VALUES ('400','en','Treasure in the Swamp!','2000 Pts Before Time Over or 2000 Pts Plus Ltd Paw Pass','Treshi','Gather the treasure that lies sleeping in the field to earn points. I will calculate your total and reward you based on how much you can collect. Leave no treasure undiscovered!');
INSERT INTO `quest_text` VALUES ('400','es','¡Tesoro en el pantano!','2000pts. antes de fin tiempo o 2000pts. + Pase zarpa lim.','Treshi','Encuentra el tesoro escondido en el campo para conseguir puntos. Yo calcularé el total y te recompensaré en función de la cantidad que recojas. ¡No me falles!');
INSERT INTO `quest_text` VALUES ('401','en','Treasure in the Hills!','2000 Pts Before Time Over or 2000 Pts Plus Ltd Paw Pass','Treshi','Gather the treasure that lies sleeping in the field to earn points. I will calculate your total and reward you based on how much you can collect. Leave no treasure undiscovered!');
INSERT INTO `quest_text` VALUES ('401','es','¡Tesoro en las colinas!','2000pts. antes de fin tiempo o 2000pts. + Pase zarpa lim.','Treshi','Encuentra el tesoro escondido en el campo para conseguir puntos. Yo calcularé el total y te recompensaré en función de la cantidad que recojas. ¡No me falles!');
INSERT INTO `quest_text` VALUES ('402','en','Treasure in the Lava!','2000 Pts Before Time Over or 2000 Pts Plus Ltd Paw Pass','Treshi','Gather the treasure that lies sleeping in the field to earn points. I will calculate your total and reward you based on how much you can collect. Leave no treasure undiscovered!');
INSERT INTO `quest_text` VALUES ('402','es','¡Tesoro en la lava!','2000pts. antes de fin tiempo o 2000pts. + Pase zarpa lim.','Treshi','Encuentra el tesoro escondido en el campo para conseguir puntos. Yo calcularé el total y te recompensaré en función de la cantidad que recojas. ¡No me falles!');
INSERT INTO `quest_text` VALUES ('403','en','Treasure in the Grt Forest!','2000 Pts Before Time Over or 2000 Pts Plus Ltd Paw Pass','Treshi','Gather the treasure that lies sleeping in the field to earn points. I will calculate your total and reward you based on how much you can collect. Leave no treasure undiscovered!');
INSERT INTO `quest_text` VALUES ('403','es','¡Tesoro en el Gran bosque!','2000pts. antes de fin tiempo o 2000pts. + Pase zarpa lim.','Treshi','Encuentra el tesoro escondido en el campo para conseguir puntos. Yo calcularé el total y te recompensaré en función de la cantidad que recojas. ¡No me falles!');
INSERT INTO `quest_text` VALUES ('404','en','Its name is "Mega Kut-Ku"!?','Hunt 2 Yian Kut-Ku (?)','Food Connoisseur','I came here in search of a meal yet to be tasted by mortal buds. I hear there is a legendary creature that lives on that hill nearby. Help me fulfill my life-long ambition! Hurry to the hunt!');
INSERT INTO `quest_text` VALUES ('404','es','¿¡Se llama "Mega Kut-Ku"!?','Caza 2 Yian Kut-Ku (?)','Experto en comida','Llegué aquí buscando una comida nunca probada por los mortales. He oído que en la montaña cercana vive una criatura legendaria. ¡Ayúdame a satisfacer mi ambición! ¡A cazar!');
INSERT INTO `quest_text` VALUES ('405','en','Triumvirate of the Sands','Hunt all of the Large Monsters','Northern Meds Seller','What''s up with this desert!? That''s the 3rd time today!! I had to leave all my goods behind. All those large Potions... I wonder if they''re sitting in some monster''s stomach out there?');
INSERT INTO `quest_text` VALUES ('405','es','Triunvirato de las arenas','Caza todos los monstruos grandes','Farmacéutico norte','¿Qué pasa con este desierto? ¡Ya es la tercera vez hoy! Tuve que dejar atrás todas mis cosas. Esas grandes pociones... Me pregunto si están por ahí en el estómago de algún monstruo.');
INSERT INTO `quest_text` VALUES ('406','en','Laurel, Please.','Hunt all of the Large Monsters','Young Arena Manager','Wanna show off? Then the arena is perfect for you! Today on the menu, we''ve got a Congalala, a Rathian, a Shogun Ceanataur, and a whole lot more! Use those few Potions you find well!');
INSERT INTO `quest_text` VALUES ('406','es','Laurel, por favor.','Caza todos los monstruos grandes','Jefe arena joven','¿Quieres destacar? ¡Pues la arena es perfecta para ti! Hoy tenemos en el menú un Congalala, un Rathian, un Shogun Ceanataur y muchas otras cosas. ¡Usa bien las pociones que encontraste!');
INSERT INTO `quest_text` VALUES ('407','en','2 Colors of Meow - Sm. Arena','Defeat 20 Felynes','Ying-Yang Creatures','To the one million Felyne fans out there: At long last we bring you our special challenge! Skillfully clear this and your reward will be a very special ticket!');
INSERT INTO `quest_text` VALUES ('407','es','2 colores Meow – Arena','Vence a 20 Felyne','Criaturas Ying-Yang','Al millón de admiradores de los Felyne: ¡por fin llega nuestro desafío especial! ¡Supéralo y tu recompensa será un ticket muy especial!');
INSERT INTO `quest_text` VALUES ('408','en','Baby Boom! Flocking to Sleep','Survive until Time Over or Deliver the Paw Pass Ticket','Determined Creature','I thought I was moving into a peaceful neighborhood when I bought the place, but there are Hypnocatrices all over, meow! Please help me protect my house by hunting down at least two of them!');
INSERT INTO `quest_text` VALUES ('408','es','¡Baby boom! Todos a dormir','Sobrevive hasta fin del tiempo o usa el Ticket zarpa','Criatura resuelta','¡Creía mudarme a un lugar tranquilo cuando compré la casa, pero hay Hypnocatrice por todas partes, miau! ¡Ayúdame a proteger mi casa cazando al menos dos de ellos!');
INSERT INTO `quest_text` VALUES ('409','en','Jungle Hunt!','Hunt all of the Large Monsters','Overbearing Noble','For our commoners'' sake, we took it upon ourselves to be brave and investigate the forest. But even Mother Dear did not warn us that such a dangerous place existed! I demand you keep us safe!');
INSERT INTO `quest_text` VALUES ('409','es','¡Cacería en la jungla!','Caza todos los monstruos grandes','Noble autoritario','Por el bien del pueblo llano nos propusimos ser valientes y explorar el bosque, pero nadie nos avisó de que existiera un lugar tan peligroso. ¡Te pido que nos mantengas a salvo!');
INSERT INTO `quest_text` VALUES ('410','en','Aquatic Festival','Hunt all of the Large Monsters','Suave Show Producer','I want this to be one fun festival, and you know what I think would make it fun? Letting the people see some top-notch hunters in action! I''ve got 4 monsters ready, so let''s give them a show!');
INSERT INTO `quest_text` VALUES ('410','es','Festival acuático','Caza todos los monstruos grandes','Showman','Quiero que éste sea un festival divertido y, ¿sabes cómo creo que lo sería? ¡Mostrando a la gente a buenos cazadores en acción! Tengo 4 monstruos listos, ¡vamos a dar espectáculo!');
INSERT INTO `quest_text` VALUES ('411','en','JUMP: Flame Emperor''s Return!','Slay the Teostra','One-Eyed, Bearded Man','The city is about to be overrun by Teostra. So... why don''t you show me that you can save the city. Of course, you can expect a reward.');
INSERT INTO `quest_text` VALUES ('411','es','JUMP: Flame Emperor''s Return!','Slay the Teostra','One-Eyed, Bearded Man','The city is about to be overrun by Teostra. So... why don''t you show me that you can save the city. Of course, you can expect a reward.');
INSERT INTO `quest_text` VALUES ('412','en','The Big Daddy','Slay the Fatalis','Pure White Felyne','Master! Do you plan to check out the old Tower? You can''t afford to miss it, meow... And if you do go, you''ll see something pretty incredible... Though I have a bad feeling about going...');
INSERT INTO `quest_text` VALUES ('412','es','El pez gordo','Mata al Fatalis','Felyne blanco puro','¡Maestro! ¿Vas a explorar la vieja Torre? No te la puedes perder, miau... Si vas, verás algo increíble... Aunque tengo un mal presentimiento...');
INSERT INTO `quest_text` VALUES ('413','en','Two Walls? Dark Winds','Hunt 2 Terra S.Ceanataurs','Suspicious Manager','Come one, come all, to the ultimate arena! I''ve got 2 of the hardest, strongest, and most terrifying monsters around! Step on up! Prove you''ve got the right stuff!');
INSERT INTO `quest_text` VALUES ('413','es','¿Dos muros? Vientos oscuros','Caza 2 Shogun Ceanataur tierra','Jefe sospechoso','¡Todos están invitados a la pelea definitiva! ¡Tengo 2 monstruos de los más duros, fuertes y terroríficos! ¡Atrévete! ¡Prueba que tienes lo que hay que tener!');
INSERT INTO `quest_text` VALUES ('414','en','Beasts of the Dunes','Hunt 2 Copper Blangongas','Wounded Creatures','We made a promise to our master, meow! We''ve just got to get this letter to its destination! We were so close, but there were these monsters hanging about... Please... Help us... Meow...');
INSERT INTO `quest_text` VALUES ('414','es','Bestias de las dunas','Caza 2 Blangonga cobre','Criaturas heridas','Hicimos una promesa a nuestro maestro, ¡miau! Tenemos que llevar esta carta a su destino. Estábamos muy cerca, pero hay monstruos por ahí... Por favor, ayúdanos... Miau');
INSERT INTO `quest_text` VALUES ('415','en','Expunge the Funk!','Hunt the Emerald Congalala and the Congalala','Lakeside Housewife','Please, hear me out! Lately, my village''s water has started smelling like sewage! Surely there must be something wrong at the source... Please find the problem and exterminate it!');
INSERT INTO `quest_text` VALUES ('415','es','¡Sacúdete el miedo!','Caza el Congalala esmeralda y el Congalala','Ama de casa del lago','¡Escúchame! Últimamente, el agua de mi pueblo huele a alcantarilla. Seguro que pasa algo malo en la fuente. ¡Por favor, encuentra el problema y acaba con él!');
INSERT INTO `quest_text` VALUES ('416','en','Dual Twin Horns - Arena','Hunt the Black Diablos and the Diablos','Mid-Age Arena Manag','I had sworn off this business a long time ago, but I couldn''t leave it behind, so here I am, back in the thick of it! Your opponent this time is a pair of Diablos! Good luck!');
INSERT INTO `quest_text` VALUES ('416','es','Doble cornamenta – Arena','Caza el Diablos negro y el Diablos','Jefe arena 1/2 edad','Renuncié a este negocio hace mucho tiempo, pero no podría abandonarlo, así que aquí estoy, ¡otra vez liado! ¡Tus oponentes esta vez son un par de Diablos! ¡Buena suerte!');
INSERT INTO `quest_text` VALUES ('417','en','Two Cliffs! Dark Hot Winds','Hunt 2 Black Gravios','Arena Manager','Come one, come all, to the ultimate arena! I''ve got 2, yes, count ''em, 2 fearsome Black Gravios right here in this very arena! Think you''ve got what it takes to beat these wild beasts?');
INSERT INTO `quest_text` VALUES ('417','es','¡Dos abismos! Viento cálido','Caza 2 Gravios negros','Jefe arena','¡Todos están invitados a la pelea definitiva! ¡Tengo 2, cuéntenlos, 2 horribles Gravios negros aquí, en esta arena! ¿Crees que tienes lo que hay que tener para vencer a estas bestias?');
INSERT INTO `quest_text` VALUES ('418','en','Demon''s Teardrop Mountain','Hunt 2 Rajang','Young Nobleman','Two Rajang stole my lovely, unwilling bride and escaped into the mountains. I don''t care that she doesn''t want me, but I can''t live without her! Please, lend me your strength!');
INSERT INTO `quest_text` VALUES ('418','es','La lágrima del demonio','Caza 2 Rajang','Joven noble','Dos Rajang raptaron a mi adorable novia y escaparon a las montañas. No me importa que no me quiera, pero no puedo vivir sin ella. ¡Por favor, préstame tu fuerza!');
INSERT INTO `quest_text` VALUES ('419','en','Porky Panic Party!','Slay 30 Bullfangos','Showy Suspect Dame','I require some entertainment at my party, for which I am recruiting hunters. Hee hee hee... It''s a veritable buffet of free-roaming porkers, if you will. Can you outrun them, I wonder...');
INSERT INTO `quest_text` VALUES ('419','es','¡Fiesta del pánico porcino!','Mata 30 Bullfango','Dama exuberante','Estoy contratando cazadores para divertir a los míos, ji, ji ji... Hay toda una colección de cerditos sueltos. Me pregunto si serás capaz de atraparlos...');
INSERT INTO `quest_text` VALUES ('420','en','Super Hypnocatrice Brawl','Hunt 2 Hypnocatrices','Arena Manager','Come one, come all, to the ultimate arena! I''ve got 2, yes, count ''em, 2 Hypnocatrices waiting just inside, ready to lull you off to Lala-land! Can you fight off 2 droopy eyelids?');
INSERT INTO `quest_text` VALUES ('420','es','Superpelea Hypnocatrice','Caza 2 Hypnocatrice','Jefe arena','¡Todos están invitados a la pelea definitiva! ¡Tengo 2, cuéntalos, 2 Hypnocatrice esperando, listos para ponerte a soñar. ¿Eres capaz de vencer 2 párpados somnolientos?');
INSERT INTO `quest_text` VALUES ('421','en','Surrounded in a Sea of Magma','Hunt the Lavasioth','Ashen Miner','We were just about to pack up for the day when we spied a huge, dark shadow lurking under the surface of the lava at the back of the cave like some sort of Lava Ness Monster! Check it out!');
INSERT INTO `quest_text` VALUES ('421','es','Rodeado en un mar de magma','Caza el Lavasioth','Minero pálido','Íbamos a dar por acabada la jornada cuando vimos una sombra enorme y oscura acechando bajo el magma al fondo de la cueva, como un Nessie de la Lava. ¡Ten cuidado!');
INSERT INTO `quest_text` VALUES ('422','en','Tiger of the Desert','Hunt the Tigrex','Very Curious Maiden','Wow! Sounds like there''s a striped monster somewhere on the other side! Let''s hurry and try to catch a glimpse! If it''s a violent beast, you will be there for me, right?');
INSERT INTO `quest_text` VALUES ('422','es','Tigre del desierto','Caza el Tigrex','Doncella muy curiosa','¡Guau! ¡Parece que hay un monstruo a rayas al otro lado! ¡Corre, vamos a ver si vemos algo! Si es una bestia violenta estarás ahí para protegerme, ¿verdad?');
INSERT INTO `quest_text` VALUES ('423','en','Twin Terrors','Hunt 2 Rajang','DeathlyPaleMercenary','I can''t believe what I saw! It was terrible! There they were, 2 Rajang just sitting there in the arena... Listen, if you value your life at all, absolutely do not go near there! Got it!?');
INSERT INTO `quest_text` VALUES ('423','es','Terror doble','Caza 2 Rajang','Mercenario pálido','¡No puedo creer lo que vi! Fue horrible. Allí estaban, 2 Rajang esperando en la arena... Escucha, si das algún valor a tu vida, ¡no te acerques allí! ¿De acuerdo?');
INSERT INTO `quest_text` VALUES ('424','en','Amezari Carnival!','Hunt the Plum D.Hermitaur and the Terra S.Ceanataur','America Zarigani','America Zarigani''s challenge! The stage is a water arena with no escape, can you win against two huge Carapaceons!? If you can clear it, you may get amazing armor!?');
INSERT INTO `quest_text` VALUES ('424','es','Amezari Carnival!','Hunt the Plum D.Hermitaur and the Terra S.Ceanataur','America Zarigani','America Zarigani''s challenge! The stage is a water arena with no escape, can you win against two huge Carapaceons!? If you can clear it, you may get amazing armor!?');
INSERT INTO `quest_text` VALUES ('425','en','Demon King Returns!','Hunt the Diablos','Ex-Hunter''s Old Man','Do you know of the One Horned Demon King? Its body is huge and different from similar species. It seems to be very strong... I heard it was defeated, but lately there are rumors. Can you check it out?');
INSERT INTO `quest_text` VALUES ('425','es','Demon King Returns!','Hunt the Diablos','Ex-Hunter''s Old Man','Do you know of the One Horned Demon King? Its body is huge and different from similar species. It seems to be very strong... I heard it was defeated, but lately there are rumors. Can you check it out?');
INSERT INTO `quest_text` VALUES ('426','en','Magazine: Tyranny of Tigrex','Hunt the Tigrex','Man in Rathalos Armor','Lately, hunters are being recognized as first-class on words alone. I don''t like it. So here''s the story... It seems that a Tigrex has settled in a remote Arena. If you can beat it I''ll recognize you as first-class.');
INSERT INTO `quest_text` VALUES ('426','es','Magazine: Tyranny of Tigrex','Hunt the Tigrex','Man in Rathalos Armor','Lately, hunters are being recognized as first-class on words alone. I don''t like it. So here''s the story... It seems that a Tigrex has settled in a remote Arena. If you can beat it I''ll recognize you as first-class.');
INSERT INTO `quest_text` VALUES ('427','en','Arena of Blood and Tears','Hunt all of the Large Monsters','Serious Lady Knight','It is not my usual practice, however, there is someone who wishes to test your strength. Therefore, can you show me your true power? You may expect to be compensated for your trouble.');
INSERT INTO `quest_text` VALUES ('427','es','Arena de sangre y lágrimas','Caza todos los monstruos grandes','Caballero serio','No suelo hacerlo así pero hay alguien que quiere probar tu fuerza. ¿Puedes mostrarme tu auténtico poder? Espera una recompensa por tus esfuerzos.');
INSERT INTO `quest_text` VALUES ('428','en','Four Kings of Fire','Hunt all of the Large Monsters','White-Clad Scientist','We''ve confirmed that the Volcano zone is ripe feeding grounds for a large variety of monsters. If you please, go to that area and hunt down 4 species for us to use in our research, would you?');
INSERT INTO `quest_text` VALUES ('428','es','Cuatro reyes de fuego','Caza todos los monstruos grandes','Científico de blanco','Hemos confirmado que la zona volcánica es adecuada para la alimentación de una gran variedad de monstruos. ¿Tendrías la bondad de ir allí y cazar 4 especies para nuestra investigación?');
INSERT INTO `quest_text` VALUES ('429','en','Hunter''s Fiesta!','Hunt all of the Large Monsters','Short-Haired Girl','I... I''m the one in charge of the festival this time, and, um... *ahem* The reward for skillfully winning this challenge is a very special ticket! So, um, I hope you will all give it a try!');
INSERT INTO `quest_text` VALUES ('429','es','¡Fiesta del cazador!','Caza todos los monstruos grandes','Chica de pelo corto','M-me toca encargarme del festival y, em... *ejem* ¡La recompensa por superar hábilmente este desafío es un ticket muy especial! Así que, em, ¡espero que todos lo intentemos!');
INSERT INTO `quest_text` VALUES ('430','en','Magazine: Giant Bird Formation','Hunt all of the Large Monsters','Keen Eastern Warior','I came far from the east to see the power of the Hunter. I will prepare the stage here. If you are confident in your strength, please come to the Arena.');
INSERT INTO `quest_text` VALUES ('430','es','Magazine: Giant Bird Formation','Hunt all of the Large Monsters','Keen Eastern Warior','I came far from the east to see the power of the Hunter. I will prepare the stage here. If you are confident in your strength, please come to the Arena.');
INSERT INTO `quest_text` VALUES ('431','en','JUMP: Red Rumble Roundup','Hunt all of the Large Monsters','Pirate First Mate','''Tis the cap''n''s birthday and we be holdin'' a brawl to celebrate. Need some right tough tusslers in the ring, the strongest ye got!');
INSERT INTO `quest_text` VALUES ('431','es','JUMP: Red Rumble Roundup','Hunt all of the Large Monsters','Pirate First Mate','''Tis the cap''n''s birthday and we be holdin'' a brawl to celebrate. Need some right tough tusslers in the ring, the strongest ye got!');
INSERT INTO `quest_text` VALUES ('432','en','Famitsu: Cherry Blossom Season','Hunt all of the Large Monsters','Famitsu MHP Planners','A challenge from Famitsu! There''s a flurry of pink in the Jungle! Can you hunt them all and secure a victory? There''s a special ticket if you can clear it!');
INSERT INTO `quest_text` VALUES ('432','es','Famitsu: Cherry Blossom Season','Hunt all of the Large Monsters','Famitsu MHP Planners','A challenge from Famitsu! There''s a flurry of pink in the Jungle! Can you hunt them all and secure a victory? There''s a special ticket if you can clear it!');
INSERT INTO `quest_text` VALUES ('433','en','Dengeki G: Ikaduchi Mountain','Hunt all of the Large Monsters','Dengeki PS Polytan','Great Challenge from Polytan! Can you defeat the Snowy Mountain''s shocking monster!? If you can do it you''ll get a luxury ticket! But is there only one?');
INSERT INTO `quest_text` VALUES ('433','es','Dengeki G: Ikaduchi Mountain','Hunt all of the Large Monsters','Dengeki PS Polytan','Great Challenge from Polytan! Can you defeat the Snowy Mountain''s shocking monster!? If you can do it you''ll get a luxury ticket! But is there only one?');
INSERT INTO `quest_text` VALUES ('434','en','Mountain in the Sky','Slay the Yama Tsukami','Long-Haired Old Lady','One time, when I was a little girl, I saw a giant shadow in the sky. It was bigger than any wyvern I''d ever seen... Was it all just a dream? Would you look into this for me, please, deary?');
INSERT INTO `quest_text` VALUES ('434','es','Montaña en el cielo','Mata al Yama Tsukami','Anciana pelo largo','Una vez, siendo una niña, vi una sombra gigante en el cielo. Era lo más grande que había visto. ¿Fue un sueño? ¿Serías tan amable de comprobarlo por mí, majete?');
INSERT INTO `quest_text` VALUES ('435','en','High Altitude King','Slay the Akantor','Benevolent Monarch','The profoundly powerful Akantor... We chased it this far, however, we''ve sustained heavy damage. Hunters of this land! I ask for your immediate help!');
INSERT INTO `quest_text` VALUES ('435','es','Rey de altura','Mata al Akantor','Monarca benevolente','El profundamente poderoso Akantor... Lo hemos perseguido, pero sufriendo muchos daños. ¡Cazadores de esta tierra! ¡Os pido vuestra ayuda inmediata!');
INSERT INTO `quest_text` VALUES ('436','en','Famitsu: Snowstorm Raider','Slay the Kushala Daora','Gunlance Messenger','I''ve been chasing that old dragon in the Snowy Mountain for many years. If I can just beat it I can complete this gunlance, but... it''s terribly strong! There''ll be a great reward! Please help me!');
INSERT INTO `quest_text` VALUES ('436','es','Famitsu: Snowstorm Raider','Slay the Kushala Daora','Gunlance Messenger','I''ve been chasing that old dragon in the Snowy Mountain for many years. If I can just beat it I can complete this gunlance, but... it''s terribly strong! There''ll be a great reward! Please help me!');
INSERT INTO `quest_text` VALUES ('437','en','JUMP: Emperor of Explosions','Slay the Teostra','One-Eyed, Bearded Man','Teostra sits in his mountain, challenging the strongest of hunters. Now your time has come. A reward... yes... I''ll give you a true treasure.');
INSERT INTO `quest_text` VALUES ('437','es','JUMP: Emperor of Explosions','Slay the Teostra','One-Eyed, Bearded Man','Teostra sits in his mountain, challenging the strongest of hunters. Now your time has come. A reward... yes... I''ll give you a true treasure.');
INSERT INTO `quest_text` VALUES ('438','en','Black Wings of Fate','Slay the Fatalis','Sly Guild Master','We received word that a black-winged dragon was spotted at the ruins of an old castle. Our expedition team has disappeared, and I fear the worst. Is there no one who will go take a look?');
INSERT INTO `quest_text` VALUES ('438','es','Las negras alas del destino','Mata al Fatalis','Maest. astuto Gremio','Nos han informado de que se ha visto un dragón de alas negras en las ruinas de la Torre. Nuestra expedición ha desaparecido y me temo lo peor. ¿No irá nadie a echar un vistazo?');
INSERT INTO `quest_text` VALUES ('439','en','Scarlet Skies','Slay the Fatalis','Guild Heavyweight','Look at that fiery scarlet sky! The legends are true! The wrath of a Fatalis turns even the sky blood red. Please, someone, anyone! Quell the rage and return the sky to its normal color!');
INSERT INTO `quest_text` VALUES ('439','es','Cielos escarlatas','Mata al Fatalis','Pez gordo Gremio','¡Mira ese cielo escarlata! ¡Las leyendas son ciertas! La ira de un Fatalis tiñe de rojo sangre hasta el cielo. ¡Por favor, que alguien calme esa rabia y devuelva el color al cielo!');
INSERT INTO `quest_text` VALUES ('440','en','A White Beam of Light','Slay the Fatalis','White-Dressed Girl','You''re a hunter, right? Tee hee. I want you to come with me... to a wonderful place; a place where white light dances about, twinkling like the stars in the sky... I swear you won''t be bored...');
INSERT INTO `quest_text` VALUES ('440','es','Un rayo de luz blanca','Mata al Fatalis','Chica de blanco','Eres cazador, ¿no? Quiero que vengas conmigo... a un lugar maravilloso, donde la luz baila como estrellas en el cielo... Te juro que no te aburrirás...');
INSERT INTO `quest_text` VALUES ('441','en','Hunting God''s Free-For-All','Hunt all of the Large Monsters','Red-Clad Knight','O ye who would take up this test! Believe in thine own strength, and the strength of thy companions, for it is in the thick of danger that fortitude is tested. Keep hope and fight to the end!');
INSERT INTO `quest_text` VALUES ('441','es','Cacería divina para todos','Caza todos los monstruos grandes','Caballero de rojo','¡Oh tú que vas a someterte a esta prueba! Cree en tu fuerza y en la de los tuyos porque es en el peligro donde se prueba la fortaleza. ¡Lucha hasta el fin sin perder la esperanza!');
INSERT INTO `quest_text` VALUES ('442','en','Basic Training - Basics','Deliver 2 pcs Raw Meat','Instructor','I am your esteemed instructor. First, I shall have you deliver some Raw Meat. Slay a Popo in the wild, and deliver the meat to the Delivery Box in camp. Good luck.');
INSERT INTO `quest_text` VALUES ('442','es','Entren. básico - Fundamentos','Entrega 2 trozos de Carne cruda','Instructor','Soy tu querido instructor. Primero, quiero que traigas un poco de Carne cruda. Mata un Popo en el campo y lleva la carne a la Caja de entregas del campamento. Buena suerte.');
INSERT INTO `quest_text` VALUES ('443','en','Basic Training - BBQ','Deliver 1 Well-Done Steak','Instructor','Your esteemed instructor once again. Now we will cover BBQ training. Carve Raw Meat from a Popo and then use the BBQ Spit to cook a tasty steak. It''s my dinner, so don''t burn it!');
INSERT INTO `quest_text` VALUES ('443','es','Entren. básico – Barbacoa','Entrega 1 Filete al punto','Instructor','Soy tu querido instructor otra vez. Ahora te enseñaré a usar la barbacoa. Corta Carne cruda de un Popo y usa el Asador de barbacoa para freír un filete. ¡Es mi cena, así que no lo quemes!');
INSERT INTO `quest_text` VALUES ('444','en','Basic Training - Gathering','Deliver 2 Honeys','Instructor','Another lesson from your esteemed instructor. Today you will train in gathering Honey. Snowy mountain Honey is less sweet but more fragrant than regular honey. A real treat with manly men!');
INSERT INTO `quest_text` VALUES ('444','es','Entren. básico - Recogida','Entrega 2 botes de Miel','Instructor','Otra lección de tu querido instructor. Hoy vas a aprender a recoger Miel. La Miel de las montañas nevadas es menos dulce, pero más aromática que la normal. ¡Un placer para el paladar!');
INSERT INTO `quest_text` VALUES ('445','en','Basic Training - Combining','Deliver 1 Potion','Instructor','Take some advice from your esteemed instructor, if there is one thing a hunter cannot go without, it is a Potion. Drink it when injured and all will be well. Never forget this!');
INSERT INTO `quest_text` VALUES ('445','es','Entren. básico - Combinación','Entrega 1 Poción','Instructor','Acepta un consejo de tu querido instructor. Si hay algo que no le puede faltar a un cazador, es una Poción. Bébetela cuando estés herido y todo irá bien. ¡No lo olvides!');
INSERT INTO `quest_text` VALUES ('446','en','Basic Training - Fishing','Deliver 1 Sushifish','Instructor','Once again you come before your esteemed instructor. Your next quest is to deliver a Sushifish. Use bait near the waterside and catch a big one. Just deliver it before dinner!');
INSERT INTO `quest_text` VALUES ('446','es','Entren. básico – Pesca','Entrega 1 Pez sushi','Instructor','Una vez más, estás ante tu querido instructor. En tu siguiente misión, tienes que traer un Pez sushi. Usa cebo a orillas del agua y pesca uno grande. ¡Pero tráelo antes de cenar!');
INSERT INTO `quest_text` VALUES ('447','en','Basic Training - Transport','Deliver 1 Carnivore Egg','Instructor','I am truly esteemed, especially as an instructor. Today''s quest is to snatch a Carnivore Egg and return it to camp. This may be training, but it is no opportunity to slack!');
INSERT INTO `quest_text` VALUES ('447','es','Entren. básico – Transporte','Entrega 1 Huevo de carnívoro','Instructor','Todos me quieren, sobre todo como instructor. La misión de hoy consiste en coger un Huevo de carnívoro y llevarlo al campamento. Es sólo un ejercicio, pero no hagas el vago.');
INSERT INTO `quest_text` VALUES ('448','en','Basic Training - Hunting','Hunt the Giadrome','Instructor','You will hold me in great esteem as I say this is the last basic training quest. You must hunt down the fierce Giadrome. Stare death in the face and show your true hunting spirit.');
INSERT INTO `quest_text` VALUES ('448','es','Entren. básico - Caza','Caza al Giadrome','Instructor','La estima que me tienes va a aumentar cuando te diga que ésta es la última misión de entrenamiento. Debes cazar a un Giadrome. Mira a la muerte a la cara y saca tu espíritu de cazador.');
INSERT INTO `quest_text` VALUES ('449','en','Sword Mastery','Slay 5 Giaprey','Instructor','As your esteemed instructor, I must inform you that the key to Sword mastery is the jumping attack. Gauge the distance of the jump and then unleash a string of deadly attacks!');
INSERT INTO `quest_text` VALUES ('449','es','Dominio de la Espada','Mata a 5 Giaprey','Instructor','En mi calidad de querido instructor, debo informarte de que la clave para dominar la Espada es el ataque con salto. Mide la distancia del salto y lanza una cadena de ataques mortales.');
INSERT INTO `quest_text` VALUES ('450','en','Dual Blade Mastery','Slay 5 Giaprey','Instructor','As your esteemed instructor, I must inform you that the key to Dual Blade mastery is the timing of Demonization. Don''t wait for a chance to Demonize, Demonize and create your own chances.');
INSERT INTO `quest_text` VALUES ('450','es','Dominio de la Espada Doble','Mata a 5 Giaprey','Instructor','En mi calidad de querido instructor, debo decirte que la clave para dominar la Espada Doble es el momento de la Endemonización. No esperes. Endemonízate para tener oportunidades.');
INSERT INTO `quest_text` VALUES ('451','en','Great Sword Mastery','Slay 5 Giaprey','Instructor','As your esteemed instructor, I must inform you that the key to Great Sword mastery is using ready attacks and charge slices. View your enemy and decide if a quick cut or strong slice is best.');
INSERT INTO `quest_text` VALUES ('451','es','Dominio de la Gran Espada','Mata a 5 Giaprey','Instructor','En mi calidad de querido instructor, debo decirte que la clave para dominar la Gran Espada es usar ataques rápidos y cortes con cargas. Observa al enemigo y decide cuál es el mejor.');
INSERT INTO `quest_text` VALUES ('452','en','Long Sword Mastery','Slay 5 Giaprey','Instructor','As your esteemed instructor, I must inform you that the key to Long Sword mastery lies in the Spirit gauge. If you can fill the gauge, your attack power will increase greatly! Fill it up!');
INSERT INTO `quest_text` VALUES ('452','es','Dominio de la Espada Larga','Mata a 5 Giaprey','Instructor','En mi calidad de querido instructor, debo decirte que la clave para dominar la Espada Larga es el indicador de Espíritu. Si lo llenas, la fuerza del ataque aumenta muchísimo. ¡Llénalo a tope!');
INSERT INTO `quest_text` VALUES ('453','en','Hammer Mastery','Slay 5 Giaprey','Instructor','As your esteemed instructor, I must inform you that the key to Hammer mastery is the charge attack. An attack should be charged to the right level then released. Time the hit with your soul!');
INSERT INTO `quest_text` VALUES ('453','es','Dominio del Martillo','Mata a 5 Giaprey','Instructor','En mi calidad de querido instructor, debo decirte que la clave para dominar el Martillo es el ataque cargado. Cárgalo al nivel correcto y luego lánzalo. ¡Sincronízalo con tu alma!');
INSERT INTO `quest_text` VALUES ('454','en','Hunting Horn Mastery','Slay 5 Giaprey','Instructor','I, your instructor, must inform you that the key to Horn mastery is in the Recital. String together 2 white notes to make yourself strong, then claim victory before the effect wears off.');
INSERT INTO `quest_text` VALUES ('454','es','Dominio del Cuerno de caza','Mata a 5 Giaprey','Instructor','Yo, tu instructor, te informo de que la clave para dominar el Cuerno está en el recital. Encadena 2 notas blancas para ser más fuerte y salir victorioso antes de que el efecto desaparezca.');
INSERT INTO `quest_text` VALUES ('455','en','Lance Mastery','Slay 5 Giaprey','Instructor','As your esteemed instructor, I must inform you that the key to Lance mastery is guarding. Use the Lance to block an approaching monster''s attack then counter fiercely!');
INSERT INTO `quest_text` VALUES ('455','es','Dominio de la Lanza','Mata a 5 Giaprey','Instructor','En mi calidad de querido instructor, debo decirte que la clave para dominar la Lanza es la defensa. Usa la Lanza para bloquear un ataque del monstruo y luego contraataca con fuerza.');
INSERT INTO `quest_text` VALUES ('456','en','Gunlance Mastery','Slay 5 Giaprey','Instructor','As your esteemed instructor, I must inform you that the key to Gunlance mastery is bombardment. Blast armored monsters into submission, then take that chance to unleash Wyvern''s Fire!');
INSERT INTO `quest_text` VALUES ('456','es','Dominio de la Lanza Pistola','Mata a 5 Giaprey','Instructor','En mi calidad de querido instructor, debo decirte que la clave para dominar la Lanza Pistola es el bombardeo. ¡Somete a los monstruos armados y luego lánzales Fuego de Wyvern!');
INSERT INTO `quest_text` VALUES ('457','en','Light Bowgun Mastery','Slay 5 Giaprey','Instructor','Esteemed instructor here, remember the key to the Light Bowgun is ammo selection. Select your ammo depending on the monster and situation. Master the qualities of each shot!');
INSERT INTO `quest_text` VALUES ('457','es','Dominio de Ballesta Ligera','Mata a 5 Giaprey','Instructor','Soy tu querido instructor. La clave para dominar la Ballesta Ligera es la selección de munición. Selecciónala en función de cada monstruo y situación. ¡Domina cada disparo!');
INSERT INTO `quest_text` VALUES ('458','en','Heavy Bowgun Mastery','Slay 5 Giaprey','Instructor','Your esteemed instructor reminds you that the key to the Heavy Bowgun is judging the proper distance. A Bowgun''s advantages aren''t limited to long distances, so pick the right distance!');
INSERT INTO `quest_text` VALUES ('458','es','Dominio de Ballesta Pesada','Mata a 5 Giaprey','Instructor','Tu querido instructor te recuerda que la clave para dominar la Ballesta Pesada es medir bien la distancia. Sus ventajas no se limitan a las largas distancias, así que mídela bien.');
INSERT INTO `quest_text` VALUES ('459','en','Bow Mastery','Slay 5 Giaprey','Instructor','Your esteemed instructor reminds you that the key to Bow mastery is charging. Charge the power of the Bow and then release it at the perfect moment. Charged arrows are a unique beast!');
INSERT INTO `quest_text` VALUES ('459','es','Dominio del Arco','Mata a 5 Giaprey','Instructor','Tu querido instructor te recuerda que la clave para dominar el Arco es la carga. Carga la potencia del Arco y dispara en el momento justo. ¡Las flechas cargadas son mucho mejores!');
INSERT INTO `quest_text` VALUES ('460','en','Yian Kut-Ku Training','Slay the Yian Kut-Ku','Instructor','It is I, your esteemed instructor. Today you will battle a Yian Kut-Ku. Its weakness is its sensitivity to loud noises. Try a Sonic Bomb or even a Barrel-Bomb!');
INSERT INTO `quest_text` VALUES ('460','es','Entrenam. con Yian Kut-Ku','Mata al Yian Kut-Ku','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Yian Kut-Ku. Su debilidad es su sensibilidad a los ruidos fuertes. Prueba una Bomba sónica o incluso una Bomba barril.');
INSERT INTO `quest_text` VALUES ('461','en','Congalala Training','Slay the Congalala','Instructor','It is I, your esteemed instructor. Today you will battle a Congalala. If you are hit by something it has thrown, the smell will spoil your items and you won''t be able to use them!');
INSERT INTO `quest_text` VALUES ('461','es','Entrenamiento con Congalala','Mata al Congalala','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Congalala. Si te da con algo que haya lanzado, el olor estropeará tus objetos y no podrás utilizarlos.');
INSERT INTO `quest_text` VALUES ('462','en','Khezu Training','Slay the Khezu','Instructor','It is I, your esteemed instructor. Today you will battle a Khezu. You must fear not only its electric attacks but also its roar. Thus, equip a weapon guard and be ready to use it.');
INSERT INTO `quest_text` VALUES ('462','es','Entrenamiento con Khezu','Mata al Khezu','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Khezu. Debes temer sus ataques eléctricos, pero también su rugido. Por eso, equípate con una arma con protección.');
INSERT INTO `quest_text` VALUES ('463','en','Daimyo Hermitaur Training','Slay the Daimyo Hermitaur','Instructor','It is I, your esteemed instructor. Today you will battle a Daimyo Hermitaur. Supposedly you can only crack its shell with a Hammer or Hunting Horn, but a Lance works as well!');
INSERT INTO `quest_text` VALUES ('463','es','Entr. con Daimyo Hermitaur','Mata al Daimyo Hermitaur','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Daimyo Hermitaur. supuestamente, la concha sólo se rompe con un Martillo o un Cuerno de caza, pero la Lanza también funciona bien.');
INSERT INTO `quest_text` VALUES ('464','en','Blangonga Training','Slay the Blangonga','Instructor','It is I, your esteemed instructor. Today you will battle a Blangonga. You may even become a Snowman! The best escape is using a Thawing Agent... Or hitting the beast on its arms!');
INSERT INTO `quest_text` VALUES ('464','es','Entrenamiento con Blangonga','Mata al Blangonga','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Blangonga. ¡Puede que hasta te conviertas en un muñeco de nieve! Usa Descongelante o te alcanzará fácilmente con sus brazos.');
INSERT INTO `quest_text` VALUES ('465','en','Yian Garuga Training','Slay the Yian Garuga','Instructor','It is I, your esteemed instructor. Today you will battle a Yian Garuga. After threatening you, Garuga likes to let off a roar or two. When you sense a threat, prepare yourself!');
INSERT INTO `quest_text` VALUES ('465','es','Entrenam. con Yian Garuga','Mata al Yian Garuga','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Yian Garuga. Tras amenazarte, al Garuga le gusta lanzar uno o dos rugidos. ¡Cuando sientas el peligro, prepárate!');
INSERT INTO `quest_text` VALUES ('466','en','Tigrex Training','Slay the Tigrex','Instructor','It is I, your esteemed instructor. Today you will battle a Tigrex. Tigrex will come after you with all its got, so don''t just wait around. Jump into the fight!');
INSERT INTO `quest_text` VALUES ('466','es','Entrenamiento con Tigrex','Mata al Tigrex','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Tigrex. El Tigrex te atacará con todo lo que tenga, así que no esperes a que venga. ¡Ve a por él!');
INSERT INTO `quest_text` VALUES ('467','en','Diablos Training','Slay the Diablos','Instructor','It is I, your esteemed instructor. Today you will battle a Diablos. When it''s on the defensive, a Sonic Bomb is useful, but once it''s mad, that won''t do a thing, so use a Flash Bomb!');
INSERT INTO `quest_text` VALUES ('467','es','Entrenamiento con Diablos','Mata al Diablos','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Diablos. Cuando está a la defensiva, la Bomba sónica es útil, pero cuando se vuelve loco, no vale para nada. ¡Usa una Bomba de luz!');
INSERT INTO `quest_text` VALUES ('468','en','Gravios Training','Slay the Gravios','Instructor','It is I, your esteemed instructor. Today you will battle a Gravios. When fighting underneath it, beware of being crushed! When it''s airborne, choose your spots! Don''t mess up!');
INSERT INTO `quest_text` VALUES ('468','es','Entrenamiento con Gravios','Mata al Gravios','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Gravios. ¡Cuando luches bajo él, procura que no te aplaste! Cuando esté en el aire, mira sus puntos débiles. ¡No la fastidies!');
INSERT INTO `quest_text` VALUES ('469','en','Kirin Training','Slay the Kirin','Instructor','It is I, your esteemed instructor. Today you will battle a Kirin. The key to this battle is lightning. If you can detect its patterns, you can increase your chances of victory!');
INSERT INTO `quest_text` VALUES ('469','es','Entrenamiento con Kirin','Mata al Kirin','Instructor','Soy yo, tu querido instructor. Hoy vas a luchar con un Kirin. La clave de este combate son los rayos. Si memorizas sus patrones, tus posibilidades de ganar aumentarán.');
INSERT INTO `quest_text` VALUES ('470','en','Cephadrome Training','Slay the Cephadrome','Instructor','It is I, your esteemed instructor. Time to face a Cephadrome! Aim to use Small Barrel-Bombs when it is hiding. Set the bomb where it will resurface! That''s the secret!');
INSERT INTO `quest_text` VALUES ('470','es','Entrenamiento con Cephadrome','Mata al Cephadrome','Instructor','Soy yo, tu querido instructor. ¡Es hora de enfrentarse a un Cephadrome! Usa Bombas de barril pequeñas cuando se oculte. Coloca la bomba en donde vaya a salir. ¡Ése es el secreto!');
INSERT INTO `quest_text` VALUES ('471','en','Plesioth Training','Slay the Plesioth','Instructor','It is I, your esteemed instructor. Time to face a Plesioth! Chasing it when it changes areas is easy, but you''ll have to figure out a way to fish it out of the ground.');
INSERT INTO `quest_text` VALUES ('471','es','Entrenamiento con Plesioth','Mata al Plesioth','Instructor','Soy yo, tu querido instructor. ¡Es hora de enfrentarse a un Plesioth! Es fácil perseguirlo cuando cambia de zona, pero hay que descubrir el modo de sacarlo de bajo el agua.');
INSERT INTO `quest_text` VALUES ('472','en','Shogun Ceanataur Training','Slay the Shogun Ceanataur','Instructor','It is I, your esteemed instructor. Time to face a Shogun Ceanataur! If it extends its claws, that''s your cue to pay attention because its reach has doubled! Get out of the way!');
INSERT INTO `quest_text` VALUES ('472','es','Entr. con Shogun Ceanataur','Mata al Shogun Ceanataur','Instructor','Soy yo, tu querido instructor. ¡Es hora de enfrentarse a un Shogun Ceanataur! Si extiende las garras, hay que tener cuidado, porque su alcance será el doble. ¡Vete!');
INSERT INTO `quest_text` VALUES ('473','en','Rathalos Training','Slay the Rathalos','Instructor','It is I, your esteemed instructor. Time to face a Rathalos! You''ll need a Paintball to keep track of it when it takes to flight, so make sure you hit it before it gets away!');
INSERT INTO `quest_text` VALUES ('473','es','Entrenamiento con Rathalos','Mata al Rathalos','Instructor','Soy yo, tu querido instructor. ¡Es hora de enfrentarse a un Rathalos! ¡Necesitarás una Bola de pintura para seguirlo cuando vuele, así que dale antes de que se vaya!');
INSERT INTO `quest_text` VALUES ('474','en','Rajang Training','Slay the Rajang','Instructor','It is I, your esteemed instructor. So you''ve made it this far, huh!? I''m speechless! Let''s see what you''ve got! Show me your true strength on this mountain!');
INSERT INTO `quest_text` VALUES ('474','es','Entrenamiento con Rajang','Mata al Rajang','Instructor','Soy yo, tu querido instructor. ¡Has llegado muy lejos! ¡Me has dejado impresionado! ¡Veamos lo que vales! ¡Demuéstrame tu fuerza en esta montaña!');
INSERT INTO `quest_text` VALUES ('475','en','Hypnocatrice Training','Slay the Hypnocatrice','Instructor','▲▼Instructor''s Note▲▼' || CHAR(10) || 'Paintball ........... Area 6' || CHAR(10) || 'Mega Potion ......... Area 2' || CHAR(10) || 'Farcaster ........... Area 4' || CHAR(10) || 'Flash Bomb ... Egg (1 only!)');
INSERT INTO `quest_text` VALUES ('475','es','Ent. con Hypnocatrice','Mata al Hypnocatrice','Instructor','▲▼Nota del instructor▲▼' || CHAR(10) || 'Bola de pintura ..... Área 6' || CHAR(10) || 'Megapoción .......... Área 2' || CHAR(10) || 'Transportador ....... Área 4' || CHAR(10) || 'Bomba luz . Huevo (¡sólo 1!)');
INSERT INTO `quest_text` VALUES ('476','en','Emerald Congalala Training','Slay the Emerald Congalala','Instructor','▲▼Instructor''s Note▲▼' || CHAR(10) || 'Trap Tool ........... Area 3' || CHAR(10) || 'Mega Potion ..... Usual spot' || CHAR(10) || 'Deodorant ........... Area 9' || CHAR(10) || 'Max Potion ..... Furthest in');
INSERT INTO `quest_text` VALUES ('476','es','Ent. con Congalala esmeralda','Mata al Congalala esmeralda','Instructor','▲▼Nota del instructor▲▼' || CHAR(10) || 'Herram. trampa ...... Área 3' || CHAR(10) || 'Megapoción .. Punto habitual' || CHAR(10) || 'Desodorante ......... Área 9' || CHAR(10) || 'Poción máx. . Punto + lejano');
INSERT INTO `quest_text` VALUES ('477','en','Plum D.Hermitaur Training','Slay the Plum D.Hermitaur','Instructor','▲▼Instructor''s Note▲▼' || CHAR(10) || 'Book of Combos 1 .... Area 2' || CHAR(10) || 'Mega Potion ......... Area 8' || CHAR(10) || 'Iron Pickaxe ........ Area 8' || CHAR(10) || 'Trap Tool + Genprey Fang = !');
INSERT INTO `quest_text` VALUES ('477','es','Entrenam. D.Hermitaur cer.','Mata al D. Hermitaur cereza','Instructor','▲▼Nota del instructor▲▼' || CHAR(10) || 'Libro combos 1 ...... Área 2' || CHAR(10) || 'Megapoción .......... Área 8' || CHAR(10) || 'Pico de hierro ...... Área 8' || CHAR(10) || 'H. trampa + Col. Genprey = !');
INSERT INTO `quest_text` VALUES ('478','en','Nargacuga Training','Slay the Nargacuga','Instructor','▲▼Instructor''s Note▲▼' || CHAR(10) || 'Sonic Bomb .......... Area 4' || CHAR(10) || 'Mega Potion ......... Area 8' || CHAR(10) || 'Pitfall Trap ........ Area 3' || CHAR(10) || 'Max Potion .......... Bugnet');
INSERT INTO `quest_text` VALUES ('478','es','Entrenamiento con Nargacuga','Mata al Nargacuga','Instructor','▲▼Nota del instructor▲▼' || CHAR(10) || 'Bomba sónica......... Área 4' || CHAR(10) || 'Megapoción .......... Área 8' || CHAR(10) || 'Trampa escollo....... Área 3' || CHAR(10) || 'Poción máx. ..... Red bichos');
INSERT INTO `quest_text` VALUES ('479','en','Copper Blangonga Training','Slay the Copper Blangonga','Instructor','▲▼Instructor''s Note▲▼' || CHAR(10) || 'Armorskin .......... Remobra' || CHAR(10) || 'Mega Potion ......... Area 9' || CHAR(10) || 'Demondrug .... A cool desert' || CHAR(10) || 'Max Potion ..... Underground');
INSERT INTO `quest_text` VALUES ('479','es','Ent. con Blanconga cobre','Mata al Blangonga cobre','Instructor','▲▼Nota del instructor▲▼' || CHAR(10) || 'Piel armadura ...... Remobra' || CHAR(10) || 'Megapoción .......... Área 9' || CHAR(10) || 'Droga demon. Desierto frío' || CHAR(10) || 'Poción máx. .... Subterráneo');
INSERT INTO `quest_text` VALUES ('480','en','Lavasioth Training','Slay the Lavasioth','Instructor','▲▼Instructor''s Note▲▼' || CHAR(10) || 'Lg Barrel-Bomb ...... Area 2' || CHAR(10) || 'Mega Potion ......... Area 6' || CHAR(10) || 'Iron Pickaxe ........ Area 3' || CHAR(10) || 'Max Potion .... A cool place');
INSERT INTO `quest_text` VALUES ('480','es','Entrenamiento con Lavasioth','Mata al Lavasioth','Instructor','▲▼Nota del instructor▲▼' || CHAR(10) || 'Bomba barril gr. .... Área 2' || CHAR(10) || 'Megapoción .......... Área 6' || CHAR(10) || 'Pico de hierro ...... Área 3' || CHAR(10) || 'Poción máx. ..... Lugar frío');
INSERT INTO `quest_text` VALUES ('481','en','Terra S.Ceanataur Training','Slay the Terra S.Ceanataur','Instructor','▲▼Instructor''s Note▲▼' || CHAR(10) || 'Thr Knife ..... Veggie Elder' || CHAR(10) || 'Mega Potion ........ Area 10' || CHAR(10) || 'Iron Pickaxe ........ Area 5' || CHAR(10) || 'Max Potion .... Grassy field' || CHAR(10) || '         (bugnet) under tree');
INSERT INTO `quest_text` VALUES ('481','es','Ent. con S. Ceanataur tierra','Mata al S. Ceanataur tierra','Instructor','▲▼Nota del instructor▲▼' || CHAR(10) || 'Cuchillo lz. .. Anciano veg.' || CHAR(10) || 'Megapoción ......... Área 10' || CHAR(10) || 'Pico de hierro ..... Área 5' || CHAR(10) || 'Poción máx. ... Campo hierba' || CHAR(10) || '     (Red bichos) bajo árbol');
INSERT INTO `quest_text` VALUES ('482','en','Rajang Training','Slay the Rajang','Instructor','▲▼Instructor''s Note▲▼' || CHAR(10) || 'Net .... Area 4 (South East)' || CHAR(10) || 'Mega Potion .... Furthest in' || CHAR(10) || 'Demondrug ........... Area 7' || CHAR(10) || 'Max Potion .. Near base camp');
INSERT INTO `quest_text` VALUES ('482','es','Entrenamiento con Rajang','Mata al Rajang','Instructor','▲▼Nota del instructor▲▼' || CHAR(10) || 'Red ....... Área 4 (Sureste)' || CHAR(10) || 'Megapoción .. Punto + lejano' || CHAR(10) || 'Droga demonio........ Área 7' || CHAR(10) || 'Poción máx. . Cerca camp. b.');
INSERT INTO `quest_text` VALUES ('483','en','Blue Yian Kut-Ku Exercises','Slay the Blue Yian Kut-Ku','Instructor','It is I, your esteemed instructor. If you can clear this Group Training in time, your reward will explode! Faster! Smarter! Set a new record!');
INSERT INTO `quest_text` VALUES ('483','es','Ejerc. con el Kut-Ku azul','Mata al Kut-Ku azul','Instructor','Soy yo, tu querido instructor. Si superas esta misión a tiempo, ¡la recompensa será generosa! ¡Más rápido, más listo! ¡Bate récords!');
INSERT INTO `quest_text` VALUES ('484','en','Cephadrome Exercises','Slay the Cephadrome','Instructor','It is I, your esteemed instructor. An all out assault will only lower your time marginally. Victory rests on what you have and what you can combine it with in the southern desert.');
INSERT INTO `quest_text` VALUES ('484','es','Ejercicios con Cephadrome','Mata al Cephadrome','Instructor','Soy yo, tu querido instructor. Un potente ataque sólo reducirá el tiempo marginalmente. La victoria depende de lo que tienes y con que lo puedes combinar en el desierto del sur.');
INSERT INTO `quest_text` VALUES ('485','en','Rathian Exercises','Slay the Rathian','Instructor','It is I, your esteemed instructor. No time for tricks, just use your skills and finish this beast off! Use everything you''ve learned about "cooperation" and obliterate your foe!');
INSERT INTO `quest_text` VALUES ('485','es','Ejercicios con Rathian','Mata la Rathian','Instructor','Soy yo, tu querido instructor. Aquí no hay trucos, usa tus habilidades y acaba con la bestia. ¡Usa todo lo que has aprendido sobre "cooperación" y aniquila al enemigo!');
INSERT INTO `quest_text` VALUES ('486','en','Congalala Exercises','Slay the Congalala','Instructor','It is I, your esteemed instructor. I want to see your true power on this one! Give it all you''ve got, you hear!? But don''t leave your friends in the dust. Be as one! Fight as one!');
INSERT INTO `quest_text` VALUES ('486','es','Ejercicios con Congalala','Mata al Congalala','Instructor','Soy yo, tu querido instructor. ¡Esta vez quiero ver tu verdadero poder! Da todo lo que tengas, ¿vale? Pero no abandones a tus amigos. ¡Sed como uno! ¡Luchad como uno!');
INSERT INTO `quest_text` VALUES ('487','en','Shogun Ceanataur Exercises','Slay 1 Shogun Ceanataur','Instructor','It is I, your esteemed instructor. Your opponent this time is a pair of Shogun Ceanataurs. You only have to beat one to clear the quest, so remember which one you''re going after!');
INSERT INTO `quest_text` VALUES ('487','es','Ejercicios Shogun Ceanataur','Mata a 1 Shogun Ceanataur','Instructor','Soy yo, tu querido instructor. Esta vez tus oponentes son un par de Shogun Ceanataur. Sólo tienes que vencer a uno para culminar la aventura, así que ¡recuerda a cuál persigues!');
INSERT INTO `quest_text` VALUES ('488','en','Tigrex Exercises','Slay 2 Tigrex','Instructor','It is I, your esteemed instructor. You''ll be going after 2 Tigrex back to back today. Try not to attack when it''s infuriated, and use whatever you''ve got to create an opening!');
INSERT INTO `quest_text` VALUES ('488','es','Ejercicios con Tigrex','Mata a 2 Tigrex','Instructor','Soy yo, tu querido instructor. Hoy vas tras 2 Tigrex a la vez. ¡Intenta no atacar cuando estén furiosos y usa lo que tengas para abrir brecha!');
INSERT INTO `quest_text` VALUES ('489','en','Challenge Quest 1','Slay the Yian Garuga','Instructor','A Yian Garuga has been spotted in the jungle, and as your esteemed instructor, I deem this to be a great chance to do some training. I''ll lend ya some equipment, so get out there already!');
INSERT INTO `quest_text` VALUES ('489','es','Misión Desafío 1','Mata al Yian Garuga','Instructor','En la jungla han visto un Yian Garuga y, como tu querido instructor, creo que es una gran oportunidad para tu entrenamiento. Te voy a prestar equipo, así que ¡vamos para allá!');
INSERT INTO `quest_text` VALUES ('490','en','Challenge Quest 2','Slay 2 King Shakalakas','Instructor','Oho! A challenge from the Shakalaka! Now normally, I''d go myself, but I just remembered I have something very important to take care of! Go stand in for me and bring back that trophy!');
INSERT INTO `quest_text` VALUES ('490','es','Misión Desafío 2','Mata a 2 King Shakalaka','Instructor','¡Anda! ¡Un desafío de Shakalaka! Normalmente iría solo, pero acabo de recordar que tengo algo importante de lo que ocuparme. ¡Ve en mi lugar y vuelve con ese trofeo!');
INSERT INTO `quest_text` VALUES ('491','en','Challenge Quest 3','Slay the Plesioth','Instructor','The battlefield this time will be the Moat Arena. The prize money is pretty good, so no harm in trying. Huh? Where''s the fine print? Aww, you''ll do fine! You''ll win! ...Maybe. Ha ha.');
INSERT INTO `quest_text` VALUES ('491','es','Misión Desafío 3','Mata al Plesioth','Instructor','Esta vez, el campo de batalla será la Arena acuática. El premio en metálico es bueno, así que por qué no probar, ¿eh? ¿La letra pequeña? ¡Vas a ganar! Quizá... Ja ja.');
INSERT INTO `quest_text` VALUES ('492','en','Challenge Quest 4','Slay all of the Large Monsters','Instructor','Become one with the monsters by knowing how they think; that''s the best way to beat them! That''s what this training is for. Use this equipment and get inside the heads of those beasts!');
INSERT INTO `quest_text` VALUES ('492','es','Misión Desafío 4','Mata todos los monstruos grandes','Instructor','Identifícate con los monstruos sabiendo cómo piensan; ¡es la mejor manera de vencerlos! Para eso es el entrenamiento. ¡Usa este equipo para entrar en la cabeza de esas bestias!');
INSERT INTO `quest_text` VALUES ('493','en','Challenge Quest 5','Slay 2 Bulldromes','Instructor','Running on an empty tank is the worst thing a hunter can do. That is to say, to master eating is to master the hunt! I''m going to turn you into the best cook ever! Or at least the best BBQer!');
INSERT INTO `quest_text` VALUES ('493','es','Misión Desafío 5','Mata 2 Bulldrome','Instructor','Lo peor que puedes hacer es ir con el depósito vacío. ¡Saber comer es saber cazar! Te convertiré en el mejor cocinero del mundo. O al menos en experto en barbacoas...');
INSERT INTO `quest_text` VALUES ('494','en','Challenge Quest 6','Slay the Vespoid Queen','Instructor','I got a request to do something about all the huge bugs that have popped up in the Old Jungle. Just an idea, but you might want to go for the leader here. Make a beeline for the Queen!');
INSERT INTO `quest_text` VALUES ('494','es','Misión Desafío 6','Mata la Vespoid reina','Instructor','Me han pedido que haga algo con los enormes bichos que han aparecido en la Vieja Jungla. Es sólo una idea, pero quizá quieras ir a por la jefa. ¡Vete zumbando a por la reina!');
INSERT INTO `quest_text` VALUES ('495','en','Challenge Quest 7','Slay 2 Nargacugas','Instructor','Fight 2 Nargacugas back to back! Be wary of their intense speed and their super-strong tails! One swish is all it takes! Stay cool and think things out. They''ll fall soon enough.');
INSERT INTO `quest_text` VALUES ('495','es','Misión Desafío 7','Mata a 2 Nargacuga','Instructor','¡Lucha con 2 Nargacuga a la vez! ¡Cuidado con su velocidad y sus colas superfuertes! ¡Un latigazo es letal! Mantén la calma y piensa bien las cosas. No tardarán en caer.');
INSERT INTO `quest_text` VALUES ('496','en','Challenge Quest 8','Slay all of the Large Monsters','Instructor','I''m hosting an arena of my own where I''ll happily hand out prizes from my stash of treasures to anyone with outstanding times. You can even participate with your pals. Don''t keep me waiting!');
INSERT INTO `quest_text` VALUES ('496','es','Misión Desafío 8','Mata todos los monstruos grandes','Instructor','Aquí regento mi arena propia, y estaré feliz de repartir premios de mi tesoro a cualquiera que destaque por sus tiempos. Puedes venir con amigos. ¡No me hagas esperar!');
INSERT INTO `quest_text` VALUES ('497','en','Challenge Quest 9','Slay 50 Velociprey','Instructor','I''ve got a special quest for you today! Your target: the pack of Velociprey waiting for you at the Great Arena. But! Those guys are small fries compared to the other monster that awaits!');
INSERT INTO `quest_text` VALUES ('497','es','Misión Desafío 9','Mata 50 Velociprey','Instructor','Hoy tengo para ti una aventura especial: un grupo de Velociprey en la Gran arena. Pero, ¡cuidado! ¡No son nada al lado del otro monstruo que te espera!');
INSERT INTO `quest_text` VALUES ('498','en','Challenge Quest 10','Slay the Rajang','Instructor','It''s the much dreaded Golden Rajang! It''s the strongest of the strong you''ll ever face, but since it''s you, I have faith that you''ll defeat it. Hold nothing back and victory will be yours!');
INSERT INTO `quest_text` VALUES ('498','es','Misión Desafío 10','Mata al Rajang','Instructor','¡Es el temido Rajang dorado! Es el más fuerte que verás jamás pero, tratándose de ti, confío en que lo vencerás. ¡No te guardes nada y la victoria será tuya!');
INSERT INTO `quest_text` VALUES ('499','en','Monster Hunter Fiesta 1','Slay the Nargacuga','Youth Promoter','Welcome to the competition! In this challenge, we are asking participants to slay a Nargacuga of the Great Forest. Trust yourself and show us the strength that lies within!');
INSERT INTO `quest_text` VALUES ('499','es','Fiesta Monster Hunter 1','Mata al Nargacuga','Promotor joven','¡Bienvenido! En este desafío pedimos a los participantes que maten un Nargacuga del Gran bosque. ¡Confía en ti mismo y muéstranos la fuerza que llevas dentro!');
INSERT INTO `quest_text` VALUES ('500','en','Monster Hunter Fiesta 2','Slay the Tigrex','Hearty Promoter','It''s festival time! Your opponent is the mighty Tigrex! As you know, its strength is suffocating, but in order to advance, you must break on through to the other side!');
INSERT INTO `quest_text` VALUES ('500','es','Fiesta Monster Hunter 2','Mata al Tigrex','Promotor campechano','¡Hora del festival! ¡Tu oponente es el poderoso Tigrex! Como sabes, su fuerza es sofocante pero, para avanzar, debes abrirte camino hasta el otro lado.');
INSERT INTO `quest_text` VALUES ('501','en','Monster Hunter Fiesta 3','Slay all of the Large Monsters','Voluptuous Promoter','It appears that we have arrived at the best part of these competitions. I wonder who will stand tall in the end and take home the proof! I look forward to seeing your magnificent technique.');
INSERT INTO `quest_text` VALUES ('501','es','Fiesta Monster Hunter 3','Mata todos los monstruos grandes','Promotora voluptuosa','Parece que hemos llegado a lo mejor de estas competiciones. ¡Me pregunto quién quedará en pie y se llevará el premio a casa. Estoy impaciente por ver tu magnífica técnica.');
INSERT INTO `quest_text` VALUES ('502','en','Monster Hunter Fiesta 4','Slay the Rajang','Virtuous Promoter','Thanks to the participation of so many strong hunters, we''ve been able to reach this stage, the finale! We hope that all the hunters will join in one last hunt in a show of true might!');
INSERT INTO `quest_text` VALUES ('502','es','Fiesta Monster Hunter 4','Mata al Rajang','Promotor virtuoso','¡Gracias a la participación de todos hemos llegado hasta aquí! ¡Esperamos que todos los cazadores se unan en una última cacería y demuestren su fuerza!');
